"use client";

import Link from "next/link";
import { useEffect, useState, type FormEvent } from "react";
import { useParams } from "next/navigation";
import { FormalOpsShell, accountOpsNav } from "@/components/formalOps/FormalOpsShell";
import { formatDateTime, useAuthedJson } from "@/components/formalOps/useAuthedJson";
import styles from "@/components/image20/Image20Auxiliary.module.css";

export default function AccountAppealDetailPage() {
  const params = useParams<{ appealId: string }>();
  const appealId = params?.appealId || "";
  const { accessToken, authedFetch } = useAuthedJson(`/account/appeals/${appealId}`);
  const [payload, setPayload] = useState<any>(null);
  const [reply, setReply] = useState("");
  const [notice, setNotice] = useState("正在讀取申訴…");

  async function load() {
    const data = await authedFetch(`/api/appeals/${encodeURIComponent(appealId)}`);
    setPayload(data);
  }

  useEffect(() => {
    if (!accessToken || !appealId) return;
    load().then(() => setNotice("")).catch((error) => setNotice(error.message));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [accessToken, appealId]);

  async function send(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setNotice("正在送出補充…");
    try {
      await authedFetch(`/api/appeals/${appealId}/messages`, { method: "POST", body: JSON.stringify({ body: reply }) });
      setReply("");
      await load();
      setNotice("已送出補充。");
    } catch (error: any) {
      setNotice(error?.message || "送出補充失敗。");
    }
  }

  async function closeAppeal() {
    setNotice("正在關閉申訴…");
    try {
      await authedFetch(`/api/appeals/${appealId}`, { method: "PATCH", body: JSON.stringify({ action: "close" }) });
      await load();
      setNotice("申訴已關閉。");
    } catch (error: any) {
      setNotice(error?.message || "關閉申訴失敗。");
    }
  }

  const appeal = payload?.appeal || {};
  const messages = payload?.messages || [];
  const events = payload?.events || [];
  const canReply = ["open", "reviewing"].includes(appeal.status);

  return (
    <FormalOpsShell activeHref="/account/appeals" navItems={accountOpsNav} eyebrow="Appeal" title={`申訴｜${appeal.status || "讀取中"}`} description="你只能看到自己的申訴、使用者可見回覆與相關處置摘要。內部管理備註不會出現在這裡。" quoteTitle={appeal.reason_code} quoteBody={appeal.requested_outcome || "未填期望結果"} topActions={<Link href="/account/appeals">返回申訴列表</Link>} dataPage="account-appeal-detail-v129">
      {notice ? <div className={styles.accountLoading}>{notice}</div> : null}
      <section className={styles.accountContentGrid}>
        <article className={styles.accountContentCard}><div className={styles.accountContentHead}><div><span className="i20-kicker">Decision</span><h3>申訴狀態</h3></div>{["open", "reviewing"].includes(appeal.status) ? <button type="button" onClick={closeAppeal}>關閉申訴</button> : null}</div><div className={styles.accountPreferenceList}><div><b>狀態</b><span>{appeal.status || "—"}</span></div><div><b>管理端回覆</b><span>{appeal.admin_response || "尚未有正式決定。"}</span></div><div><b>審查時間</b><span>{formatDateTime(appeal.review_started_at)} → {formatDateTime(appeal.resolved_at || appeal.closed_at)}</span></div>{payload?.original_action ? <div><b>原處置</b><span>{payload.original_action.action_type}｜{payload.original_action.reason || "—"}</span></div> : null}{payload?.resolution_action ? <div><b>恢復處置</b><span>{payload.resolution_action.action_type}｜{payload.resolution_action.reason || "—"}</span></div> : null}</div></article>
        <article className={styles.accountContentCard}><div className={styles.accountContentHead}><div><span className="i20-kicker">Messages</span><h3>申訴對話</h3></div></div><div className={styles.accountPreferenceList}>{messages.map((message: any) => <div key={message.id}><b>{message.sender_role === "admin" ? "安感島治理人員" : message.sender_role === "system" ? "系統" : "你"}</b><span>{message.body}</span><span>{formatDateTime(message.created_at)}</span></div>)}</div>{canReply ? <form className={styles.formStack} onSubmit={send}><label><span className="i20-kicker">補充說明</span><textarea value={reply} onChange={(event) => setReply(event.target.value)} rows={5} required /></label><button className="i20-btn peach" type="submit" disabled={!reply.trim()}>送出補充</button></form> : null}</article>
      </section>
      <section className={styles.accountContentGrid}><article className={styles.accountContentCard}><div className={styles.accountContentHead}><div><span className="i20-kicker">Events</span><h3>處理事件</h3></div></div><div className={styles.accountPreferenceList}>{events.map((event: any) => <div key={event.id}><b>{event.event_type}</b><span>{event.from_status || "—"} → {event.to_status || "—"}｜{formatDateTime(event.created_at)}</span></div>)}</div></article></section>
    </FormalOpsShell>
  );
}

"use client";

import Link from "next/link";
import { useEffect, useMemo, useState, type FormEvent } from "react";
import { FormalOpsShell, accountOpsNav } from "@/components/formalOps/FormalOpsShell";
import { formatDateTime, useAuthedJson } from "@/components/formalOps/useAuthedJson";
import styles from "@/components/image20/Image20Auxiliary.module.css";

const reasonLabels: Record<string, string> = {
  mistaken_identity: "對象辨識有誤",
  missing_context: "缺少重要脈絡",
  incorrect_facts: "事實內容不正確",
  disproportionate_action: "處置比例不合理",
  resolved_issue: "問題已經排除",
  other: "其他",
};

export default function AccountAppealsPage() {
  const { accessToken, authedFetch } = useAuthedJson("/account/appeals");
  const [appeals, setAppeals] = useState<any[]>([]);
  const [actions, setActions] = useState<any[]>([]);
  const [cases, setCases] = useState<any[]>([]);
  const [notice, setNotice] = useState("正在讀取申訴與治理紀錄…");
  const [form, setForm] = useState({
    moderation_action_id: "",
    moderation_case_id: "",
    reason_code: "missing_context",
    message: "",
    requested_outcome: "",
  });

  async function load() {
    const [appealPayload, moderationPayload] = await Promise.all([
      authedFetch("/api/appeals?limit=100"),
      authedFetch("/api/account/moderation/actions"),
    ]);
    setAppeals(appealPayload.appeals || []);
    setActions(moderationPayload.actions || []);
    setCases(moderationPayload.cases || []);
  }

  useEffect(() => {
    if (!accessToken) return;
    load().then(() => setNotice("")).catch((error) => setNotice(error.message));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [accessToken]);

  const selectedAction = useMemo(
    () => actions.find((item) => item.id === form.moderation_action_id),
    [actions, form.moderation_action_id],
  );

  async function submit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setNotice("正在送出申訴…");
    try {
      const actionId = form.moderation_action_id || null;
      const caseId = actionId ? selectedAction?.case_id || null : form.moderation_case_id || null;
      await authedFetch("/api/appeals", {
        method: "POST",
        body: JSON.stringify({
          moderation_action_id: actionId,
          moderation_case_id: caseId,
          reason_code: form.reason_code,
          message: form.message,
          requested_outcome: form.requested_outcome || null,
          idempotency_key: `account:${actionId || caseId}:${form.reason_code}`,
        }),
      });
      setForm({ moderation_action_id: "", moderation_case_id: "", reason_code: "missing_context", message: "", requested_outcome: "" });
      await load();
      setNotice("申訴已送出。若同一處置已有進行中的申訴，系統會回傳原申訴而不重複建立。");
    } catch (error: any) {
      setNotice(error?.message || "送出申訴失敗。");
    }
  }

  return (
    <FormalOpsShell
      activeHref="/account/appeals"
      navItems={accountOpsNav}
      eyebrow="Appeals"
      title="申訴與處置回查"
      description="申訴不是寄出一封信就結束。每一次補充、審查、決定與恢復動作都應留下可回查紀錄。"
      quoteTitle="一個處置，一個進行中申訴"
      quoteBody="重複提交不會製造多張案件；接受申訴時，管理端可建立獨立 restore 處置。"
      dataPage="account-appeals-v129"
    >
      {notice ? <div className={styles.accountLoading}>{notice}</div> : null}
      <section className={styles.accountContentGrid}>
        <article className={styles.accountContentCard}>
          <div className={styles.accountContentHead}><div><span className="i20-kicker">New Appeal</span><h3>提出申訴</h3></div></div>
          <form className={styles.formStack} onSubmit={submit}>
            <label><span className="i20-kicker">關聯處置</span><select value={form.moderation_action_id} onChange={(event) => setForm({ ...form, moderation_action_id: event.target.value, moderation_case_id: "" })}><option value="">不指定處置，改選治理案件</option>{actions.map((item) => <option key={item.id} value={item.id}>{item.action_type}｜{formatDateTime(item.created_at)}</option>)}</select></label>
            {!form.moderation_action_id ? <label><span className="i20-kicker">關聯案件</span><select value={form.moderation_case_id} onChange={(event) => setForm({ ...form, moderation_case_id: event.target.value })}><option value="">請選擇治理案件</option>{cases.map((item) => <option key={item.id} value={item.id}>{item.severity}｜{item.status}｜{item.summary || item.id}</option>)}</select></label> : null}
            <label><span className="i20-kicker">原因</span><select value={form.reason_code} onChange={(event) => setForm({ ...form, reason_code: event.target.value })}>{Object.entries(reasonLabels).map(([value, label]) => <option key={value} value={value}>{label}</option>)}</select></label>
            <label><span className="i20-kicker">申訴內容</span><textarea value={form.message} onChange={(event) => setForm({ ...form, message: event.target.value })} rows={7} minLength={10} required /></label>
            <label><span className="i20-kicker">希望的處理結果</span><textarea value={form.requested_outcome} onChange={(event) => setForm({ ...form, requested_outcome: event.target.value })} rows={3} /></label>
            <button className="i20-btn peach" type="submit" disabled={!form.message.trim() || (!form.moderation_action_id && !form.moderation_case_id)}>送出申訴</button>
          </form>
        </article>
        <article className={styles.accountContentCard}>
          <div className={styles.accountContentHead}><div><span className="i20-kicker">History</span><h3>我的申訴</h3></div><button type="button" onClick={() => load().catch((error) => setNotice(error.message))}>重新整理</button></div>
          <div className={styles.accountPreferenceList}>{appeals.map((appeal) => <div key={appeal.id}><b><Link href={`/account/appeals/${appeal.id}`}>{reasonLabels[appeal.reason_code] || appeal.reason_code}｜{appeal.status}</Link></b><span>{appeal.requested_outcome || "未填期望結果"}</span><span>{formatDateTime(appeal.updated_at)}</span></div>)}{appeals.length === 0 ? <div><b>目前沒有申訴。</b><span>只有與你本人相關的治理案件或處置可以提出申訴。</span></div> : null}</div>
        </article>
      </section>
    </FormalOpsShell>
  );
}

"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import {
  buildInvoicePreferenceFromForm,
  defaultInvoiceFormState,
  describeInvoicePreference,
  InvoicePreferenceFields,
  invoicePreferenceToFormState,
  type InvoiceFormState,
} from "@/components/billing/InvoicePreferenceFields";
import type { InvoicePreference } from "@/lib/invoicePreferences";
import { FormalOpsShell, accountOpsNav } from "@/components/formalOps/FormalOpsShell";
import { formatDateTime, formatTwd, useAuthedJson } from "@/components/formalOps/useAuthedJson";
import styles from "@/components/image20/Image20Auxiliary.module.css";

function latestByOrder(rows: any[], orderId: string) {
  return rows.find((row) => row.payment_order_id === orderId) || null;
}

function invoiceLabel(order: any, invoiceEvents: any[], invoiceTasks: any[]) {
  const events = invoiceEvents.filter((row) => row.payment_order_id === order.id);
  const issued = events.find((row) => row.event_type === "issued");
  if (issued) return `已開立 ${issued.invoice_number || ""}`.trim();
  const followup = events.find((row) => row.event_type === "void_or_allowance_required");
  if (followup) return "退款後需作廢 / 折讓";
  const failed = events.find((row) => row.event_type === "failed");
  if (failed) return "開立失敗，待處理";
  const task = latestByOrder(invoiceTasks, order.id);
  if (task?.status === "manual_required") return "待人工開立";
  if (task?.status === "failed") return "發票任務失敗";
  if (task?.status === "queued" || task?.status === "processing") return "開立處理中";
  const requested = events.find((row) => row.event_type === "requested");
  if (requested) return "已請求開立";
  return "尚未產生";
}

function refundLabel(order: any, refunds: any[], refundTasks: any[]) {
  const refund = refunds.find((row) => row.payment_order_id === order.id);
  if (!refund) return "—";
  const task = refundTasks.find((row) => row.refund_request_id === refund.id);
  const taskSuffix = task ? ` / ${task.status}` : "";
  return `${refund.status}${taskSuffix}`;
}

function StatusList({ title, rows, emptyText }: { title: string; rows: any[]; emptyText: string }) {
  return (
    <article className={styles.accountContentCard}>
      <div className={styles.accountContentHead}>
        <div>
          <span className="i20-kicker">Status</span>
          <h3>{title}</h3>
        </div>
      </div>
      <div className={styles.accountPreferenceList}>
        {rows.map((row) => (
          <div key={row.id}>
            <b>{row.title}</b>
            <span>{row.body}</span>
          </div>
        ))}
        {rows.length === 0 ? (
          <div>
            <b>{emptyText}</b>
            <span>完成付款、開票或退款後會出現在這裡。</span>
          </div>
        ) : null}
      </div>
    </article>
  );
}

function InvoicePreferenceCard({
  email,
  authedFetch,
}: {
  email: string;
  authedFetch: (path: string, init?: RequestInit) => Promise<any>;
}) {
  const [form, setForm] = useState<InvoiceFormState>(defaultInvoiceFormState(email));
  const [savedPreference, setSavedPreference] = useState<InvoicePreference | null>(null);
  const [source, setSource] = useState("default_account_email");
  const [message, setMessage] = useState("正在讀取預設發票資料…");
  const [saving, setSaving] = useState(false);

  async function load() {
    const payload = await authedFetch("/api/account/invoice-preference");
    setSavedPreference(payload.preference || null);
    setSource(payload.source || "default_account_email");
    setForm(invoicePreferenceToFormState(payload.preference, email));
    setMessage("");
  }

  useEffect(() => {
    load().catch((error) => setMessage(error.message || "讀取預設發票資料失敗。"));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [email]);

  async function save() {
    setSaving(true);
    setMessage("正在驗證並儲存發票資料…");
    try {
      const invoicePreference = buildInvoicePreferenceFromForm(form, email, "account_billing_default_v120");
      const validation = await authedFetch("/api/invoices/validate-preference", {
        method: "POST",
        body: JSON.stringify({ invoicePreference }),
      });
      const normalized = validation.invoicePreference || invoicePreference;
      const saved = await authedFetch("/api/account/invoice-preference", {
        method: "PUT",
        body: JSON.stringify({ invoicePreference: normalized }),
      });
      setSavedPreference(saved.preference || normalized);
      setForm(invoicePreferenceToFormState(saved.preference || normalized, email));
      setSource("saved");
      setMessage("已儲存。之後付款會先帶入這份預設資料，付款前仍可針對單筆訂單調整。 ");
    } catch (error: any) {
      setMessage(error?.message || "儲存發票資料失敗。");
    } finally {
      setSaving(false);
    }
  }

  return (
    <article className={styles.accountContentCard}>
      <div className={styles.accountContentHead}>
        <div>
          <span className="i20-kicker">Invoice Preference</span>
          <h3>預設發票資料</h3>
        </div>
        <button type="button" onClick={() => load().catch((error) => setMessage(error.message))}>重新讀取</button>
      </div>
      <div className={styles.accountPreferenceList}>
        <div>
          <b>{source === "saved" ? "目前已儲存預設" : "目前使用帳號 Email 預設"}</b>
          <span>{describeInvoicePreference(savedPreference)}</span>
        </div>
      </div>
      <InvoicePreferenceFields state={form} onChange={setForm} compact />
      <div style={{ display: "flex", flexWrap: "wrap", gap: 10, marginTop: 14 }}>
        <button type="button" onClick={save} disabled={saving}>{saving ? "儲存中…" : "儲存預設發票資料"}</button>
        <Link href="/pricing">回方案頁付款</Link>
      </div>
      {message ? <p className={styles.accountHint}>{message}</p> : null}
      <p className={styles.accountHint}>已付款訂單不會被之後修改的預設資料覆蓋；每筆訂單會保留當下的發票快照，方便客服與退款作廢 / 折讓追蹤。</p>
    </article>
  );
}

export default function Page() {
  const { accessToken, email, authedFetch } = useAuthedJson("/account/billing");
  const [payload, setPayload] = useState<any>(null);
  const [message, setMessage] = useState("正在讀取帳務資料…");

  async function loadBilling() {
    const data = await authedFetch("/api/account/billing");
    setPayload(data);
    setMessage("");
  }

  useEffect(() => {
    if (!accessToken) return;
    loadBilling().catch((error) => setMessage(error.message));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [accessToken]);

  const orders = payload?.payment_orders || [];
  const ledger = payload?.billing_ledger || [];
  const refunds = payload?.refund_requests || [];
  const invoices = payload?.invoice_events || [];
  const invoiceTasks = payload?.invoice_tasks || [];
  const refundTasks = payload?.refund_tasks || [];
  const subscriptions = payload?.subscription_profiles || [];
  const entitlement = payload?.entitlement;

  const invoiceRows = useMemo(
    () =>
      orders.map((order: any) => ({
        id: `invoice-${order.id}`,
        title: `${order.item_name || order.plan_code || "付款訂單"}｜${invoiceLabel(order, invoices, invoiceTasks)}`,
        body: `${order.merchant_trade_no}｜付款 ${order.status}｜${formatDateTime(order.paid_at || order.created_at)}｜${describeInvoicePreference(order.invoice_preference)}`,
      })),
    [orders, invoices, invoiceTasks],
  );

  const refundRows = useMemo(
    () =>
      orders
        .filter((order: any) => refunds.some((refund: any) => refund.payment_order_id === order.id))
        .map((order: any) => ({
          id: `refund-${order.id}`,
          title: `${order.item_name || order.plan_code || "付款訂單"}｜${refundLabel(order, refunds, refundTasks)}`,
          body: `${formatTwd(order.amount)}｜${order.merchant_trade_no}`,
        })),
    [orders, refunds, refundTasks],
  );

  return (
    <FormalOpsShell
      activeHref="/account/billing"
      navItems={accountOpsNav}
      eyebrow="Billing Center"
      title="帳務紀錄"
      description="付款、權益、發票、退款與訂閱狀態會集中到這裡。"
      quoteTitle={entitlement?.plan || "free"}
      quoteBody={`VIP 到期：${formatDateTime(entitlement?.vip_until)}`}
      topActions={
        <>
          <Link href="/pricing">查看方案</Link>
          <Link href="/account/refunds">申請退款</Link>
          <Link href="/account/subscriptions">訂閱管理</Link>
        </>
      }
      dataPage="account-billing-v120-invoice-preference"
    >
      {message ? <div className={styles.accountLoading}>{message}</div> : null}

      {accessToken ? (
        <section className={styles.accountContentGrid}>
          <InvoicePreferenceCard email={email} authedFetch={authedFetch} />
          <article className={styles.accountContentCard}>
            <div className={styles.accountContentHead}>
              <div>
                <span className="i20-kicker">How it works</span>
                <h3>發票資料怎麼被記住</h3>
              </div>
            </div>
            <div className={styles.accountPreferenceList}>
              <div>
                <b>帳務中心保存預設</b>
                <span>儲存在 user_invoice_preferences，之後付款會自動帶入。</span>
              </div>
              <div>
                <b>結帳前可單次調整</b>
                <span>修改後可選擇是否保存為下次預設。</span>
              </div>
              <div>
                <b>訂單保存快照</b>
                <span>付款建立時會寫入 payment_orders.invoice_preference；後續改預設不會影響舊訂單。</span>
              </div>
            </div>
          </article>
        </section>
      ) : null}

      <section className={styles.accountMetricGrid}>
        <article className={styles.accountMetricCard}>
          <span className="i20-kicker">Orders</span>
          <h3>付款訂單</h3>
          <b>{orders.length}</b>
          <p>付款成立後會同步權益、帳務與發票任務。</p>
        </article>
        <article className={styles.accountMetricCard}>
          <span className="i20-kicker">Invoice</span>
          <h3>發票事件</h3>
          <b>{invoices.length}</b>
          <p>已請求、已開立、失敗或退款後需作廢 / 折讓都會顯示。</p>
        </article>
        <article className={styles.accountMetricCard}>
          <span className="i20-kicker">Refunds</span>
          <h3>退款申請</h3>
          <b>{refunds.length}</b>
          <p>退款需要客服與帳務審核。</p>
        </article>
      </section>

      <section className={styles.accountContentGrid}>
        <article className={styles.accountContentCard}>
          <div className={styles.accountContentHead}>
            <div>
              <span className="i20-kicker">Payment Orders</span>
              <h3>付款紀錄</h3>
            </div>
            <button type="button" onClick={() => loadBilling().catch((error) => setMessage(error.message))}>重新整理</button>
          </div>
          <div className={styles.accountPreferenceList}>
            {orders.map((order: any) => (
              <div key={order.id || order.merchant_trade_no}>
                <b>{order.item_name || order.plan_code || "付款訂單"}｜{formatTwd(order.amount)}</b>
                <span>{order.status}｜{order.merchant_trade_no}｜{formatDateTime(order.created_at)}</span>
