"use client";

import { useEffect, useState } from "react";
import { FormalOpsShell, adminOpsNav } from "@/components/formalOps/FormalOpsShell";
import { formatDateTime, formatTwd, useAuthedJson } from "@/components/formalOps/useAuthedJson";
import styles from "@/components/image20/Image20Auxiliary.module.css";

export default function Page() {
  const { accessToken, authedFetch } = useAuthedJson("/admin/refunds");
  const [refunds, setRefunds] = useState<any[]>([]);
  const [msg, setMsg] = useState("正在讀取退款申請…");

  async function load() {
    const p = await authedFetch("/api/admin/billing/refunds?limit=160");
    setRefunds(p.refunds || []);
  }

  useEffect(() => {
    if (!accessToken) return;
    load().then(() => setMsg("")).catch((e) => setMsg(e.message));
  }, [accessToken]);

  async function update(id: string, status: string) {
    let adminNote = `Admin quick update: ${status}`;
    let providerRefundId = "";
    let manualRefundConfirmed = false;

    if (status === "refunded") {
      providerRefundId = window.prompt("請輸入綠界退刷 / 人工退款的 provider refund id 或對帳備註：", "") || "";
      if (!providerRefundId) {
        manualRefundConfirmed = window.confirm("沒有 provider refund id。你確定要以人工確認方式標記已退款嗎？");
        if (!manualRefundConfirmed) return;
      }
      adminNote = window.prompt("請填寫退款完成備註：", providerRefundId ? `人工確認退款完成：${providerRefundId}` : "人工確認退款完成") || adminNote;
    }

    if (status === "approved") {
      adminNote = window.prompt("核准退款備註：", "核准退款，建立退刷任務。") || adminNote;
    }

    setMsg("正在更新退款狀態…");
    try {
      await authedFetch(`/api/admin/billing/refunds/${id}`, {
        method: "PATCH",
        body: JSON.stringify({
          status,
          admin_note: adminNote,
          provider_refund_id: providerRefundId || undefined,
          manual_refund_confirmed: manualRefundConfirmed,
        }),
      });
      await load();
      setMsg(status === "approved" ? "已核准退款，並建立退刷任務。" : "已更新退款狀態。");
    } catch (e: any) {
      setMsg(e?.message || "更新退款狀態失敗。");
    }
  }

  return (
    <FormalOpsShell
      activeHref="/admin/refunds"
      navItems={adminOpsNav}
      eyebrow="Refund Queue"
      title="退款審核"
      description="退款不是刪掉訂單，而是留下清楚處理紀錄，並和客服、付款、退刷任務、發票作廢 / 折讓流程保持一致。"
      dataPage="admin-refunds-v115"
    >
      {msg ? <div className={styles.accountLoading}>{msg}</div> : null}
      <section className={styles.accountContentGrid}>
        <article className={styles.accountContentCard}>
          <div className={styles.accountContentHead}>
            <div>
              <span className="i20-kicker">Requests</span>
              <h3>退款申請</h3>
            </div>
            <button type="button" onClick={() => load().catch((e) => setMsg(e.message))}>重新整理</button>
          </div>
          <div className={styles.accountPreferenceList}>
            {refunds.map((r) => (
              <div key={r.id}>
                <b>{formatTwd(r.amount_twd)}｜{r.reason_category}</b>
                <span>{r.status}｜{r.user_id}｜{formatDateTime(r.created_at)}</span>
                <span>{r.provider_refund_id ? `provider refund id：${r.provider_refund_id}` : "尚未有 provider refund id"}</span>
                <span>
                  <button type="button" onClick={() => update(r.id, "reviewing")}>審核中</button>{" "}
                  <button type="button" onClick={() => update(r.id, "approved")}>核准並建立退刷任務</button>{" "}
                  <button type="button" onClick={() => update(r.id, "rejected")}>拒絕</button>{" "}
                  <button type="button" onClick={() => update(r.id, "refunded")}>人工標記已退款</button>
                </span>
              </div>
            ))}
            {refunds.length === 0 ? (
              <div>
                <b>目前沒有退款申請。</b>
                <span>使用者送出退款申請後會出現在這裡。</span>
              </div>
            ) : null}
          </div>
        </article>
      </section>
    </FormalOpsShell>
  );
}

"use client";
import { useEffect, useMemo, useState } from "react";
import { FormalOpsShell, adminOpsNav } from "@/components/formalOps/FormalOpsShell";
import { formatDateTime, useAuthedJson } from "@/components/formalOps/useAuthedJson";
import styles from "@/components/image20/Image20Auxiliary.module.css";
const roleOptions = ["owner", "ops", "support", "safety", "finance", "viewer", "custom"] as const;
type Assignment = { id: string; user_id: string; role_key: string; permissions: string[]; status: string; note?: string | null; granted_at?: string | null; updated_at?: string | null };
export default function AdminRolesPage() {
  const { accessToken, authedFetch } = useAuthedJson("/admin/roles");
  const [assignments, setAssignments] = useState<Assignment[]>([]); const [presets, setPresets] = useState<any[]>([]); const [allPermissions, setAllPermissions] = useState<string[]>([]); const [currentAdmin, setCurrentAdmin] = useState<any>(null); const [message, setMessage] = useState("正在讀取管理權限…");
  const [form, setForm] = useState({ user_id: "", email: "", role_key: "viewer", permissions: "", status: "active", note: "" });
  const activeOwners = useMemo(() => assignments.filter((item) => item.status === "active" && item.role_key === "owner"), [assignments]);
  async function load() { const payload = await authedFetch("/api/admin/roles"); setAssignments(payload.assignments || []); setPresets(payload.presets || []); setAllPermissions(payload.all_permissions || []); setCurrentAdmin(payload.current_admin || null); }
  useEffect(() => { if (!accessToken) return; load().then(() => setMessage("")).catch((error) => setMessage(error.message)); /* eslint-disable-next-line react-hooks/exhaustive-deps */ }, [accessToken]);
  async function createAssignment(event: React.FormEvent<HTMLFormElement>) { event.preventDefault(); setMessage("正在建立 admin role assignment…"); try { await authedFetch("/api/admin/roles", { method: "POST", body: JSON.stringify({ user_id: form.user_id || undefined, email: form.email || undefined, role_key: form.role_key, permissions: form.permissions.split(",").map((item) => item.trim()).filter(Boolean), status: form.status, note: form.note }) }); setForm({ user_id: "", email: "", role_key: "viewer", permissions: "", status: "active", note: "" }); await load(); setMessage("已建立管理權限。"); } catch (error: any) { setMessage(error?.message || "建立管理權限失敗。"); } }
  async function updateAssignment(id: string, patch: Record<string, unknown>) { setMessage("正在更新管理權限…"); try { await authedFetch(`/api/admin/roles/${id}`, { method: "PATCH", body: JSON.stringify(patch) }); await load(); setMessage("已更新管理權限。"); } catch (error: any) { setMessage(error?.message || "更新管理權限失敗。"); } }
  return (
    <FormalOpsShell activeHref="/admin/roles" navItems={adminOpsNav} eyebrow="Admin RBAC" title="權限管理" description="正式商業平台不能長期只靠 Vercel env 隱藏 Admin 入口；這裡建立 DB-backed role assignments，並保留 env 作為短期 break-glass fallback。" quoteTitle={currentAdmin ? `${currentAdmin.role_key} / ${currentAdmin.source}` : "讀取中"} quoteBody={`Active owners: ${activeOwners.length}。每次權限異動都會寫 admin_audit_logs。`} dataPage="admin-rbac-v115">
      {message ? <div className={styles.accountLoading}>{message}</div> : null}
