export default function Page(){const p=useParams();const userId=String((p as any)?.userId||"");const{accessToken,authedFetch}=useAuthedJson(`/admin/users/${userId}`);const[data,setData]=useState<any>(null);const[note,setNote]=useState("");const[msg,setMsg]=useState("正在讀取使用者 360…");async function load(){setData(await authedFetch(`/api/admin/users/${userId}`))}useEffect(()=>{if(!accessToken||!userId)return;load().then(()=>setMsg("")).catch(e=>setMsg(e.message))},[accessToken,userId]);async function add(e:React.FormEvent<HTMLFormElement>){e.preventDefault();setMsg("正在新增管理備註…");try{await authedFetch("/api/admin/entity-notes",{method:"POST",body:JSON.stringify({target_type:"user",target_id:userId,body:note})});setNote("");await load();setMsg("已新增管理備註。")}catch(err:any){setMsg(err?.message||"新增備註失敗。")}}const user=data?.user||{};const s=data?.sections||{};const errs=Object.values(s).map((x:any)=>x?.error).filter(Boolean).concat(data?.errors||[]);return <FormalOpsShell activeHref="/admin/users" navItems={adminOpsNav} eyebrow="User Detail" title={user.email||user.phone||userId} description="將付款、客服、退款、房間、AI 額度、訂閱與安全事件放在同一個使用者視圖。" quoteTitle={userId.slice(0,8)} quoteBody={`建立 ${formatDateTime(user.created_at)}｜最後登入 ${formatDateTime(user.last_sign_in_at)}`} topActions={<><Link href="/admin/users">返回搜尋</Link><Link href={`/admin/ai/host-credits?user_id=${userId}`}>AI 額度</Link></>} dataPage="admin-user-detail-v110">{msg?<div className={styles.accountLoading}>{msg}</div>:null}{errs.length?<div className={styles.accountLoading}>部分資料表讀取失敗：{errs.join("；")}</div>:null}<section className={styles.accountMetricGrid}><article className={styles.accountMetricCard}><span className="i20-kicker">Plan</span><h3>權益</h3><b>{s.entitlement?.data?.plan||"—"}</b><p>VIP 到期 {formatDateTime(s.entitlement?.data?.vip_until)}</p></article><article className={styles.accountMetricCard}><span className="i20-kicker">Host Credit</span><h3>AI 額度</h3><b>{s.host_credit?.data?.balance_total??0}</b><p>累計使用 {s.host_credit?.data?.lifetime_consumed??0}</p></article><article className={styles.accountMetricCard}><span className="i20-kicker">Orders</span><h3>付款</h3><b>{rows(s.payment_orders).length}</b><p>退款 {rows(s.refund_requests).length} 筆</p></article></section><section className={styles.accountContentGrid}><Card title="付款訂單" items={rows(s.payment_orders)} render={o=><div key={o.id}><b><Link href={`/admin/billing/orders/${o.id}`}>{o.item_name||o.plan_code}</Link>｜{formatTwd(o.amount)}</b><span>{o.status}｜{o.merchant_trade_no}｜{formatDateTime(o.created_at)}</span></div>}/><Card title="客服單" items={rows(s.support_tickets)} render={t=><div key={t.id}><b><Link href={`/admin/support/${t.id}`}>{t.subject}</Link></b><span>{t.status}｜{t.category}｜{formatDateTime(t.updated_at)}</span></div>}/></section><section className={styles.accountContentGrid}><Card title="房間" items={rows(s.rooms_created)} render={r=><div key={r.id}><b><Link href={`/admin/rooms/${r.id}`}>{r.title||r.id}</Link></b><span>{r.status}｜{r.duration_minutes} 分鐘｜{formatDateTime(r.created_at)}</span></div>}/><Card title="訂閱" items={rows(s.subscriptions)} render={sub=><div key={sub.id}><b>{sub.plan_code}｜{sub.status}</b><span>{formatTwd(sub.period_amount)}｜下次 {formatDateTime(sub.next_charge_at)}</span></div>}/></section><section className={styles.accountContentGrid}><Card title="安全 / 檢舉 / 治理" items={[...rows(s.reports_by_user),...rows(s.reports_targeting_user),...rows(s.moderation_cases)]} render={i=><div key={i.id}><b>{i.category||i.target_type||"case"}｜{i.status}</b><span>{i.description||i.summary||"—"}｜{formatDateTime(i.created_at||i.updated_at)}</span></div>}/><Card title="AI / Host Credit 事件" items={rows(s.host_credit_events)} render={ev=><div key={ev.id}><b>{ev.event_type}｜{ev.credits_delta}</b><span>balance {ev.balance_after}｜{formatDateTime(ev.created_at)}</span></div>}/></section><section className={styles.accountContentGrid}><article className={styles.accountContentCard}><div className={styles.accountContentHead}><div><span className="i20-kicker">Notes</span><h3>管理備註</h3></div></div><form className={styles.formStack} onSubmit={add}><label><span className="i20-kicker">備註</span><textarea value={note} onChange={e=>setNote(e.target.value)} rows={5} required /></label><button className="i20-btn peach" type="submit">新增備註</button></form><div className={styles.accountPreferenceList}>{rows(s.notes).map((n:any)=><div key={n.id}><b>{formatDateTime(n.created_at)}</b><span>{n.body}</span></div>)}</div></article><Card title="帳務 Ledger" items={rows(s.billing_ledger)} render={i=><div key={i.id}><b>{i.ledger_type}｜{formatTwd(i.amount_twd)}</b><span>{i.direction}｜{i.description||"—"}｜{formatDateTime(i.occurred_at)}</span></div>}/></section></FormalOpsShell>}

