import Link from "next/link";import {useState} from "react";import {FormalOpsShell,adminOpsNav} from "@/components/formalOps/FormalOpsShell";import {formatDateTime,useAuthedJson} from "@/components/formalOps/useAuthedJson";import styles from "@/components/image20/Image20Auxiliary.module.css";
export default function Page(){const{authedFetch}=useAuthedJson("/admin/users");const[q,setQ]=useState("");const[users,setUsers]=useState<any[]>([]);const[msg,setMsg]=useState("輸入 email、user_id 或手機查詢使用者。");async function search(e?:React.FormEvent<HTMLFormElement>){e?.preventDefault();setMsg("正在查詢使用者…");try{const p=await authedFetch(`/api/admin/users/search?q=${encodeURIComponent(q)}&limit=80`);setUsers(p.users||[]);setMsg((p.users||[]).length?"":"沒有找到使用者。")}catch(err:any){setMsg(err?.message||"查詢失敗。")}}return <FormalOpsShell activeHref="/admin/users" navItems={adminOpsNav} eyebrow="User 360" title="使用者 360" description="客服處理付款、退款、房間、AI 額度與安全事件時，需要先看到完整使用者上下文。" quoteTitle="先查人，再處理" quoteBody="避免客服只看到單一 ticket 而忽略付款或風控狀態。" dataPage="admin-users-v110">{msg?<div className={styles.accountLoading}>{msg}</div>:null}<section className={styles.accountContentGrid}><article className={styles.accountContentCard}><div className={styles.accountContentHead}><div><span className="i20-kicker">Search</span><h3>查詢使用者</h3></div></div><form className={styles.formStack} onSubmit={search}><label><span className="i20-kicker">Email / User ID / Phone</span><input value={q} onChange={e=>setQ(e.target.value)} placeholder="noccs75@gmail.com 或 uuid" /></label><button className="i20-btn peach" type="submit">查詢</button></form></article><article className={styles.accountContentCard}><div className={styles.accountContentHead}><div><span className="i20-kicker">Results</span><h3>查詢結果</h3></div></div><div className={styles.accountPreferenceList}>{users.map(u=><div key={u.id}><b><Link href={`/admin/users/${u.id}`}>{u.email||u.phone||u.id}</Link></b><span>{u.id}｜建立 {formatDateTime(u.created_at)}｜最後登入 {formatDateTime(u.last_sign_in_at)}</span></div>)}</div></article></section></FormalOpsShell>}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { PROFILE_IDENTITY_BUILD_TAG, getAuthUserAdmin, maskEmail, maskPhone, syncVerifiedIdentityBindings } from "@/lib/server/profileIdentity";
export const runtime = "nodejs";
type Body = { action?: "submit_manual_review" | "cancel_pending_review"; legal_name?: string; birth_year?: number | string; document_type?: string; document_last4?: string; user_note?: string };

export async function GET(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const authUser = await getAuthUserAdmin(userId);
    await syncVerifiedIdentityBindings({ userId, email: authUser.email, phone: authUser.phone });
    const [bindings, requests] = await Promise.all([
      supabaseAdmin.from("user_identity_bindings").select("*").eq("user_id", userId).order("created_at", { ascending: false }),
      supabaseAdmin.from("identity_verification_requests").select("*").eq("user_id", userId).order("created_at", { ascending: false }).limit(20),
    ]);
    const firstError = bindings.error || requests.error;
    if (firstError) return NextResponse.json({ error: firstError.message, build_tag: PROFILE_IDENTITY_BUILD_TAG }, { status: 400 });
    return NextResponse.json({ auth: { email_masked: maskEmail(authUser.email), phone_masked: maskPhone(authUser.phone), email_verified: Boolean((authUser as any).email_confirmed_at || authUser.email), phone_verified: Boolean((authUser as any).phone_confirmed_at || authUser.phone) }, bindings: bindings.data ?? [], requests: requests.data ?? [], build_tag: PROFILE_IDENTITY_BUILD_TAG });
  } catch (error: any) {
