import { ADMIN_OPS_BUILD_TAG, adminErrorResponse, getAdminUserFromRequest, writeAdminAudit } from "@/lib/server/adminAuth";

export const runtime = "nodejs";

async function safeCount(table: string, apply?: (query: any) => any) {
  let query = supabaseAdmin.from(table).select("id", { count: "exact", head: true });
  if (apply) query = apply(query);
  const { count, error } = await query;
  if (error) return { count: null, error: error.message };
  return { count: count ?? 0, error: null };
}

export async function GET(req: Request) {
  try {
    const admin = await getAdminUserFromRequest(req);

    const [openTickets, openReports, openModerationCases, requestedRefunds, activeRooms, pendingPayments, paidPayments, recentReliability] = await Promise.all([
      safeCount("support_tickets", (q) => q.in("status", ["open", "pending", "admin_review"])),
      safeCount("user_reports", (q) => q.in("status", ["open", "triaged"])),
      safeCount("moderation_cases", (q) => q.in("status", ["open", "investigating", "action_required"])),
      safeCount("refund_requests", (q) => q.in("status", ["requested", "reviewing", "approved", "processing"])),
      safeCount("rooms", (q) => q.eq("status", "active").is("ended_at", null)),
      safeCount("payment_orders", (q) => q.eq("status", "pending")),
      safeCount("payment_orders", (q) => q.eq("status", "paid")),
      supabaseAdmin.from("reliability_events").select("id,user_id,room_id,event_type,severity,source,metadata,created_at").order("created_at", { ascending: false }).limit(20),
    ]);

    await writeAdminAudit(req, {
      adminUserId: admin.userId,
      actionType: "admin_ops_summary_viewed",
      targetType: "ops_summary",
      metadata: { admin_by: admin.adminBy },
    });

    return NextResponse.json({
      summary: {
        open_tickets: openTickets,
        open_reports: openReports,
        open_moderation_cases: openModerationCases,
        requested_refunds: requestedRefunds,
        active_rooms: activeRooms,
        pending_payments: pendingPayments,
        paid_payments: paidPayments,
      },
      recent_reliability_events: recentReliability.data ?? [],
      build_tag: ADMIN_OPS_BUILD_TAG,
    });
  } catch (error: any) {
    const res = adminErrorResponse(error);
    return NextResponse.json(res.body, { status: res.status });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { ADMIN_OPS_BUILD_TAG, ALL_ADMIN_PERMISSIONS, adminErrorResponse, getAdminUserFromRequest, writeAdminAudit, type AdminRoleKey } from "@/lib/server/adminAuth";
export const runtime = "nodejs";
type Context = { params: Promise<{ assignmentId: string }> };
type PatchBody = { role_key?: AdminRoleKey; permissions?: string[]; status?: "active" | "inactive" | "revoked"; note?: string | null };
function normalizePermissions(value: unknown) { const valid = new Set<string>(ALL_ADMIN_PERMISSIONS); if (!Array.isArray(value)) return []; return Array.from(new Set(value.map((item) => String(item)).filter((item) => valid.has(item)))); }
function normalizeRole(value: unknown): AdminRoleKey | null { if (value === undefined) return null; const role = String(value || "") as AdminRoleKey; return ["owner", "ops", "support", "safety", "finance", "viewer", "custom"].includes(role) ? role : null; }
export async function PATCH(req: Request, context: Context) {
  try {
    const admin = await getAdminUserFromRequest(req, { permission: "admin.manage_roles" });
    const { assignmentId } = await context.params;
    const body = (await req.json().catch(() => ({}))) as PatchBody;
    const existing = await supabaseAdmin.from("admin_role_assignments").select("*").eq("id", assignmentId).maybeSingle();
    if (existing.error || !existing.data) return NextResponse.json({ error: existing.error?.message || "找不到 admin role assignment。", build_tag: ADMIN_OPS_BUILD_TAG }, { status: 404 });
    if (existing.data.user_id === admin.userId && body.status && body.status !== "active") return NextResponse.json({ error: "不能停用或撤銷自己的管理員權限。", build_tag: ADMIN_OPS_BUILD_TAG }, { status: 400 });
    const patch: Record<string, unknown> = { updated_at: new Date().toISOString() };
    const role = normalizeRole(body.role_key); if (role) patch.role_key = role;
    if (Array.isArray(body.permissions)) patch.permissions = normalizePermissions(body.permissions);
    if (body.status && ["active", "inactive", "revoked"].includes(body.status)) { patch.status = body.status; if (body.status === "revoked") { patch.revoked_at = new Date().toISOString(); patch.revoked_by_admin_user_id = admin.userId; } }
    if (body.note !== undefined) patch.note = String(body.note || "").trim().slice(0, 2000) || null;
    if (patch.status === "active") await supabaseAdmin.from("admin_role_assignments").update({ status: "inactive", revoked_by_admin_user_id: admin.userId, revoked_at: new Date().toISOString(), updated_at: new Date().toISOString(), metadata: { reason: "replaced_by_assignment_patch" } }).eq("user_id", existing.data.user_id).eq("status", "active").neq("id", assignmentId);
    const updated = await supabaseAdmin.from("admin_role_assignments").update(patch).eq("id", assignmentId).select("*").single();
    if (updated.error || !updated.data) return NextResponse.json({ error: updated.error?.message || "更新 admin role 失敗。", build_tag: ADMIN_OPS_BUILD_TAG }, { status: 400 });
    await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "admin_role_assignment_updated", targetType: "admin_role_assignment", targetId: assignmentId, metadata: { before: { user_id: existing.data.user_id, role_key: existing.data.role_key, permissions: existing.data.permissions, status: existing.data.status }, after: { user_id: updated.data.user_id, role_key: updated.data.role_key, permissions: updated.data.permissions, status: updated.data.status } } });
    return NextResponse.json({ assignment: updated.data, build_tag: ADMIN_OPS_BUILD_TAG });
  } catch (error: any) { const res = adminErrorResponse(error); return NextResponse.json(res.body, { status: res.status }); }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { ADMIN_OPS_BUILD_TAG, ALL_ADMIN_PERMISSIONS, ADMIN_ROLE_PRESET_PERMISSIONS, adminErrorResponse, getAdminUserFromRequest, writeAdminAudit, type AdminRoleKey } from "@/lib/server/adminAuth";
export const runtime = "nodejs";
type CreateBody = { user_id?: string; email?: string; role_key?: AdminRoleKey; permissions?: string[]; status?: "active" | "inactive"; note?: string | null };
function normalizeRole(value: unknown): AdminRoleKey { const role = String(value || "viewer") as AdminRoleKey; return ["owner", "ops", "support", "safety", "finance", "viewer", "custom"].includes(role) ? role : "viewer"; }
function normalizePermissions(value: unknown) { const valid = new Set<string>(ALL_ADMIN_PERMISSIONS); if (!Array.isArray(value)) return []; return Array.from(new Set(value.map((item) => String(item)).filter((item) => valid.has(item)))); }
async function resolveUserId(input: { user_id?: string; email?: string }) {
  const userId = String(input.user_id || "").trim(); if (userId) return userId;
  const email = String(input.email || "").trim().toLowerCase(); if (!email) throw new Error("缺少 user_id 或 email。");
  const { data, error } = await supabaseAdmin.auth.admin.listUsers({ page: 1, perPage: 1000 }); if (error) throw error;
  const user = data.users.find((item) => String(item.email || "").toLowerCase() === email); if (!user) throw new Error("找不到這個 Email 對應的 Supabase 使用者。");
  return user.id;
}
export async function GET(req: Request) {
  try {
    const admin = await getAdminUserFromRequest(req, { permission: "admin.read" });
    const [assignments, presets] = await Promise.all([
      supabaseAdmin.from("admin_role_assignments").select("*").order("status", { ascending: true }).order("updated_at", { ascending: false }).limit(200),
      supabaseAdmin.from("admin_permission_presets").select("*").order("role_key", { ascending: true }),
    ]);
    const firstError = assignments.error || presets.error; if (firstError) return NextResponse.json({ error: firstError.message, build_tag: ADMIN_OPS_BUILD_TAG }, { status: 400 });
    await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "admin_roles_listed", targetType: "admin_role_assignments", metadata: { admin_source: admin.adminSource, role_key: admin.roleKey } });
    return NextResponse.json({ assignments: assignments.data ?? [], presets: presets.data ?? [], fallback_presets: ADMIN_ROLE_PRESET_PERMISSIONS, all_permissions: ALL_ADMIN_PERMISSIONS, current_admin: { user_id: admin.userId, email: admin.email, source: admin.adminSource, role_key: admin.roleKey, permissions: admin.permissions }, build_tag: ADMIN_OPS_BUILD_TAG });
  } catch (error: any) { const res = adminErrorResponse(error); return NextResponse.json(res.body, { status: res.status }); }
}
export async function POST(req: Request) {
  try {
    const admin = await getAdminUserFromRequest(req, { permission: "admin.manage_roles" });
    const body = (await req.json().catch(() => ({}))) as CreateBody;
    const targetUserId = await resolveUserId(body); const roleKey = normalizeRole(body.role_key); const permissions = normalizePermissions(body.permissions); const status = body.status === "inactive" ? "inactive" : "active"; const note = String(body.note || "").trim().slice(0, 2000) || null;
    if (targetUserId === admin.userId && roleKey !== "owner") return NextResponse.json({ error: "不能用這個 route 把自己的角色降級。請先指定另一位 owner。", build_tag: ADMIN_OPS_BUILD_TAG }, { status: 400 });
    if (status === "active") await supabaseAdmin.from("admin_role_assignments").update({ status: "inactive", revoked_by_admin_user_id: admin.userId, revoked_at: new Date().toISOString(), updated_at: new Date().toISOString(), metadata: { reason: "replaced_by_new_active_assignment" } }).eq("user_id", targetUserId).eq("status", "active");
    const inserted = await supabaseAdmin.from("admin_role_assignments").insert({ user_id: targetUserId, role_key: roleKey, permissions, status, granted_by_admin_user_id: admin.userId, note, metadata: { source: "admin_roles_route_v115" } }).select("*").single();
    if (inserted.error || !inserted.data) return NextResponse.json({ error: inserted.error?.message || "建立 admin role 失敗。", build_tag: ADMIN_OPS_BUILD_TAG }, { status: 400 });
    await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "admin_role_assignment_created", targetType: "admin_role_assignment", targetId: inserted.data.id, metadata: { target_user_id: targetUserId, role_key: roleKey, status, permissions } });
    return NextResponse.json({ assignment: inserted.data, build_tag: ADMIN_OPS_BUILD_TAG });
  } catch (error: any) { const res = adminErrorResponse(error); return NextResponse.json(res.body, { status: res.status }); }
}

import { NextResponse } from "next/server";
import { ADMIN_OPS_BUILD_TAG, adminErrorResponse, getAdminUserFromRequest, writeAdminAudit } from "@/lib/server/adminAuth";
import { ROOM_RECONCILIATION_BUILD_TAG, deleteDailyRoomByName, endSupabaseRoom, markReconciliationItem } from "@/lib/server/roomReconciliation";
import { supabaseAdmin } from "@/lib/supabaseAdmin";

export const runtime = "nodejs";
type Context = { params: Promise<{ itemId: string }> };
type Body = { action?: "mark_in_progress" | "ignore" | "mark_fixed" | "end_room" | "delete_daily_room" | "end_room_and_delete_daily"; note?: string };

export async function PATCH(req: Request, context: Context) {
  try {
    const admin = await getAdminUserFromRequest(req, { permission: "rooms.manage" });
    const { itemId } = await context.params;
    const body = (await req.json().catch(() => ({}))) as Body;
    const action = body.action || "mark_in_progress";
    const itemResult = await supabaseAdmin.from("room_reconciliation_items").select("*").eq("id", itemId).maybeSingle();
    if (itemResult.error || !itemResult.data) return NextResponse.json({ error: itemResult.error?.message || "找不到 reconciliation item。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 404 });
    const item = itemResult.data as any;
    let actionResult: Record<string, unknown> = { action, note: body.note || null };
    if (action === "mark_in_progress") {
      const updated = await markReconciliationItem({ itemId, adminUserId: admin.userId, status: "in_progress", result: actionResult });
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_item_in_progress", targetType: "room_reconciliation_item", targetId: itemId });
      return NextResponse.json({ item: updated, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    if (action === "ignore") {
      const updated = await markReconciliationItem({ itemId, adminUserId: admin.userId, status: "ignored", result: actionResult });
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_item_ignored", targetType: "room_reconciliation_item", targetId: itemId });
      return NextResponse.json({ item: updated, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    if (action === "mark_fixed") {
      const updated = await markReconciliationItem({ itemId, adminUserId: admin.userId, status: "fixed", result: actionResult });
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_item_marked_fixed", targetType: "room_reconciliation_item", targetId: itemId });
      return NextResponse.json({ item: updated, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    if (action === "end_room" || action === "end_room_and_delete_daily") {
      if (!item.room_id) return NextResponse.json({ error: "此 item 沒有 room_id。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 400 });
      const room = await endSupabaseRoom(item.room_id, admin.userId, `room_reconciliation_item:${itemId}`);
      actionResult = { ...actionResult, room };
      if (action === "end_room_and_delete_daily" && item.daily_room_name) actionResult.daily_result = await deleteDailyRoomByName(item.daily_room_name);
      const updated = await markReconciliationItem({ itemId, adminUserId: admin.userId, status: "fixed", result: actionResult });
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: `room_reconciliation_item_${action}`, targetType: "room_reconciliation_item", targetId: itemId, metadata: actionResult });
      return NextResponse.json({ item: updated, result: actionResult, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    if (action === "delete_daily_room") {
      if (!item.daily_room_name) return NextResponse.json({ error: "此 item 沒有 daily_room_name。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 400 });
      actionResult.daily_result = await deleteDailyRoomByName(item.daily_room_name);
      const updated = await markReconciliationItem({ itemId, adminUserId: admin.userId, status: "fixed", result: actionResult });
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_item_delete_daily_room", targetType: "room_reconciliation_item", targetId: itemId, metadata: actionResult });
      return NextResponse.json({ item: updated, result: actionResult, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    return NextResponse.json({ error: "不支援的 action。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 400 });
  } catch (error: any) {
    const res = adminErrorResponse(error);
    return NextResponse.json(res.body, { status: res.status });
  }
}

import { NextResponse } from "next/server";
import { ADMIN_OPS_BUILD_TAG, adminErrorResponse, getAdminUserFromRequest, writeAdminAudit } from "@/lib/server/adminAuth";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { ROOM_RECONCILIATION_BUILD_TAG, deleteDailyRoomByName, endSupabaseRoom, persistRoomReconciliationRun, scanRoomReconciliation } from "@/lib/server/roomReconciliation";

export const runtime = "nodejs";

type Body = { action?: "scan" | "end_room" | "delete_daily_room" | "end_room_and_delete_daily"; room_id?: string; daily_room_name?: string; reason?: string; persist?: boolean };

export async function GET(req: Request) {
  try {
    const admin = await getAdminUserFromRequest(req, { permission: "rooms.manage" });
    const url = new URL(req.url);
    const persist = url.searchParams.get("persist") === "1";
    const limit = Math.min(Math.max(Number(url.searchParams.get("history_limit") || 40), 1), 100);
    const [scan, runs, openItems] = await Promise.all([
      scanRoomReconciliation(),
      supabaseAdmin.from("room_reconciliation_runs").select("*").order("created_at", { ascending: false }).limit(limit),
      supabaseAdmin.from("room_reconciliation_items").select("*").in("status", ["open", "in_progress", "failed"]).order("created_at", { ascending: false }).limit(200),
    ]);
    const persisted = persist ? await persistRoomReconciliationRun({ adminUserId: admin.userId, runType: "manual_scan", scan }) : null;
    await writeAdminAudit(req, { adminUserId: admin.userId, actionType: persist ? "room_reconciliation_scanned_and_persisted" : "room_reconciliation_scanned", targetType: "room_reconciliation", metadata: { summary: scan.summary, persist } });
    return NextResponse.json({ ...scan, runs: runs.error ? [] : runs.data ?? [], open_items: openItems.error ? [] : openItems.data ?? [], errors: [runs.error?.message, openItems.error?.message, scan.daily_error].filter(Boolean), persisted, build_tag: ROOM_RECONCILIATION_BUILD_TAG, admin_build_tag: ADMIN_OPS_BUILD_TAG });
  } catch (error: any) {
    const res = adminErrorResponse(error);
    return NextResponse.json(res.body, { status: res.status });
  }
}

export async function POST(req: Request) {
  try {
    const admin = await getAdminUserFromRequest(req, { permission: "rooms.manage" });
    const body = (await req.json().catch(() => ({}))) as Body;
    const action = body.action || "scan";
    if (action === "scan") {
      const scan = await scanRoomReconciliation();
      const persisted = body.persist === false ? null : await persistRoomReconciliationRun({ adminUserId: admin.userId, runType: "manual_scan", scan });
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_scan_created", targetType: "room_reconciliation", targetId: persisted?.run?.id ?? null, metadata: { summary: scan.summary } });
      return NextResponse.json({ ...scan, persisted, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    if (action === "end_room") {
      const roomId = String(body.room_id || "").trim();
      if (!roomId) return NextResponse.json({ error: "缺少 room_id。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 400 });
      const room = await endSupabaseRoom(roomId, admin.userId, body.reason || "admin_reconciliation_end_room");
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_end_room", targetType: "room", targetId: roomId, metadata: { reason: body.reason || null } });
      return NextResponse.json({ room, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    if (action === "delete_daily_room") {
      const roomName = String(body.daily_room_name || "").trim();
      if (!roomName) return NextResponse.json({ error: "缺少 daily_room_name。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 400 });
      const result = await deleteDailyRoomByName(roomName);
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_delete_daily_room", targetType: "daily_room", targetId: roomName, metadata: { result } });
      return NextResponse.json({ daily_room_name: roomName, result, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    if (action === "end_room_and_delete_daily") {
      const roomId = String(body.room_id || "").trim();
      const roomName = String(body.daily_room_name || "").trim();
      if (!roomId) return NextResponse.json({ error: "缺少 room_id。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 400 });
      const room = await endSupabaseRoom(roomId, admin.userId, body.reason || "admin_reconciliation_end_room_and_delete_daily");
      const dailyResult = roomName ? await deleteDailyRoomByName(roomName) : { ok: false, skipped: true, reason: "missing_daily_room_name" };
      await writeAdminAudit(req, { adminUserId: admin.userId, actionType: "room_reconciliation_end_room_and_delete_daily", targetType: "room", targetId: roomId, metadata: { daily_room_name: roomName, daily_result: dailyResult } });
      return NextResponse.json({ room, daily_room_name: roomName, daily_result: dailyResult, build_tag: ROOM_RECONCILIATION_BUILD_TAG });
    }
    return NextResponse.json({ error: "不支援的 action。", build_tag: ROOM_RECONCILIATION_BUILD_TAG }, { status: 400 });
  } catch (error: any) {
    const res = adminErrorResponse(error);
    return NextResponse.json(res.body, { status: res.status });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { ADMIN_OPS_BUILD_TAG, adminErrorResponse, getAdminUserFromRequest, writeAdminAudit } from "@/lib/server/adminAuth";
import { cleanText } from "@/lib/server/safety";

export const runtime = "nodejs";
export async function GET(req: Request) {
  try {
