import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { BUDDIES_BUILD_TAG, type BuddyBookingRow } from "@/lib/buddies";

export const runtime = "nodejs";

type RouteContext = { params: Promise<{ serviceId: string }> };
type ReviewPayload = { booking_id?: string; rating?: number; comment?: string | null };

export async function POST(req: Request, context: RouteContext) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { serviceId } = await context.params;
    const body = (await req.json()) as ReviewPayload;
    const bookingId = (body.booking_id ?? "").trim();
    const rating = Number(body.rating ?? 0);
    const comment = (body.comment ?? "").trim().slice(0, 600) || null;

    if (!bookingId) {
      return NextResponse.json({ error: "請先指定 booking。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }
    if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
      return NextResponse.json({ error: "評分必須是 1～5。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }

    const bookingResult = await supabaseAdmin.from("buddy_bookings").select("*").eq("id", bookingId).maybeSingle();
    const booking = bookingResult.data as BuddyBookingRow | null;

    if (bookingResult.error || !booking) {
      return NextResponse.json({ error: bookingResult.error?.message ?? "找不到 booking。", build_tag: BUDDIES_BUILD_TAG }, { status: 404 });
    }
    if (booking.service_id !== serviceId) {
      return NextResponse.json({ error: "booking 與服務不一致。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }
    if (booking.booking_status !== "completed") {
      return NextResponse.json({ error: "只有已完成的預約才能評價。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }
    if (booking.buyer_user_id !== userId && booking.provider_user_id !== userId) {
      return NextResponse.json({ error: "你沒有權限評價這筆預約。", build_tag: BUDDIES_BUILD_TAG }, { status: 403 });
    }

    const revieweeUserId = booking.buyer_user_id === userId ? booking.provider_user_id : booking.buyer_user_id;
    const insertResult = await supabaseAdmin
      .from("buddy_reviews")
      .insert({
        booking_id: booking.id,
        service_id: serviceId,
        reviewer_user_id: userId,
        reviewee_user_id: revieweeUserId,
        rating,
        comment,
      })
      .select("*")
      .single();

    if (insertResult.error || !insertResult.data) {
      return NextResponse.json({ error: insertResult.error?.message ?? "寫入評價失敗。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ review: insertResult.data, build_tag: BUDDIES_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再留下評價。", build_tag: BUDDIES_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "Unexpected server error", build_tag: BUDDIES_BUILD_TAG }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { areUsersFriends, extractBearer, getAuthUserFromRequest, isVipUser } from "@/lib/serverRoomUtils";
import { BUDDIES_BUILD_TAG } from "@/lib/buddies";

export const runtime = "nodejs";
type Context = { params: Promise<{ serviceId: string }> };

async function tryViewer(req: Request) {
  if (!extractBearer(req)) return null;
  try { return await getAuthUserFromRequest(req); } catch { return null; }
}

async function canViewService(req: Request, service: any) {
  if (service.visibility === "public") return { ok: true, viewer: await tryViewer(req) };
  const viewer = await tryViewer(req);
  if (!viewer?.userId) return { ok: false, viewer: null, status: 401, error: "請先登入後再查看這個服務。" };
  if (service.provider_user_id === viewer.userId) return { ok: true, viewer };
  if (service.visibility === "members") return { ok: await isVipUser(viewer.userId), viewer, status: 403, error: "這個服務目前只開放會員查看。" };
  if (service.visibility === "friends") return { ok: await areUsersFriends(viewer.userId, service.provider_user_id), viewer, status: 403, error: "這個服務目前只開放好友查看。" };
  return { ok: false, viewer, status: 403, error: "你目前沒有權限查看這個服務。" };
}

export async function GET(req: Request, context: Context) {
  try {
    const { serviceId } = await context.params;
    const serviceResult = await supabaseAdmin.from("buddy_services").select("*").eq("id", serviceId).maybeSingle();
    if (serviceResult.error || !serviceResult.data) return NextResponse.json({ error: serviceResult.error?.message || "找不到服務。", build_tag: BUDDIES_BUILD_TAG }, { status: 404 });
    const service = serviceResult.data as any;
    const gate = await canViewService(req, service);
    if (!gate.ok) return NextResponse.json({ error: gate.error, build_tag: BUDDIES_BUILD_TAG }, { status: gate.status || 403 });

    const [profileResult, slotsResult, reviewsResult, approvedIdentityResult] = await Promise.all([
      supabaseAdmin.from("profiles").select("user_id,handle,display_name,avatar_url,bio,tags,is_professional_buddy").eq("user_id", service.provider_user_id).maybeSingle(),
      supabaseAdmin.from("buddy_service_slots").select("*").eq("service_id", service.id).eq("slot_status", "open").gte("starts_at", new Date().toISOString()).order("starts_at", { ascending: true }).limit(40),
      supabaseAdmin.from("buddy_reviews").select("*").eq("service_id", service.id).order("created_at", { ascending: false }).limit(20),
      supabaseAdmin.from("identity_verification_requests").select("id,review_status,reviewed_at").eq("user_id", service.provider_user_id).eq("review_status", "approved").limit(1),
    ]);

    if (profileResult.error) return NextResponse.json({ error: profileResult.error.message, build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    if (slotsResult.error) return NextResponse.json({ error: slotsResult.error.message, build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    if (reviewsResult.error) return NextResponse.json({ error: reviewsResult.error.message, build_tag: BUDDIES_BUILD_TAG }, { status: 400 });

    const reviews = reviewsResult.data ?? [];
    const average = reviews.length ? Number((reviews.reduce((sum: number, item: any) => sum + Number(item.rating || 0), 0) / reviews.length).toFixed(1)) : null;
    return NextResponse.json({
      service,
      provider_profile: profileResult.data ?? null,
      provider_trust: {
        professional_buddy: Boolean((profileResult.data as any)?.is_professional_buddy),
        real_name_verified: Boolean((approvedIdentityResult.data ?? [])[0]?.id),
      },
      slots: slotsResult.data ?? [],
      reviews,
      review_summary: { count: reviews.length, average_rating: average },
      viewer: gate.viewer ? { user_id: gate.viewer.userId, email: gate.viewer.email } : null,
      build_tag: BUDDIES_BUILD_TAG,
    });
  } catch (error: any) {
    return NextResponse.json({ error: error?.message || "讀取服務詳情失敗。", build_tag: BUDDIES_BUILD_TAG }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { BUDDIES_BUILD_TAG, type BuddyServiceRow } from "@/lib/buddies";

export const runtime = "nodejs";

type RouteContext = { params: Promise<{ serviceId: string }> };
type SlotPayload = { starts_at?: string; hours?: number; note?: string | null; slot_id?: string };

export async function GET(_req: Request, context: RouteContext) {
  try {
    const { serviceId } = await context.params;
    const result = await supabaseAdmin
      .from("buddy_service_slots")
      .select("*")
      .eq("service_id", serviceId)
      .gt("starts_at", new Date().toISOString())
      .order("starts_at", { ascending: true });

    if (result.error) {
      return NextResponse.json({ error: result.error.message, build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ slots: result.data ?? [], build_tag: BUDDIES_BUILD_TAG });
  } catch (error: any) {
    return NextResponse.json({ error: error?.message || "讀取可預約時段失敗。", build_tag: BUDDIES_BUILD_TAG }, { status: 500 });
  }
}

export async function POST(req: Request, context: RouteContext) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { serviceId } = await context.params;
    const body = (await req.json()) as SlotPayload;

    const serviceResult = await supabaseAdmin.from("buddy_services").select("*").eq("id", serviceId).maybeSingle();
    const service = serviceResult.data as BuddyServiceRow | null;
    if (serviceResult.error || !service) {
      return NextResponse.json({ error: serviceResult.error?.message ?? "找不到服務。", build_tag: BUDDIES_BUILD_TAG }, { status: 404 });
    }
    if (service.provider_user_id !== userId) {
      return NextResponse.json({ error: "你沒有權限管理這個服務的時段。", build_tag: BUDDIES_BUILD_TAG }, { status: 403 });
    }

    const startsAt = new Date((body.starts_at ?? "").trim());
    const hours = Number(body.hours ?? 1);
    const note = (body.note ?? "").trim().slice(0, 200) || null;

    if (Number.isNaN(startsAt.getTime()) || startsAt.getTime() <= Date.now()) {
      return NextResponse.json({ error: "時段開始時間必須晚於現在。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }
    if (!Number.isInteger(hours) || hours < 1 || hours > 4) {
      return NextResponse.json({ error: "每個可預約時段只支援 1～4 小時。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }

    const endsAt = new Date(startsAt.getTime() + hours * 60 * 60 * 1000).toISOString();
    const insertResult = await supabaseAdmin
      .from("buddy_service_slots")
      .insert({
        service_id: serviceId,
        provider_user_id: userId,
        starts_at: startsAt.toISOString(),
        ends_at: endsAt,
        slot_status: "open",
        note,
      })
      .select("*")
      .single();

    if (insertResult.error || !insertResult.data) {
      return NextResponse.json({ error: insertResult.error?.message ?? "建立可預約時段失敗。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ slot: insertResult.data, build_tag: BUDDIES_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再管理可預約時段。", build_tag: BUDDIES_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "Unexpected server error", build_tag: BUDDIES_BUILD_TAG }, { status: 500 });
  }
}

export async function DELETE(req: Request, context: RouteContext) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { serviceId } = await context.params;
    const url = new URL(req.url);
    const slotId = (url.searchParams.get("slotId") ?? "").trim();

    if (!slotId) {
      return NextResponse.json({ error: "缺少 slotId。", build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }

    const result = await supabaseAdmin
      .from("buddy_service_slots")
      .delete()
      .eq("id", slotId)
      .eq("service_id", serviceId)
      .eq("provider_user_id", userId)
      .eq("slot_status", "open");

    if (result.error) {
      return NextResponse.json({ error: result.error.message, build_tag: BUDDIES_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ ok: true, build_tag: BUDDIES_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再刪除可預約時段。", build_tag: BUDDIES_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "刪除可預約時段失敗。", build_tag: BUDDIES_BUILD_TAG }, { status: 500 });
  }
}

