      privacy: "private",
      properties: {
        max_participants: 6,
        enable_screenshare: true,
        enable_knocking: false,
        enable_video_processing_ui: true,

        // 關鍵：加入時不要自動打開麥克風（避免 No Mic / 已拔除麥克風 造成 NotFoundError）
        start_audio_off: true,
      },
    };

    const resp = await fetch(`${apiBase}/rooms`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${apiKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(payload),
    });

    const json = await resp.json().catch(() => ({}));

    // Idempotency: if the room already exists, Daily returns 409.
    // For our UI we treat this as "ok" and just return the existing room.
    if (resp.status === 409) {
      const getResp = await fetch(`${apiBase}/rooms/${encodeURIComponent(roomName)}`, {
        method: "GET",
        headers: {
          Authorization: `Bearer ${apiKey}`,
          "Content-Type": "application/json",
        },
      });

      const existing = await getResp.json().catch(() => ({}));
      const existingUrl = existing?.url;

      if (getResp.ok && existingUrl) {
        return NextResponse.json({ url: existingUrl, raw: existing, existed: true });
      }

      // Fallback: keep the original 409 error details if we cannot fetch the room.
      return NextResponse.json(
        {
          error:
            json?.info ||
            json?.error ||
            existing?.info ||
            existing?.error ||
            "Daily room already exists, but failed to fetch it",
          raw: { create: json, get: existing },
        },
        { status: 409 }
      );
    }

    if (!resp.ok) {
      return NextResponse.json(
        { error: json?.info || json?.error || "Daily create-room failed", raw: json },
        { status: resp.status }
      );
    }

    const url = json?.url;
    if (!url) {
      return NextResponse.json(
        { error: "Daily created room but missing url", raw: json },
        { status: 500 }
      );
    }

    return NextResponse.json({ url, raw: json });
  } catch (e: any) {
    return NextResponse.json(
      { error: e?.message || "Unexpected server error" },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { ROOM_INFRA_BUILD_TAG } from "@/lib/server/roomInfra";

export const runtime = "nodejs";

export async function GET() {
  const dailyKey = process.env.DAILY_API_KEY;
  const dailyApiBase = process.env.DAILY_API_BASE || "https://api.daily.co/v1";

  if (!dailyKey) {
    return NextResponse.json(
      {
        ok: false,
        configured: false,
        error: "Missing DAILY_API_KEY",
        build_tag: ROOM_INFRA_BUILD_TAG,
      },
      { status: 500 }
    );
  }

  const startedAt = Date.now();

  try {
    const response = await fetch(`${dailyApiBase}/rooms?limit=1`, {
      method: "GET",
      headers: { Authorization: `Bearer ${dailyKey}` },
      cache: "no-store",
    });

    const latencyMs = Date.now() - startedAt;
    const payload = await response.json().catch(() => ({}));

    if (!response.ok) {
      return NextResponse.json(
        {
          ok: false,
          configured: true,
          daily_api_base: dailyApiBase,
          status: response.status,
          latency_ms: latencyMs,
          error: payload?.info || payload?.error || "Daily health check failed",
          build_tag: ROOM_INFRA_BUILD_TAG,
        },
        { status: response.status }
      );
    }

    return NextResponse.json({
      ok: true,
      configured: true,
      daily_api_base: dailyApiBase,
      status: response.status,
      latency_ms: latencyMs,
      sample_count: Array.isArray(payload?.data) ? payload.data.length : null,
      build_tag: ROOM_INFRA_BUILD_TAG,
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        ok: false,
        configured: true,
        daily_api_base: dailyApiBase,
        error: error?.message || "Daily health check exception",
        build_tag: ROOM_INFRA_BUILD_TAG,
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import {
  ROOM_INFRA_BUILD_TAG,
  buildBillingSessionKey,
  creditCostByDuration,
  getMonthStartTaipeiISO,
  getVipStatus,
  isRoomEndedOrExpired,
  parseDailyRoomNameFromUrl,
} from "@/lib/server/roomInfra";
import {
  identityAccessErrorResponse,
  requirePhoneVerifiedFromAccessToken,
} from "@/lib/server/identityAccess";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const ROOM_TOKEN_BUILD_TAG =
  "daily-meeting-token-p0-safe-media-v128-2026-07-18";
const FREE_MONTHLY_CREDITS = 4;
const ACCESS_SESSION_PENDING_RETRY_MS = 90_000;

type RequestBody = { roomId?: string };

type AccessSessionInput = {
  roomId: string;
  userId: string;
  dailyRoomName: string;
  billingSessionKey: string;
  durationMinutes: number;
  costCredits: number;
  entitlementSource: string;
  allowedByPairVipCarry: boolean;
};

function extractBearer(req: Request): string | null {
  const header =
    req.headers.get("authorization") || req.headers.get("Authorization");
  if (!header) return null;
  const match = header.match(/^Bearer\s+(.+)$/i);
  return match ? match[1].trim() : null;
}

async function getSupabaseUser(userJwt: string) {
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const supabaseAnon = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
  if (!supabaseUrl || !supabaseAnon) {
    throw new Error(
      "Missing Supabase env (NEXT_PUBLIC_SUPABASE_URL / NEXT_PUBLIC_SUPABASE_ANON_KEY)",
    );
  }

  const authResponse = await fetch(`${supabaseUrl}/auth/v1/user`, {
    headers: {
      apikey: supabaseAnon,
      Authorization: `Bearer ${userJwt}`,
    },
  });

  if (!authResponse.ok) {
    const raw = await authResponse.text().catch(() => "");
    const error = new Error("Invalid Supabase session token") as Error & {
      raw?: string;
      status?: number;
    };
    error.raw = raw;
    error.status = 401;
    throw error;
  }

  return (await authResponse.json().catch(() => null)) as any;
}

async function getRoomAccessSession(input: AccessSessionInput) {
  const nowIso = new Date().toISOString();
  const insertResult = await supabaseAdmin
    .from("room_access_sessions")
    .insert({
      room_id: input.roomId,
      user_id: input.userId,
      daily_room_name: input.dailyRoomName,
      billing_session_key: input.billingSessionKey,
      duration_minutes: input.durationMinutes,
      cost_credits: input.costCredits,
      charge_status: "pending",
      entitlement_source: input.entitlementSource,
      allowed_by_pair_vip_carry: input.allowedByPairVipCarry,
      status: "active",
      provider_payload: {},
      created_at: nowIso,
      updated_at: nowIso,
    })
    .select("*")
    .single();

  if (!insertResult.error && insertResult.data) {
    return { session: insertResult.data as any, created: true };
  }

  const duplicate =
    insertResult.error?.code === "23505" ||
    /duplicate key|unique/i.test(insertResult.error?.message ?? "");
  if (!duplicate) {
    throw new Error(
      insertResult.error?.message || "建立 room access session 失敗。",
    );
  }

  const existingResult = await supabaseAdmin
    .from("room_access_sessions")
    .select("*")
    .eq("room_id", input.roomId)
    .eq("user_id", input.userId)
    .eq("billing_session_key", input.billingSessionKey)
    .maybeSingle();
  if (existingResult.error || !existingResult.data) {
    throw new Error(
      existingResult.error?.message || "讀取既有 room access session 失敗。",
    );
  }

  return { session: existingResult.data as any, created: false };
}

async function markAccessSession(
  id: string,
  patch: Record<string, unknown>,
) {
  const { data, error } = await supabaseAdmin
    .from("room_access_sessions")
    .update({ ...patch, updated_at: new Date().toISOString() })
    .eq("id", id)
    .select("*")
    .single();
  if (error) throw new Error(error.message);
  return data as any;
}

export async function POST(req: Request) {
  try {
    const body = (await req.json()) as RequestBody;
    const roomId = String(body?.roomId || "").trim();
    if (!roomId) {
      return NextResponse.json(
        { error: "Missing roomId", build_tag: ROOM_TOKEN_BUILD_TAG },
        { status: 400 },
      );
    }

    const dailyKey = process.env.DAILY_API_KEY;
    const dailyApiBase =
      process.env.DAILY_API_BASE || "https://api.daily.co/v1";
    if (!dailyKey) {
      return NextResponse.json(
        { error: "Missing DAILY_API_KEY", build_tag: ROOM_TOKEN_BUILD_TAG },
        { status: 500 },
      );
    }

    const userJwt = extractBearer(req);
    if (!userJwt) {
      return NextResponse.json(
        {
          error: "Missing Authorization Bearer <supabase_access_token>",
          build_tag: ROOM_TOKEN_BUILD_TAG,
        },
        { status: 401 },
      );
    }

    const user = await getSupabaseUser(userJwt);
    const userId: string | undefined = user?.id;
    const email: string | undefined = user?.email;
    if (!userId) {
      return NextResponse.json(
        { error: "Supabase user missing id", build_tag: ROOM_TOKEN_BUILD_TAG },
        { status: 401 },
      );
    }

    await requirePhoneVerifiedFromAccessToken(userJwt);

    const { data: room, error: roomError } = await supabaseAdmin
      .from("rooms")
      .select(
        "id,created_by,created_at,duration_minutes,mode,max_size,daily_room_url,status,scheduled_end_at,ended_at",
      )
      .eq("id", roomId)
      .single();
    if (roomError || !room) {
      return NextResponse.json(
        {
          error: roomError?.message || "Room not found",
          build_tag: ROOM_TOKEN_BUILD_TAG,
        },
        { status: 404 },
      );
    }
    if (isRoomEndedOrExpired(room as any, 3)) {
      return NextResponse.json(
        {
          error: "Room has ended",
          code: "ROOM_ENDED",
          build_tag: ROOM_TOKEN_BUILD_TAG,
        },
        { status: 410 },
      );
    }
    if (!room.daily_room_url) {
      return NextResponse.json(
        {
          error: "Daily room not created yet",
          build_tag: ROOM_TOKEN_BUILD_TAG,
        },
        { status: 409 },
      );
    }

    const isOwner = room.created_by === userId;
    const memberResult = await supabaseAdmin
      .from("room_members")
      .select("room_id,user_id")
      .eq("room_id", roomId)
      .eq("user_id", userId)
      .maybeSingle();
    if (memberResult.error) {
      return NextResponse.json(
        { error: memberResult.error.message, build_tag: ROOM_TOKEN_BUILD_TAG },
        { status: 500 },
      );
    }
    if (!memberResult.data && !isOwner) {
      return NextResponse.json(
        { error: "Not a room member", build_tag: ROOM_TOKEN_BUILD_TAG },
        { status: 403 },
      );
    }

    const durationMinutes = Number(room.duration_minutes || 25);
    const costCredits = creditCostByDuration(durationMinutes);
    const selfEntitlement = await getVipStatus(userId);
    const selfIsVip = selfEntitlement.isVip;

    let allowedByPairVipCarry = false;
    if (!selfIsVip && room.mode === "pair") {
      const membersResult = await supabaseAdmin
        .from("room_members")
        .select("user_id")
        .eq("room_id", roomId);
      if (!membersResult.error && Array.isArray(membersResult.data)) {
        for (const member of membersResult.data) {
          const otherUserId = String((member as any).user_id || "");
          if (!otherUserId || otherUserId === userId) continue;
          const otherEntitlement = await getVipStatus(otherUserId);
          if (otherEntitlement.isVip) {
            allowedByPairVipCarry = true;
            break;
          }
        }
      }
    }

    const entitlementSource = selfIsVip
      ? "vip"
      : allowedByPairVipCarry
        ? "pair_vip_carry"
        : "free_credits";
    const dailyRoomName = parseDailyRoomNameFromUrl(room.daily_room_url);
    if (!dailyRoomName) {
      return NextResponse.json(
        { error: "Invalid Daily room URL", build_tag: ROOM_TOKEN_BUILD_TAG },
        { status: 500 },
      );
    }

    const billingSessionKey = buildBillingSessionKey(room as any);
    let {
      session: accessSession,
      created: createdAccessSession,
    } = await getRoomAccessSession({
      roomId,
      userId,
      dailyRoomName,
      billingSessionKey,
      durationMinutes,
      costCredits,
      entitlementSource,
      allowedByPairVipCarry,
    });

    const pendingAgeMs =
      Date.now() -
      new Date(accessSession.updated_at || accessSession.created_at).getTime();
    const stalePending =
      accessSession.charge_status === "pending" &&
      pendingAgeMs > ACCESS_SESSION_PENDING_RETRY_MS;
    if (
      !createdAccessSession &&
      accessSession.charge_status === "pending" &&
      !stalePending
    ) {
      return NextResponse.json(
        {
          error:
            "Room access session is still being prepared. Please retry shortly.",
          code: "ACCESS_SESSION_PENDING_RETRY",
          access_session_id: accessSession.id,
          build_tag: ROOM_TOKEN_BUILD_TAG,
        },
        { status: 409 },
      );
    }

    let remainingCredits: number | null = null;
    let chargedThisCall = false;
    if (createdAccessSession || stalePending) {
      try {
        if (!selfIsVip && !allowedByPairVipCarry) {
          const monthStart = getMonthStartTaipeiISO(new Date());
          const { data: remaining, error: rpcError } = await supabaseAdmin.rpc(
            "cowork_try_consume_credits",
            {
              p_user_id: userId,
              p_month_start: monthStart,
              p_cost: costCredits,
              p_allowance: FREE_MONTHLY_CREDITS,
            },
          );
          if (rpcError) {
            throw new Error(`Credit RPC error: ${rpcError.message}`);
          }

          const numericRemaining = Number(remaining);
          if (!Number.isFinite(numericRemaining) || numericRemaining < 0) {
            await markAccessSession(accessSession.id, {
              charge_status: "failed",
              status: "credit_failed",
              last_error: "Free monthly credits exhausted",
            });
            return NextResponse.json(
              {
                error: "Free monthly credits exhausted",
                code: "CREDITS_EXHAUSTED",
                allowance: FREE_MONTHLY_CREDITS,
                cost: costCredits,
                access_session_id: accessSession.id,
                build_tag: ROOM_TOKEN_BUILD_TAG,
              },
              { status: 402 },
            );
          }

          remainingCredits = numericRemaining;
          chargedThisCall = true;
          accessSession = await markAccessSession(accessSession.id, {
            charge_status: "charged",
            charged_at: new Date().toISOString(),
            entitlement_source: entitlementSource,
            allowed_by_pair_vip_carry: false,
            cost_credits: costCredits,
            status: "active",
            last_error: null,
          });
        } else {
          accessSession = await markAccessSession(accessSession.id, {
            charge_status: "waived",
            charged_at: new Date().toISOString(),
            entitlement_source: entitlementSource,
            allowed_by_pair_vip_carry: allowedByPairVipCarry,
            cost_credits: 0,
            status: "active",
            last_error: null,
          });
        }
      } catch (error) {
        await markAccessSession(accessSession.id, {
          charge_status: "failed",
          status: "credit_failed",
          last_error:
            error instanceof Error ? error.message : "Credit consume failed",
        }).catch(() => null);
        throw error;
      }
    }

    const now = Math.floor(Date.now() / 1000);
    const durationSeconds = Math.max(15 * 60, durationMinutes * 60 + 90);
    const expiresAt = now + durationSeconds;
    const userName =
      (email && email.split("@")[0]) || `u_${userId.slice(0, 8)}`;

    const dailyResponse = await fetch(`${dailyApiBase}/meeting-tokens`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${dailyKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        properties: {
          room_name: dailyRoomName,
          exp: expiresAt,
          eject_at_token_exp: true,
          user_name: userName,
          is_owner: Boolean(isOwner),
          enable_screenshare: true,
          // P0 safety invariant: no participant sends camera or microphone
          // before selecting/confirming a Presence Mode in the custom UI.
          start_video_off: true,
          start_audio_off: true,
        },
      }),
    });
    const dailyJson = await dailyResponse.json().catch(() => ({}));

    if (!dailyResponse.ok) {
      await markAccessSession(accessSession.id, {
        status: "token_failed",
        last_error:
          dailyJson?.info || dailyJson?.error || "Daily create token failed",
        provider_payload: { daily_error: dailyJson },
      }).catch(() => null);
      return NextResponse.json(
        {
          error:
            dailyJson?.info || dailyJson?.error || "Daily create token failed",
          raw: dailyJson,
          access_session_id: accessSession.id,
          build_tag: ROOM_TOKEN_BUILD_TAG,
        },
        { status: dailyResponse.status },
      );
    }

    const token = dailyJson?.token;
    if (!token) {
      await markAccessSession(accessSession.id, {
        status: "token_failed",
        last_error: "Daily token missing in response",
        provider_payload: { daily_response: dailyJson },
      }).catch(() => null);
      return NextResponse.json(
        {
          error: "Daily token missing in response",
          raw: dailyJson,
          build_tag: ROOM_TOKEN_BUILD_TAG,
        },
        { status: 500 },
      );
    }

    accessSession = await markAccessSession(accessSession.id, {
      last_token_issued_at: new Date().toISOString(),
      token_exp: new Date(expiresAt * 1000).toISOString(),
      status: "active",
      provider_payload: {
        room_name: dailyRoomName,
        token_exp: expiresAt,
        start_video_off: true,
        start_audio_off: true,
        token_refreshed_without_recharge:
          !createdAccessSession && !stalePending,
        build_tag: ROOM_TOKEN_BUILD_TAG,
      },
      last_error: null,
    });

    return NextResponse.json({
      token,
      exp: expiresAt,
      room_name: dailyRoomName,
      is_owner: Boolean(isOwner),
      duration_minutes: durationMinutes,
      cost_credits: Number(accessSession.cost_credits ?? costCredits),
      free_monthly_allowance: FREE_MONTHLY_CREDITS,
      remaining_credits: remainingCredits,
      is_vip: selfIsVip,
      allowed_by_pair_vip_carry: allowedByPairVipCarry,
      plan: selfEntitlement.plan,
      vip_until: selfEntitlement.vipUntil,
      access_session_id: accessSession.id,
      charge_status: accessSession.charge_status,
      entitlement_source: accessSession.entitlement_source,
      charged_this_call: chargedThisCall,
      token_refreshed_without_recharge:
        !createdAccessSession && !stalePending,
      billing_session_key: billingSessionKey,
      media_defaults: {
        start_video_off: true,
        start_audio_off: true,
      },
      build_tag: ROOM_TOKEN_BUILD_TAG,
      room_infra_build_tag: ROOM_INFRA_BUILD_TAG,
    });
  } catch (error: any) {
    const mapped = identityAccessErrorResponse(error, ROOM_TOKEN_BUILD_TAG);
    if (mapped) return mapped;

    const status = Number(error?.status || 500);
    return NextResponse.json(
      {
        error: error?.message || "Unexpected server error",
        raw: error?.raw,
        build_tag: ROOM_TOKEN_BUILD_TAG,
      },
      { status: status >= 400 && status < 600 ? status : 500 },
    );
  }
}

import { NextResponse } from "next/server";
import { BILLING_AUTOMATION_BUILD_TAG, processInvoiceTasks, processRefundTasks, processSubscriptionTasks, verifyBillingAutomationSecret } from "@/lib/server/billingAutomation";
export const runtime = "nodejs";
export async function POST(req: Request) { try { verifyBillingAutomationSecret(req); const [invoices, refunds, subscriptions] = await Promise.all([processInvoiceTasks(20), processRefundTasks(20), processSubscriptionTasks(20)]); return NextResponse.json({ ok: true, invoices, refunds, subscriptions, build_tag: BILLING_AUTOMATION_BUILD_TAG }); } catch (error: any) { const status = error?.status || (/UNAUTHORIZED/.test(error?.message || "") ? 401 : 500); return NextResponse.json({ error: error?.message || "billing automation failed", build_tag: BILLING_AUTOMATION_BUILD_TAG }, { status }); } }
export async function GET(req: Request) { return POST(req); }

import { NextResponse } from "next/server";
import {
  BILLING_AUTOMATION_BUILD_TAG,
  getBillingReconciliationReport,
  processInvoiceTasks,
  processRefundTasks,
  processSubscriptionTasks,
} from "@/lib/server/billingAutomation";
import { supabaseAdmin } from "@/lib/supabaseAdmin";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";
export const maxDuration = 60;

const FORMAL_BILLING_CRON_BUILD_TAG = "billing-formal-cron-v124-2026-07-04";
const JOB_NAME = "billing_automation";
const LOCK_SECONDS = 14 * 60;

type TriggerInfo = {
  trigger_source: "vercel_cron" | "manual_http";
  schedule: string | null;
  user_agent: string;
};

function firstString(...values: Array<string | null | undefined>) {
  for (const value of values) {
    const text = String(value || "").trim();
    if (text) return text;
  }
  return "";
}

function uniqueSecrets() {
  return Array.from(
    new Set(
      [process.env.CRON_SECRET, process.env.BILLING_AUTOMATION_SECRET, process.env.ROOM_CLEANUP_SECRET]
        .map((value) => String(value || "").trim())
        .filter(Boolean)
    )
  );
}

function assertAuthorized(req: Request): TriggerInfo {
  const secrets = uniqueSecrets();
  if (secrets.length === 0) {
    throw Object.assign(new Error("Missing CRON_SECRET / BILLING_AUTOMATION_SECRET / ROOM_CLEANUP_SECRET"), { status: 500 });
  }

  const auth = req.headers.get("authorization") || req.headers.get("Authorization") || "";
  const bearer = auth.match(/^Bearer\s+(.+)$/i)?.[1]?.trim() || "";
  const url = new URL(req.url);
  const got = firstString(req.headers.get("x-cron-secret"), req.headers.get("x-internal-secret"), bearer, url.searchParams.get("secret"));

  if (!got || !secrets.includes(got)) {
    throw Object.assign(new Error("UNAUTHORIZED_BILLING_FORMAL_CRON"), { status: 401 });
  }

  const userAgent = req.headers.get("user-agent") || "";
  const schedule = req.headers.get("x-vercel-cron-schedule");
  const triggerSource = userAgent.includes("vercel-cron") || !!schedule ? "vercel_cron" : "manual_http";
  return { trigger_source: triggerSource, schedule, user_agent: userAgent };
}

async function updateRun(runId: string, patch: Record<string, unknown>) {
  const result = await supabaseAdmin
    .from("billing_automation_runs")
    .update({ ...patch, updated_at: new Date().toISOString() })
    .eq("id", runId);
  if (result.error) throw result.error;
}

async function releaseLock(runId: string) {
  const released = await supabaseAdmin.rpc("billing_release_job_lock", {
    p_job_name: JOB_NAME,
    p_locked_by: runId,
  });
  if (released.error) {
    console.warn("[BILLING_FORMAL_CRON_LOCK_RELEASE_FAILED]", released.error.message);
  }
}

async function runFormalBillingAutomation(req: Request) {
  const startedAt = Date.now();
  const trigger = assertAuthorized(req);
  const runId = crypto.randomUUID();

  const insertedRun = await supabaseAdmin.from("billing_automation_runs").insert({
    id: runId,
    job_name: JOB_NAME,
    status: "running",
    trigger_source: trigger.trigger_source,
    schedule: trigger.schedule,
    user_agent: trigger.user_agent,
    build_tag: FORMAL_BILLING_CRON_BUILD_TAG,
    automation_build_tag: BILLING_AUTOMATION_BUILD_TAG,
    started_at: new Date(startedAt).toISOString(),
  });
  if (insertedRun.error) throw insertedRun.error;

  const lock = await supabaseAdmin.rpc("billing_try_acquire_job_lock", {
    p_job_name: JOB_NAME,
    p_lock_seconds: LOCK_SECONDS,
    p_locked_by: runId,
  });
  if (lock.error) throw lock.error;

  if (lock.data !== true) {
    const skipped = {
      ok: true,
      skipped: true,
      reason: "billing_automation_already_running",
      run_id: runId,
      build_tag: FORMAL_BILLING_CRON_BUILD_TAG,
      automation_build_tag: BILLING_AUTOMATION_BUILD_TAG,
    };
    await updateRun(runId, {
      status: "skipped_locked",
      finished_at: new Date().toISOString(),
      duration_ms: Date.now() - startedAt,
      result: skipped,
    });
    return skipped;
  }

  try {
    console.info("[BILLING_FORMAL_CRON_START]", {
      run_id: runId,
      trigger_source: trigger.trigger_source,
      schedule: trigger.schedule,
      build_tag: FORMAL_BILLING_CRON_BUILD_TAG,
      automation_build_tag: BILLING_AUTOMATION_BUILD_TAG,
    });

    const invoicesBeforeRefunds = await processInvoiceTasks(20);
    const refunds = await processRefundTasks(20);
    const invoicesAfterRefunds = await processInvoiceTasks(20);
    const subscriptions = await processSubscriptionTasks(20);
    const reconciliation = await getBillingReconciliationReport(100);

    const result = {
      ok: true,
      run_id: runId,
      invoices_before_refunds: invoicesBeforeRefunds,
      refunds,
      invoices_after_refunds: invoicesAfterRefunds,
      subscriptions,
      reconciliation_summary: reconciliation?.summary ?? null,
      build_tag: FORMAL_BILLING_CRON_BUILD_TAG,
      automation_build_tag: BILLING_AUTOMATION_BUILD_TAG,
    };

    await updateRun(runId, {
      status: "completed",
      finished_at: new Date().toISOString(),
      duration_ms: Date.now() - startedAt,
      result,
    });

    console.info("[BILLING_FORMAL_CRON_DONE]", {
      run_id: runId,
      duration_ms: Date.now() - startedAt,
      reconciliation_summary: reconciliation?.summary ?? null,
    });

    return result;
  } catch (error: any) {
    const message = error?.message || "billing_formal_cron_failed";
    await updateRun(runId, {
      status: "failed",
      finished_at: new Date().toISOString(),
      duration_ms: Date.now() - startedAt,
      error: message,
    });
    console.error("[BILLING_FORMAL_CRON_FAILED]", { run_id: runId, error: message });
    throw error;
  } finally {
    await releaseLock(runId);
  }
}

