      amount_twd: 0,
      currency: "TWD",
      payment_order_id: order.id,
      description: `方案權益開通：${order.plan_code}`,
      occurred_at: input.paidAtIso || new Date().toISOString(),
      metadata: { plan_code: order.plan_code, vip_days: order.vip_days, valid_until: validUntil, build_tag: NOTIFY_BUILD_TAG },
    },
  });

  await insertIfMissing({
    table: "entitlement_events",
    filters: { payment_order_id: order.id, event_type: "grant" },
    row: {
      user_id: order.user_id,
      event_type: "grant",
      plan_code: order.plan_code,
      entitlement_key: "vip",
      quantity: 1,
      valid_from: input.paidAtIso || new Date().toISOString(),
      valid_until: validUntil,
      payment_order_id: order.id,
      metadata: { merchant_trade_no: order.merchant_trade_no, provider_trade_no: input.providerTradeNo, build_tag: NOTIFY_BUILD_TAG },
    },
  });

  await insertIfMissing({
    table: "invoice_events",
    filters: { payment_order_id: order.id, event_type: "requested" },
    row: {
      user_id: order.user_id,
      payment_order_id: order.id,
      provider: "ecpay_invoice",
      event_type: "requested",
      metadata: {
        merchant_trade_no: order.merchant_trade_no,
        item_name: order.item_name,
        amount: order.amount,
        invoice_preference: invoicePreference,
        note: "付款已成立，待電子發票流程開立或同步。",
        build_tag: NOTIFY_BUILD_TAG,
      },
    },
  });

  await recordPaymentEvent({
    merchant_trade_no: order.merchant_trade_no,
    event_type: "commercial_accounting_recorded",
    raw_payload: { order_id: order.id, user_id: order.user_id, provider_trade_no: input.providerTradeNo, valid_until: validUntil, invoice_preference: invoicePreference, query_trade_info: input.queryResult, build_tag: NOTIFY_BUILD_TAG },
  });
}

export async function POST(req: Request) {
  const rawBody = await req.text();
  const payload = parseFormEncodedPayload(rawBody);
  const merchantTradeNo = payload.MerchantTradeNo || "UNKNOWN";
  const simulatePaid = String(payload.SimulatePaid || "0") === "1";

  console.info("[ECPAY_NOTIFY_HIT]", { merchantTradeNo, rtnCode: payload.RtnCode || "", simulatePaid });
  await recordPaymentEvent({ merchant_trade_no: merchantTradeNo, event_type: "return_url_raw", raw_payload: payload });

  try {
    const config = getEcpayConfig();
    if (!payload.MerchantTradeNo) return textResponse("0|MISSING_MERCHANT_TRADE_NO", 400);

    if (config.stage && simulatePaid) {
      const { data: existingOrder, error: existingOrderError } = await supabaseAdmin
        .from("payment_orders")
        .select("merchant_trade_no,status")
        .eq("merchant_trade_no", payload.MerchantTradeNo)
        .maybeSingle();
      const localOrderExists = !!existingOrder && !existingOrderError;
      await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: localOrderExists ? "return_url_simulate_paid_ack_with_local_order" : "return_url_simulate_paid_ack_without_local_order", raw_payload: { payload, localOrderExists, localOrderError: existingOrderError?.message || null } });
      return textResponse("1|OK");
    }

    if (payload.MerchantID !== config.merchantId) {
      await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: "return_url_invalid_merchant", raw_payload: payload });
      return textResponse("0|INVALID_MERCHANT", 400);
    }

    const expectedCheckMacValue = buildExpectedCheckMacValue(payload, config.hashKey, config.hashIV);
    if (!verifyCheckMacValue(payload, config.hashKey, config.hashIV)) {
      await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: "return_url_invalid_checkmac", raw_payload: { payload, providedCheckMacValue: payload.CheckMacValue || null, expectedCheckMacValue } });
      return textResponse("0|INVALID_CHECKMAC", 400);
    }

    const { data: order, error: orderError } = await supabaseAdmin
      .from("payment_orders")
      .select("id,user_id,merchant_trade_no,amount,currency,status,plan_code,item_name,trade_desc,vip_days,provider_payload")
      .eq("merchant_trade_no", payload.MerchantTradeNo)
      .maybeSingle();

    if (orderError || !order) {
      await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: "return_url_order_not_found", raw_payload: { payload, orderError: orderError?.message || null } });
      return textResponse("0|ORDER_NOT_FOUND", 404);
    }

    const queryResult = await queryEcpayTradeInfo(payload.MerchantTradeNo, config);
    await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: "query_trade_info_after_return", raw_payload: queryResult });

    const tradeStatus = String(queryResult.TradeStatus || "");
    const tradeAmt = Number(queryResult.TradeAmt || 0);
    const paidAtIso = parsePaidAt(queryResult.PaymentDate || payload.PaymentDate);
    const providerTradeNo = String(queryResult.TradeNo || payload.TradeNo || "");

    if (tradeStatus === "1" && tradeAmt === Number(order.amount)) {
      const { error: rpcError } = await supabaseAdmin.rpc("ecpay_mark_order_paid", {
        p_merchant_trade_no: payload.MerchantTradeNo,
        p_provider_trade_no: providerTradeNo || null,
        p_paid_at: paidAtIso,
        p_provider_payload: { ...order.provider_payload, return_url_payload: payload, query_trade_info: queryResult, build_tag: NOTIFY_BUILD_TAG },
      });
      if (rpcError) {
        await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: "mark_paid_rpc_error", raw_payload: { message: rpcError.message } });
        return textResponse("0|RPC_ERROR", 500);
      }
      await recordCommercialAccounting({ order, paidAtIso, providerTradeNo: providerTradeNo || null, queryResult });
      await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: "return_url_marked_paid", raw_payload: { providerTradeNo, tradeStatus, tradeAmt, paidAtIso, build_tag: NOTIFY_BUILD_TAG } });
    } else {
      const rtnCode = String(payload.RtnCode || "");
      const isDefiniteFailure = rtnCode !== "" && rtnCode !== "1";
      const isQueryFailure = tradeStatus === "10200095";
      if (isDefiniteFailure || isQueryFailure) {
        await updatePendingOrderAsFailed({ merchantTradeNo: payload.MerchantTradeNo, lastError: `RtnCode=${rtnCode}; TradeStatus=${tradeStatus || ""}; RtnMsg=${payload.RtnMsg || ""}`, providerPayload: { ...order.provider_payload, return_url_payload: payload, query_trade_info: queryResult, build_tag: NOTIFY_BUILD_TAG } });
        await recordPaymentEvent({ merchant_trade_no: payload.MerchantTradeNo, event_type: "return_url_marked_failed", raw_payload: { rtnCode, tradeStatus, rtnMsg: payload.RtnMsg || "", query_trade_info: queryResult } });
      }
    }

    return textResponse("1|OK");
  } catch (error: any) {
    await recordPaymentEvent({ merchant_trade_no: merchantTradeNo, event_type: "return_url_handler_exception", raw_payload: { message: error?.message || "unknown", build_tag: NOTIFY_BUILD_TAG } });
    return textResponse("0|SERVER_ERROR", 500);
  }
}

import { NextRequest, NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getEcpayConfig, queryEcpayTradeInfo } from "@/lib/ecpay";

export const runtime = "nodejs";

function extractBearer(req: Request): string | null {
  const header = req.headers.get("authorization") || req.headers.get("Authorization");
  if (!header) return null;
  const matched = header.match(/^Bearer\s+(.+)$/i);
  return matched ? matched[1].trim() : null;
}

async function getSupabaseUser(userJwt: string) {
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const supabaseAnon = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
  if (!supabaseUrl || !supabaseAnon) {
    throw new Error("Missing NEXT_PUBLIC_SUPABASE_URL or NEXT_PUBLIC_SUPABASE_ANON_KEY");
  }

  const authResp = await fetch(`${supabaseUrl}/auth/v1/user`, {
    headers: {
      apikey: supabaseAnon,
      Authorization: `Bearer ${userJwt}`,
    },
  });

  if (!authResp.ok) return null;
  return (await authResp.json().catch(() => null)) as any;
}

function parsePaidAt(paymentDate?: string): string | null {
  if (!paymentDate) return null;
  const normalized = paymentDate.replace(/\//g, "-");
  const date = new Date(normalized);
  if (Number.isNaN(date.getTime())) return null;
  return date.toISOString();
}

export async function GET(req: NextRequest) {
  try {
    const userJwt = extractBearer(req);
    if (!userJwt) {
      return NextResponse.json({ error: "缺少登入憑證。" }, { status: 401 });
    }

    const user = await getSupabaseUser(userJwt);
    const userId = user?.id as string | undefined;
    if (!userId) {
      return NextResponse.json({ error: "登入狀態已過期，請重新登入。" }, { status: 401 });
    }

    const merchantTradeNo = String(req.nextUrl.searchParams.get("merchantTradeNo") || "").trim();
    if (!merchantTradeNo) {
      return NextResponse.json({ error: "缺少訂單編號。" }, { status: 400 });
    }

    let { data: order, error: orderError } = await supabaseAdmin
      .from("payment_orders")
      .select("merchant_trade_no,plan_code,amount,status,paid_at,created_at,provider_trade_no,last_error,provider_payload")
      .eq("merchant_trade_no", merchantTradeNo)
      .eq("user_id", userId)
      .maybeSingle();

    if (orderError || !order) {
      return NextResponse.json({ error: "找不到這筆付款訂單。" }, { status: 404 });
    }

    if (order.status === "pending") {
      try {
        const config = getEcpayConfig();
        const queryResult = await queryEcpayTradeInfo(merchantTradeNo, config);
        const tradeStatus = String(queryResult.TradeStatus || "");
        const tradeAmt = Number(queryResult.TradeAmt || 0);

        if (tradeStatus === "1" && tradeAmt === Number(order.amount)) {
          const { error: rpcError } = await supabaseAdmin.rpc("ecpay_mark_order_paid", {
            p_merchant_trade_no: merchantTradeNo,
            p_provider_trade_no: String(queryResult.TradeNo || "") || null,
            p_paid_at: parsePaidAt(queryResult.PaymentDate),
            p_provider_payload: {
              order_status_poll: true,
              query_trade_info: queryResult,
            },
          });

          if (!rpcError) {
            const refreshed = await supabaseAdmin
              .from("payment_orders")
              .select("merchant_trade_no,plan_code,amount,status,paid_at,created_at,provider_trade_no,last_error,provider_payload")
              .eq("merchant_trade_no", merchantTradeNo)
              .eq("user_id", userId)
              .maybeSingle();

            if (refreshed.data) {
              order = refreshed.data;
            }
          }
        }
      } catch {
        // 查單失敗時，前端仍顯示處理中，不把結果頁打爆
      }
    }

    const { data: entitlement } = await supabaseAdmin
      .from("user_entitlements")
      .select("plan,vip_until")
      .eq("user_id", userId)
      .maybeSingle();

    const isVip =
      entitlement?.plan === "vip" &&
      (!entitlement?.vip_until || new Date(entitlement.vip_until).getTime() > Date.now());

    return NextResponse.json({
      merchantTradeNo: order.merchant_trade_no,
      status: order.status,
      planCode: order.plan_code,
      amount: order.amount,
      paidAt: order.paid_at,
      createdAt: order.created_at,
      providerTradeNo: order.provider_trade_no,
      lastError: order.last_error,
      entitlement: {
        plan: entitlement?.plan || "free",
        vip_until: entitlement?.vip_until || null,
        is_vip: Boolean(isVip),
      },
    });
  } catch (error: any) {
    return NextResponse.json(
      { error: error?.message || "查詢付款狀態時發生未預期錯誤。" },
      { status: 500 },
    );
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import {
  createCheckMacValue,
  formatTradeDate,
  generateMerchantTradeNo,
  getEcpayConfig,
  getRecurringCheckoutPaymentConfig,
} from "@/lib/ecpay";
import {
  buildDefaultInvoicePreference,
  normalizeInvoicePreference,
} from "@/lib/invoicePreferences";
import { getProductPlan } from "@/lib/productCatalog";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const RECURRING_CHECKOUT_BUILD_TAG =
  "ecpay-recurring-checkout-v128-pricing-v2-guard-2026-07-18";

type RecurringProductPlan = {
  code: string;
  billingMode: string;
  amountTwd: number | null;
  purchaseStatus?: string;
  purchaseEnabled?: boolean;
  checkoutPlanCode?: string | null;
  title?: string;
  invoiceItemName: string;
  tradeDescription: string;
};

function envFlag(name: string) {
  return ["1", "true", "yes", "enabled"].includes(
    String(process.env[name] || "").trim().toLowerCase(),
  );
}

function extractBearer(req: Request): string | null {
  const header =
    req.headers.get("authorization") || req.headers.get("Authorization");
  if (!header) return null;
  const matched = header.match(/^Bearer\s+(.+)$/i);
  return matched ? matched[1].trim() : null;
}

async function getSupabaseUser(userJwt: string) {
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const supabaseAnon = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
  if (!supabaseUrl || !supabaseAnon) throw new Error("Missing Supabase auth env");

  const authResponse = await fetch(`${supabaseUrl}/auth/v1/user`, {
    headers: { apikey: supabaseAnon, Authorization: `Bearer ${userJwt}` },
  });
  if (!authResponse.ok) return null;
  return (await authResponse.json().catch(() => null)) as any;
}

function getOrigin(req: Request) {
  const configured = String(
    process.env.SITE_URL || process.env.NEXT_PUBLIC_SITE_URL || "",
  )
    .trim()
    .replace(/\/$/, "");
  if (configured) return configured;
  const protocol = req.headers.get("x-forwarded-proto");
  const host = req.headers.get("x-forwarded-host");
  if (protocol && host) return `${protocol}://${host}`;
  return new URL(req.url).origin;
}

function recurringAllowlist() {
  return String(process.env.ECPAY_RECURRING_PLAN_ALLOWLIST || "")
    .split(",")
    .map((item) => item.trim())
    .filter(Boolean);
}

function canUseRecurringPlan(plan: RecurringProductPlan) {
  return (
    envFlag("ECPAY_RECURRING_ENABLED") &&
    envFlag("PRICING_V2_COMMERCIAL_ENABLED") &&
    plan.purchaseStatus === "active" &&
    plan.purchaseEnabled === true &&
    Boolean(plan.checkoutPlanCode) &&
    recurringAllowlist().includes(plan.code)
  );
}

async function resolveInvoicePreference(
  input: unknown,
  userId: string,
  email: string,
) {
  if (input !== undefined && input !== null) {
    return normalizeInvoicePreference(input, email);
  }

  const saved = await supabaseAdmin
    .from("user_invoice_preferences")
    .select("preference")
    .eq("user_id", userId)
    .maybeSingle();
  if (saved.error) throw saved.error;
  if (saved.data?.preference) {
    return normalizeInvoicePreference(saved.data.preference, email);
  }
  return buildDefaultInvoicePreference(email);
}

export async function POST(req: Request) {
  try {
    if (!envFlag("ECPAY_RECURRING_ENABLED")) {
      return NextResponse.json(
        {
          error:
            "自動扣款尚未啟用。請先確認綠界定期定額服務、訂閱取消、退款、發票與 entitlement E2E。",
          code: "RECURRING_DISABLED",
          build_tag: RECURRING_CHECKOUT_BUILD_TAG,
        },
        { status: 400 },
      );
    }

    const userJwt = extractBearer(req);
    if (!userJwt) {
      return NextResponse.json({ error: "缺少登入憑證。" }, { status: 401 });
    }

    const user = await getSupabaseUser(userJwt);
    const userId = user?.id as string | undefined;
    if (!userId) {
      return NextResponse.json({ error: "登入狀態已過期。" }, { status: 401 });
    }

    const body = (await req.json().catch(() => ({}))) as {
      planCode?: string;
      invoicePreference?: unknown;
    };
    const planCode = String(body.planCode || "").trim();
    const plan = getProductPlan(planCode) as RecurringProductPlan | undefined;

    if (!plan || plan.billingMode !== "subscription" || plan.amountTwd === null) {
      return NextResponse.json(
        {
          error: "這不是可建立自動扣款的訂閱方案。",
          code: "INVALID_RECURRING_PLAN",
          build_tag: RECURRING_CHECKOUT_BUILD_TAG,
        },
        { status: 400 },
      );
    }

    if (!canUseRecurringPlan(plan)) {
      return NextResponse.json(
        {
          error:
            "此方案仍是 Pricing v2 最終規格，尚未開放自動扣款。不能只靠舊的 ALLOW_NEXT_SPEC 開關繞過商業 gate。",
          code: "RECURRING_PLAN_NOT_OPEN",
          diagnostic: {
            pricing_v2_commercial_enabled: envFlag(
              "PRICING_V2_COMMERCIAL_ENABLED",
            ),
            plan_purchase_status: plan.purchaseStatus || null,
            plan_purchase_enabled: plan.purchaseEnabled === true,
            plan_in_allowlist: recurringAllowlist().includes(plan.code),
          },
          build_tag: RECURRING_CHECKOUT_BUILD_TAG,
        },
        { status: 400 },
      );
    }

    const invoicePreference = await resolveInvoicePreference(
      body.invoicePreference,
      userId,
      user.email || "",
    );
    const config = getEcpayConfig();
    const paymentConfig = getRecurringCheckoutPaymentConfig();
    const origin = getOrigin(req);
    const merchantTradeNo = generateMerchantTradeNo("SUB");
    const merchantMemberId = `u${userId.replaceAll("-", "").slice(0, 19)}`;

    const profile = await supabaseAdmin
      .from("subscription_profiles")
      .insert({
        user_id: userId,
        provider: "ecpay",
        plan_code: plan.code,
        status: "pending",
        merchant_member_id: merchantMemberId,
        merchant_trade_no: merchantTradeNo,
        period_amount: plan.amountTwd,
        period_type: "M",
        frequency: 1,
        exec_times: 999,
        auto_renew: true,
        raw_payload: {
          plan,
          source: "recurring_checkout_v128",
          invoice_preference: invoicePreference,
          build_tag: RECURRING_CHECKOUT_BUILD_TAG,
        },
        invoice_preference: invoicePreference,
      })
      .select("*")
      .single();

    if (profile.error || !profile.data) {
      return NextResponse.json(
        { error: profile.error?.message || "建立訂閱 profile 失敗。" },
        { status: 400 },
      );
    }

    const returnUrl = `${origin}/api/payments/ecpay/recurring/notify`;
    const clientBackUrl = `${origin}/account/billing`;
    const ecpayFields: Record<string, string> = {
      MerchantID: config.merchantId,
      MerchantTradeNo: merchantTradeNo,
      MerchantTradeDate: formatTradeDate(new Date()),
      PaymentType: "aio",
      TotalAmount: String(plan.amountTwd),
      TradeDesc: plan.tradeDescription,
      ItemName: plan.invoiceItemName,
      ReturnURL: returnUrl,
      PeriodReturnURL: returnUrl,
      ChoosePayment: paymentConfig.choosePayment,
      EncryptType: "1",
      ClientBackURL: clientBackUrl,
      NeedExtraPaidInfo: paymentConfig.needExtraPaidInfo,
      CustomField1: plan.code,
      CustomField2: profile.data.id,
      CustomField3: invoicePreference.buyerEmail || user.email || "",
      MerchantMemberID: merchantMemberId,
      PeriodAmount: String(plan.amountTwd),
      PeriodType: "M",
      Frequency: "1",
      ExecTimes: "999",
      Remark: "SUBSCRIPTION_PROFILE_V128",
    };
    if (paymentConfig.storeId) ecpayFields.StoreID = paymentConfig.storeId;
    ecpayFields.CheckMacValue = createCheckMacValue(
      ecpayFields,
      config.hashKey,
      config.hashIV,
    );

    await supabaseAdmin.from("subscription_events").insert({
      subscription_profile_id: profile.data.id,
      user_id: userId,
      event_type: "recurring_checkout_created",
      merchant_trade_no: merchantTradeNo,
      provider_payload: {
        fields_without_checkmac: {
          ...ecpayFields,
          CheckMacValue: "[redacted]",
        },
        invoice_preference: invoicePreference,
        build_tag: RECURRING_CHECKOUT_BUILD_TAG,
      },
    });

    return NextResponse.json({
      action: config.checkoutUrl,
      method: "POST",
      merchantTradeNo,
      fields: ecpayFields,
      diagnostic: {
        build_tag: RECURRING_CHECKOUT_BUILD_TAG,
        choose_payment: paymentConfig.choosePayment,
        invoice_preference_kind: invoicePreference.kind,
      },
    });
  } catch (error) {
    return NextResponse.json(
      {
        error: error instanceof Error ? error.message : "建立自動扣款流程失敗。",
        build_tag: RECURRING_CHECKOUT_BUILD_TAG,
      },
      { status: 500 },
    );
  }
}

import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getEcpayConfig, parseFormEncodedPayload, verifyCheckMacValue } from "@/lib/ecpay";

export const runtime = "nodejs";

const RECURRING_NOTIFY_BUILD_TAG = "ecpay-recurring-notify-v119-2026-06-27";

function textResponse(body: string, status = 200) {
  return new Response(body, { status, headers: { "Content-Type": "text/plain; charset=utf-8" } });
}

function parsePaidAt(value?: string) {
  if (!value) return null;
  const date = new Date(value.replace(/\//g, "-"));
  return Number.isNaN(date.getTime()) ? null : date.toISOString();
}

function addDaysIso(baseIso: string, days: number) {
  const base = new Date(baseIso);
  return new Date(base.getTime() + days * 24 * 60 * 60 * 1000).toISOString();
}

async function recordPaymentEvent(input: { merchantTradeNo: string; eventType: string; payload: unknown }) {
  await supabaseAdmin.from("payment_events").insert({
    merchant_trade_no: input.merchantTradeNo,
    provider: "ecpay",
    event_type: input.eventType,
    raw_payload: input.payload,
  });
}

async function findExistingRecurringOrder(input: { merchantTradeNo: string; providerTradeNo: string | null }) {
  if (input.providerTradeNo) {
    const byTradeNo = await supabaseAdmin
      .from("payment_orders")
      .select("*")
      .eq("provider", "ecpay_recurring")
      .eq("provider_trade_no", input.providerTradeNo)
      .limit(1)
      .maybeSingle();
    if (byTradeNo.error) throw byTradeNo.error;
    if (byTradeNo.data) return byTradeNo.data;
  }

  const byMerchantTradeNo = await supabaseAdmin
    .from("payment_orders")
    .select("*")
    .eq("provider", "ecpay_recurring")
    .eq("merchant_trade_no", input.merchantTradeNo)
    .limit(1)
    .maybeSingle();
  if (byMerchantTradeNo.error) throw byMerchantTradeNo.error;
  return byMerchantTradeNo.data ?? null;
}

async function upsertVipEntitlement(input: { userId: string; validUntil: string }) {
  const { error } = await supabaseAdmin
    .from("user_entitlements")
    .upsert({ user_id: input.userId, plan: "vip", vip_until: input.validUntil, updated_at: new Date().toISOString() }, { onConflict: "user_id" });
  if (error) throw error;
}

async function insertLedgerIfMissing(input: { userId: string; paymentOrderId: string | null; amount: number; paidAt: string; profileId: string; providerTradeNo: string | null; invoicePreference: unknown }) {
  if (!input.paymentOrderId) return;
  const existing = await supabaseAdmin.from("billing_ledger").select("id").eq("payment_order_id", input.paymentOrderId).eq("ledger_type", "payment").limit(1).maybeSingle();
  if (existing.error) throw existing.error;
  if (existing.data) return;

  await supabaseAdmin.from("billing_ledger").insert({
    user_id: input.userId,
    provider: "ecpay_recurring",
    ledger_type: "payment",
    direction: "credit",
    amount_twd: input.amount,
    currency: "TWD",
    payment_order_id: input.paymentOrderId,
    description: "訂閱自動扣款成功",
    occurred_at: input.paidAt,
    metadata: { subscription_profile_id: input.profileId, provider_trade_no: input.providerTradeNo, invoice_preference: input.invoicePreference, build_tag: RECURRING_NOTIFY_BUILD_TAG },
  });
}

async function insertEntitlementEventIfMissing(input: { userId: string; paymentOrderId: string | null; profileId: string; planCode: string; paidAt: string; validUntil: string }) {
  if (!input.paymentOrderId) return;
  const existing = await supabaseAdmin.from("entitlement_events").select("id").eq("payment_order_id", input.paymentOrderId).eq("event_type", "extend").limit(1).maybeSingle();
  if (existing.error) throw existing.error;
  if (existing.data) return;

  await supabaseAdmin.from("entitlement_events").insert({
    user_id: input.userId,
    event_type: "extend",
    plan_code: input.planCode,
    entitlement_key: "vip",
    quantity: 1,
    valid_from: input.paidAt,
    valid_until: input.validUntil,
    payment_order_id: input.paymentOrderId,
    metadata: { subscription_profile_id: input.profileId, build_tag: RECURRING_NOTIFY_BUILD_TAG },
  });
}

async function insertInvoiceRequestIfMissing(input: { userId: string; paymentOrderId: string | null; profileId: string; itemName: string; amount: number; invoicePreference: unknown }) {
  if (!input.paymentOrderId) return;
  const existing = await supabaseAdmin.from("invoice_events").select("id").eq("payment_order_id", input.paymentOrderId).eq("event_type", "requested").limit(1).maybeSingle();
  if (existing.error) throw existing.error;
  if (existing.data) return;

  await supabaseAdmin.from("invoice_events").insert({
    user_id: input.userId,
    payment_order_id: input.paymentOrderId,
    provider: "ecpay_invoice",
    event_type: "requested",
    metadata: { source: "recurring_payment", subscription_profile_id: input.profileId, item_name: input.itemName, amount: input.amount, invoice_preference: input.invoicePreference, build_tag: RECURRING_NOTIFY_BUILD_TAG },
  });
}

export async function POST(req: Request) {
  const rawBody = await req.text();
  const payload = parseFormEncodedPayload(rawBody);
  const merchantTradeNo = payload.MerchantTradeNo || "UNKNOWN";
  const profileId = payload.CustomField2 || "";

  try {
    const config = getEcpayConfig();
    if (payload.MerchantID && payload.MerchantID !== config.merchantId) return textResponse("0|INVALID_MERCHANT", 400);
    if (!payload.CheckMacValue) {
      await recordPaymentEvent({ merchantTradeNo, eventType: "recurring_missing_checkmac", payload });
      return textResponse("0|MISSING_CHECKMAC", 400);
    }
    if (!verifyCheckMacValue(payload, config.hashKey, config.hashIV)) {
      await recordPaymentEvent({ merchantTradeNo, eventType: "recurring_invalid_checkmac", payload });
      return textResponse("0|INVALID_CHECKMAC", 400);
    }

    const profile = profileId
      ? await supabaseAdmin.from("subscription_profiles").select("*").eq("id", profileId).maybeSingle()
      : await supabaseAdmin.from("subscription_profiles").select("*").eq("merchant_trade_no", merchantTradeNo).maybeSingle();
    if (profile.error || !profile.data) {
      await recordPaymentEvent({ merchantTradeNo, eventType: "recurring_profile_not_found", payload });
      return textResponse("0|PROFILE_NOT_FOUND", 404);
    }

    const invoicePreference = profile.data.raw_payload?.invoice_preference || null;
    const rtnCode = String(payload.RtnCode || payload.TradeStatus || "");
    const amount = Number(payload.TradeAmt || payload.Amount || profile.data.period_amount || 0);
    const paidAt = parsePaidAt(payload.PaymentDate) || new Date().toISOString();
    const providerTradeNo = payload.TradeNo || null;
    const success = rtnCode === "1" || /paid|success/i.test(String(payload.RtnMsg || ""));
    const orderMerchantTradeNo = providerTradeNo ? `SUB${providerTradeNo}` : merchantTradeNo;

    const existingOrder = await findExistingRecurringOrder({ merchantTradeNo: orderMerchantTradeNo, providerTradeNo });
    let order = existingOrder;

    if (!order) {
      const inserted = await supabaseAdmin.from("payment_orders").insert({
        user_id: profile.data.user_id,
        provider: "ecpay_recurring",
        merchant_trade_no: orderMerchantTradeNo,
        plan_code: profile.data.plan_code,
        amount,
        currency: "TWD",
        status: success ? "paid" : "failed",
        item_name: `安感島訂閱自動扣款｜${profile.data.plan_code}`,
        trade_desc: "ANGANDAO Subscription Recurring Charge",
        vip_days: 30,
        provider_trade_no: providerTradeNo,
        paid_at: success ? paidAt : null,
        provider_payload: { ...payload, original_merchant_trade_no: merchantTradeNo, invoice_preference: invoicePreference, build_tag: RECURRING_NOTIFY_BUILD_TAG },
        invoice_preference: invoicePreference,
        last_error: success ? null : JSON.stringify(payload),
      }).select("*").single();

      if (inserted.error || !inserted.data) throw inserted.error || new Error("recurring_payment_order_insert_failed");
      order = inserted.data;
    }

    const eventExists = await supabaseAdmin.from("subscription_events").select("id").eq("subscription_profile_id", profile.data.id).eq("event_type", success ? "recurring_payment_paid" : "recurring_payment_failed").eq("payment_order_id", order.id).limit(1).maybeSingle();
    if (eventExists.error) throw eventExists.error;

    if (!eventExists.data) {
      await supabaseAdmin.from("subscription_events").insert({
        subscription_profile_id: profile.data.id,
        user_id: profile.data.user_id,
        event_type: success ? "recurring_payment_paid" : "recurring_payment_failed",
        merchant_trade_no: merchantTradeNo,
        payment_order_id: order.id,
        provider_payload: { ...payload, invoice_preference: invoicePreference, build_tag: RECURRING_NOTIFY_BUILD_TAG },
      });
    }

    if (success) {
      const validUntil = addDaysIso(paidAt, 30);
      await supabaseAdmin.from("subscription_profiles").update({
        status: "active",
        current_period_start: paidAt,
        current_period_end: validUntil,
        next_charge_at: validUntil,
        raw_payload: { ...profile.data.raw_payload, last_notify_payload: payload, build_tag: RECURRING_NOTIFY_BUILD_TAG },
        last_provider_error: null,
        updated_at: new Date().toISOString(),
      }).eq("id", profile.data.id);

      await upsertVipEntitlement({ userId: profile.data.user_id, validUntil });
      await insertLedgerIfMissing({ userId: profile.data.user_id, paymentOrderId: order.id, amount, paidAt, profileId: profile.data.id, providerTradeNo, invoicePreference });
      await insertEntitlementEventIfMissing({ userId: profile.data.user_id, paymentOrderId: order.id, profileId: profile.data.id, planCode: profile.data.plan_code, paidAt, validUntil });
      await insertInvoiceRequestIfMissing({ userId: profile.data.user_id, paymentOrderId: order.id, profileId: profile.data.id, itemName: order.item_name, amount, invoicePreference });
    } else {
      await supabaseAdmin.from("subscription_profiles").update({
        status: "past_due",
        raw_payload: { ...profile.data.raw_payload, last_notify_payload: payload, build_tag: RECURRING_NOTIFY_BUILD_TAG },
        last_provider_error: payload.RtnMsg || JSON.stringify(payload),
        updated_at: new Date().toISOString(),
      }).eq("id", profile.data.id);
    }

    return textResponse("1|OK");
  } catch (error: any) {
    await recordPaymentEvent({ merchantTradeNo, eventType: "recurring_notify_exception", payload: { payload, message: error?.message || "unknown" } });
    return textResponse("0|SERVER_ERROR", 500);
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { ROOM_INFRA_BUILD_TAG, maskUserId, parseDailyRoomNameFromUrl } from "@/lib/server/roomInfra";

export const runtime = "nodejs";

type RouteContext = { params: Promise<{ roomId: string }> };

async function fetchDailyRoom(roomName: string) {
  const dailyKey = process.env.DAILY_API_KEY;
  const dailyApiBase = process.env.DAILY_API_BASE || "https://api.daily.co/v1";

  if (!dailyKey) {
    return { ok: false, configured: false, error: "Missing DAILY_API_KEY" };
  }

  const response = await fetch(`${dailyApiBase}/rooms/${encodeURIComponent(roomName)}`, {
    method: "GET",
    headers: { Authorization: `Bearer ${dailyKey}` },
    cache: "no-store",
  });

  const json = await response.json().catch(() => ({}));
  if (!response.ok) {
    return {
      ok: false,
      configured: true,
      status: response.status,
      error: json?.info || json?.error || "Daily room lookup failed",
    };
  }

  return {
    ok: true,
    configured: true,
    status: response.status,
    room: {
      name: json?.name ?? null,
      url: json?.url ?? null,
      privacy: json?.privacy ?? null,
      created_at: json?.created_at ?? null,
      config: json?.config ?? json?.properties ?? null,
    },
  };
}

export async function GET(req: Request, context: RouteContext) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { roomId } = await context.params;

    if (!roomId) {
      return NextResponse.json({ error: "Missing roomId", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
    }

    const roomResult = await supabaseAdmin
      .from("rooms")
      .select("id,title,created_by,created_at,duration_minutes,mode,max_size,daily_room_url,visibility,status,started_at,scheduled_end_at,ended_at,last_presence_at,cleanup_reason")
      .eq("id", roomId)
      .maybeSingle();

    if (roomResult.error || !roomResult.data) {
      return NextResponse.json({ error: roomResult.error?.message || "Room not found", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 404 });
    }

    const room = roomResult.data as any;
    const isOwner = room.created_by === userId;

    const memberResult = await supabaseAdmin
      .from("room_members")
      .select("room_id,user_id")
      .eq("room_id", roomId);

    if (memberResult.error) {
      return NextResponse.json({ error: memberResult.error.message, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
    }

    const members = (memberResult.data ?? []) as Array<{ user_id: string }>;
    const isMember = isOwner || members.some((item) => item.user_id === userId);

    if (!isMember) {
      return NextResponse.json({ error: "Not a room member", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 403 });
    }

    const [accessSessionsResult, presenceResult] = await Promise.all([
      supabaseAdmin
        .from("room_access_sessions")
        .select("id,user_id,billing_session_key,charge_status,charged_at,last_token_issued_at,token_exp,entitlement_source,allowed_by_pair_vip_carry,status,last_presence_at,last_error,created_at,updated_at")
        .eq("room_id", roomId)
        .order("created_at", { ascending: false })
        .limit(10),
      supabaseAdmin
        .from("room_presence_events")
        .select("id,user_id,presence_mode,event_type,heartbeat_at,visible_state,media_track_state,brb_until,access_session_id,created_at")
        .eq("room_id", roomId)
        .order("created_at", { ascending: false })
        .limit(20),
    ]);

    const dailyRoomName = parseDailyRoomNameFromUrl(room.daily_room_url);
    const daily = dailyRoomName ? await fetchDailyRoom(dailyRoomName) : { ok: false, configured: Boolean(process.env.DAILY_API_KEY), error: "Missing daily_room_url" };

    return NextResponse.json({
      ok: true,
      build_tag: ROOM_INFRA_BUILD_TAG,
      viewer: {
        user_id_masked: maskUserId(userId),
        is_owner: isOwner,
        is_member: isMember,
      },
      room: {
        ...room,
        created_by: maskUserId(room.created_by),
        daily_room_name: dailyRoomName,
      },
      members: {
        count: members.length,
        user_ids_masked: members.map((item) => maskUserId(item.user_id)),
      },
      access_sessions: accessSessionsResult.error
        ? { error: accessSessionsResult.error.message }
        : (accessSessionsResult.data ?? []).map((item: any) => ({ ...item, user_id: maskUserId(item.user_id) })),
      presence_events: presenceResult.error
        ? { error: presenceResult.error.message }
        : (presenceResult.data ?? []).map((item: any) => ({ ...item, user_id: maskUserId(item.user_id) })),
      daily,
    });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "Unauthorized", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "Unexpected server error", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { HOST_CREDIT_BUILD_TAG, createAiHostSponsorPass } from "@/lib/server/hostCredit";

export const runtime = "nodejs";

type Context = { params: Promise<{ roomId: string }> };
type Body = { pass_type?: "ai_host"; duration_minutes?: number; benefited_user_ids?: string[]; metadata?: Record<string, unknown> };

export async function POST(req: Request, context: Context) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { roomId } = await context.params;
    const body = (await req.json().catch(() => ({}))) as Body;

    const room = await supabaseAdmin.from("rooms").select("id,created_by,duration_minutes,status,ended_at").eq("id", roomId).maybeSingle();
    if (room.error || !room.data) return NextResponse.json({ error: room.error?.message || "找不到房間。", build_tag: HOST_CREDIT_BUILD_TAG }, { status: 404 });
    if (room.data.ended_at || room.data.status === "ended") return NextResponse.json({ error: "房間已結束，不能建立贊助通行證。", build_tag: HOST_CREDIT_BUILD_TAG }, { status: 410 });

    const membership = await supabaseAdmin.from("room_members").select("room_id,user_id").eq("room_id", roomId).eq("user_id", userId).maybeSingle();
    if (membership.error || (!membership.data && room.data.created_by !== userId)) return NextResponse.json({ error: "只有房間成員可以贊助 Shared Host。", build_tag: HOST_CREDIT_BUILD_TAG }, { status: 403 });
    if (body.pass_type && body.pass_type !== "ai_host") return NextResponse.json({ error: "目前只開放 AI 主持通行證 gate。", build_tag: HOST_CREDIT_BUILD_TAG }, { status: 400 });

    const result = await createAiHostSponsorPass({
      roomId,
      sponsorUserId: userId,
      durationMinutes: Number(body.duration_minutes || room.data.duration_minutes || 25),
      benefitedUserIds: body.benefited_user_ids ?? [],
      metadata: { source: "room_sponsor_pass_api", ...body.metadata },
    });

    return NextResponse.json({ sponsor_pass: result, build_tag: HOST_CREDIT_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") return NextResponse.json({ error: "請先登入後再贊助 AI 主持。", build_tag: HOST_CREDIT_BUILD_TAG }, { status: 401 });
    const status = /INSUFFICIENT_HOST_CREDITS/.test(error?.message || "") ? 402 : 500;
    return NextResponse.json({ error: error?.message || "建立贊助通行證失敗。", build_tag: HOST_CREDIT_BUILD_TAG }, { status });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { areUsersFriends, getAuthUserFromRequest, isVipUser } from "@/lib/serverRoomUtils";
import { ROOM_INFRA_BUILD_TAG, isRoomEndedOrExpired } from "@/lib/server/roomInfra";

export const runtime = "nodejs";

type Body = {
  roomId?: string;
  inviteCode?: string;
};

function normalizeInviteCode(input?: string | null) {
  return (input ?? "").trim().toUpperCase();
}

export async function POST(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const body = (await req.json()) as Body;
    const roomId = (body.roomId ?? "").trim();
    const inviteCode = normalizeInviteCode(body.inviteCode);

    if (!roomId) {
      return NextResponse.json({ error: "Missing roomId", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
    }

    const roomResult = await supabaseAdmin
      .from("rooms")
      .select("id,title,duration_minutes,mode,max_size,created_at,created_by,daily_room_url,visibility,invite_code,status,started_at,scheduled_end_at,ended_at,last_presence_at,cleanup_reason")
      .eq("id", roomId)
      .maybeSingle();

    const room = roomResult.data as any;

    if (roomResult.error || !room?.id) {
      return NextResponse.json({ error: roomResult.error?.message || "Room not found", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 404 });
    }

    if (isRoomEndedOrExpired(room, 3)) {
      return NextResponse.json({ error: "這間同行空間已結束。", code: "ROOM_ENDED", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 410 });
    }

    const membershipResult = await supabaseAdmin
      .from("room_members")
      .select("room_id,user_id")
      .eq("room_id", roomId)
      .eq("user_id", userId)
      .maybeSingle();

    if (membershipResult.error) {
      return NextResponse.json({ error: membershipResult.error.message, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
    }

    const isOwner = room.created_by === userId;
    const isMember = isOwner || Boolean(membershipResult.data);
    const visibility = (room.visibility ?? "public") as "public" | "members" | "friends" | "invited";
    const normalizedRoomInviteCode = normalizeInviteCode(room.invite_code);

    let canJoin = isMember;
    let requiresInviteCode = false;

    if (!canJoin) {
      if (visibility === "public") {
        canJoin = true;
      } else if (visibility === "members") {
        canJoin = await isVipUser(userId);
      } else if (visibility === "friends") {
        canJoin = await areUsersFriends(userId, room.created_by);
      } else if (visibility === "invited") {
        requiresInviteCode = true;
        canJoin = inviteCode.length > 0 && inviteCode === normalizedRoomInviteCode;
      }
    }

    if (!isMember && !canJoin && (visibility === "members" || visibility === "friends")) {
      return NextResponse.json({ error: "你目前沒有權限查看這間同行空間。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 403 });
    }

    return NextResponse.json({
      room: {
        ...room,
        invite_code: isMember ? room.invite_code : null,
      },
      is_owner: isOwner,
      is_member: isMember,
      can_join: canJoin,
      requires_invite_code: requiresInviteCode,
      invite_code_accepted: visibility === "invited" ? inviteCode.length > 0 && inviteCode === normalizedRoomInviteCode : false,
      build_tag: ROOM_INFRA_BUILD_TAG,
    });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再查看同行空間。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "Unexpected server error", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { createDailyPrivateRoom } from "@/lib/serverRoomUtils";
import { ROOM_INFRA_BUILD_TAG, addMinutes } from "@/lib/server/roomInfra";
import { isAllowedGeneralRoomDuration, normalizeGroupSize, ROOM_CATEGORIES } from "@/lib/productCatalog";
import { identityAccessErrorResponse, requirePhoneVerifiedForRequest } from "@/lib/server/identityAccess";

export const runtime = "nodejs";
type CreateRoomBody = { title?: string; duration_minutes?: number; mode?: "pair" | "group"; max_size?: number; room_category?: "focus" | "life" | "share" | "hobby"; interaction_style?: "silent" | "light-chat" | "guided" | "open-share"; visibility?: "public" | "members" | "friends" | "invited"; host_note?: string | null };
const ROOM_SELECT = "id,title,duration_minutes,mode,max_size,created_by,daily_room_url,room_category,interaction_style,visibility,host_note,invite_code,created_at,status,started_at,scheduled_end_at,ended_at,last_presence_at,cleanup_reason";
const VALID_CATEGORIES = new Set(ROOM_CATEGORIES.map((category) => category.code));

export async function POST(req: Request) {
  try {
    const { userId } = await requirePhoneVerifiedForRequest(req);
    const body = (await req.json()) as CreateRoomBody;
    const title = (body.title ?? "").trim().slice(0, 80);
    const durationMinutes = Number(body.duration_minutes ?? 50);
    const mode = body.mode === "pair" ? "pair" : "group";
    const maxSize = normalizeGroupSize(body.max_size, mode);
    const roomCategory = (body.room_category ?? "focus") as CreateRoomBody["room_category"];
    const interactionStyle = (body.interaction_style ?? "silent") as CreateRoomBody["interaction_style"];
    const visibility = (body.visibility ?? "public") as CreateRoomBody["visibility"];
    const hostNote = (body.host_note ?? "").trim() || null;
    if (!title) return NextResponse.json({ error: "請先填寫同行空間名稱。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
    if (!isAllowedGeneralRoomDuration(durationMinutes)) return NextResponse.json({ error: "一般即時同行空間目前只支援 25 / 50 / 75 分鐘；90 分鐘保留給活動房，100 分鐘不再是正式規格。", code: "UNSUPPORTED_ROOM_DURATION", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
    if (!VALID_CATEGORIES.has(roomCategory ?? "focus")) return NextResponse.json({ error: "同行空間目前只支援專注任務、生活陪伴、主題分享、興趣同好。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
    const now = new Date(); const scheduledEndAt = addMinutes(now, durationMinutes).toISOString();
    const insertRoom = await supabaseAdmin.from("rooms").insert({ title, duration_minutes: durationMinutes, mode, max_size: maxSize, created_by: userId, room_category: roomCategory, interaction_style: interactionStyle, visibility, host_note: hostNote, status: "active", started_at: now.toISOString(), scheduled_end_at: scheduledEndAt }).select(ROOM_SELECT).single();
    if (insertRoom.error || !insertRoom.data) return NextResponse.json({ error: insertRoom.error?.message ?? "建立同行空間失敗。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
    const room = insertRoom.data as any; const roomMember = await supabaseAdmin.from("room_members").insert({ room_id: room.id, user_id: userId });
    if (roomMember.error) { await supabaseAdmin.from("rooms").delete().eq("id", room.id); return NextResponse.json({ error: roomMember.error.message, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 }); }
    try { const roomName = `cowork_${String(room.id).replaceAll("-", "")}`; const created = await createDailyPrivateRoom(roomName); const updateRoom = await supabaseAdmin.from("rooms").update({ daily_room_url: created.url }).eq("id", room.id).select(ROOM_SELECT).single(); if (updateRoom.error || !updateRoom.data) throw new Error(updateRoom.error?.message ?? "更新 Daily 房間失敗"); return NextResponse.json({ room: updateRoom.data, invite_code: (updateRoom.data as any).invite_code ?? null, build_tag: ROOM_INFRA_BUILD_TAG }); } catch (error: any) { await supabaseAdmin.from("room_members").delete().eq("room_id", room.id).eq("user_id", userId); await supabaseAdmin.from("rooms").delete().eq("id", room.id); return NextResponse.json({ error: error?.message || "建立 Daily 房間失敗。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 }); }
  } catch (error: any) {
    const mapped = identityAccessErrorResponse(error, ROOM_INFRA_BUILD_TAG); if (mapped) return mapped;
    return NextResponse.json({ error: error?.message || "Unexpected server error", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
  }
}

