import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { areUsersFriends, isVipUser } from "@/lib/serverRoomUtils";
import { ROOM_INFRA_BUILD_TAG, isRoomEndedOrExpired } from "@/lib/server/roomInfra";
import { userBlockExists } from "@/lib/server/safety";
import { identityAccessErrorResponse, requirePhoneVerifiedForRequest } from "@/lib/server/identityAccess";

export const runtime = "nodejs";
type JoinBody = { roomId?: string; inviteCode?: string };
function normalizeInviteCode(input?: string | null) { return (input ?? "").trim().toUpperCase(); }
function joinErrorResponse(code?: string, payload?: any) {
  if (code === "ROOM_FULL") return NextResponse.json({ error: "這間同行空間目前已滿。", code, ...payload, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 409 });
  if (code === "ROOM_ENDED" || code === "ROOM_EXPIRED") return NextResponse.json({ error: "這間同行空間已結束。", code, ...payload, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 410 });
  if (code === "ROOM_NOT_FOUND") return NextResponse.json({ error: "找不到對應的同行空間。", code, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 404 });
  return NextResponse.json({ error: "加入同行空間失敗。", code: code || "JOIN_FAILED", ...payload, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
}
export async function POST(req: Request) {
  try {
    const { userId } = await requirePhoneVerifiedForRequest(req);
    const body = (await req.json()) as JoinBody;
    const roomId = (body.roomId ?? "").trim(); const inviteCode = normalizeInviteCode(body.inviteCode);
    if (!roomId && !inviteCode) return NextResponse.json({ error: "Missing roomId or inviteCode", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 400 });
    let query = supabaseAdmin.from("rooms").select("id,title,created_by,created_at,duration_minutes,mode,max_size,visibility,invite_code,status,scheduled_end_at,ended_at").limit(1);
    query = roomId ? query.eq("id", roomId) : query.eq("invite_code", inviteCode);
    const roomResult = await query.maybeSingle(); const room = roomResult.data as any;
    if (roomResult.error || !room?.id) return NextResponse.json({ error: "找不到對應的同行空間。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 404 });
    if (isRoomEndedOrExpired(room, 3)) return NextResponse.json({ error: "這間同行空間已結束。", code: "ROOM_ENDED", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 410 });
    const blocked = await userBlockExists(userId, room.created_by);
    if (blocked) return NextResponse.json({ error: "你目前無法加入這間同行空間。", code: "BLOCKED_BY_SAFETY_GATE", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 403 });
    const existingMembership = await supabaseAdmin.from("room_members").select("room_id,user_id").eq("room_id", room.id).eq("user_id", userId).maybeSingle();
    if (existingMembership.error) return NextResponse.json({ error: existingMembership.error.message, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
    if (existingMembership.data || room.created_by === userId) return NextResponse.json({ roomId: room.id, title: room.title, visibility: room.visibility, invite_code: room.visibility === "invited" ? room.invite_code : null, alreadyMember: true, build_tag: ROOM_INFRA_BUILD_TAG });
    const visibility = (room.visibility ?? "public") as "public" | "members" | "friends" | "invited";
    let allowed = false;
    if (visibility === "public") allowed = true;
    else if (visibility === "members") allowed = await isVipUser(userId);
    else if (visibility === "friends") allowed = await areUsersFriends(userId, room.created_by);
    else if (visibility === "invited") allowed = inviteCode.length > 0 && inviteCode === normalizeInviteCode(room.invite_code);
    if (!allowed) return NextResponse.json({ error: "你目前沒有權限加入這間同行空間。", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 403 });
    const joinResult = await supabaseAdmin.rpc("cowork_join_room_with_capacity", { p_room_id: room.id, p_user_id: userId });
    if (joinResult.error) return NextResponse.json({ error: joinResult.error.message, build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
    const payload = (joinResult.data ?? {}) as any; if (!payload.ok) return joinErrorResponse(payload.code, payload);
    return NextResponse.json({ roomId: room.id, title: room.title, visibility: room.visibility, invite_code: room.visibility === "invited" ? room.invite_code : null, alreadyMember: Boolean(payload.already_member), member_count: payload.member_count ?? null, max_size: payload.max_size ?? (room.mode === "pair" ? 2 : room.max_size), build_tag: ROOM_INFRA_BUILD_TAG });
  } catch (error: any) {
    const mapped = identityAccessErrorResponse(error, ROOM_INFRA_BUILD_TAG); if (mapped) return mapped;
    return NextResponse.json({ error: error?.message || "Unexpected server error", build_tag: ROOM_INFRA_BUILD_TAG }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import {
  ROOM_INFRA_BUILD_TAG,
  parseDailyRoomNameFromUrl,
  tryDeleteDailyRoom,
} from "@/lib/server/roomInfra";
import {
  ROOM_SUMMARY_BUILD_TAG,
  summarizeRoom,
} from "@/lib/server/roomSummary";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

type LeaveBody = {
  roomId?: string;
  reason?: string | null;
};

export async function POST(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const body = (await req.json().catch(() => ({}))) as LeaveBody;
    const roomId = String(body.roomId || "").trim();

    if (!roomId) {
      return NextResponse.json(
        { error: "Missing roomId", build_tag: ROOM_INFRA_BUILD_TAG },
        { status: 400 },
      );
    }

    const result = await supabaseAdmin.rpc("cowork_leave_room", {
      p_room_id: roomId,
      p_user_id: userId,
      p_reason: String(body.reason || "user_leave").slice(0, 80),
    });

    if (result.error) {
      return NextResponse.json(
        { error: result.error.message, build_tag: ROOM_INFRA_BUILD_TAG },
        { status: 500 },
      );
    }

    const payload = (result.data ?? {}) as any;
    const dailyRoomName = payload?.room_ended
      ? parseDailyRoomNameFromUrl(payload?.daily_room_url)
      : null;
    let dailyDelete: Record<string, unknown> | null = null;
    let summary: Record<string, unknown> | null = null;

    if (dailyRoomName) {
      dailyDelete = await tryDeleteDailyRoom(dailyRoomName).catch((error) => ({
        ok: false,
        reason:
          error instanceof Error ? error.message : "daily_delete_exception",
      }));
    }

    if (payload?.room_ended) {
      summary = await summarizeRoom(roomId)
        .then((resultPayload) => ({
          ok: true,
          room_id: roomId,
          summary_id: resultPayload.summary?.room_id ?? roomId,
          build_tag: ROOM_SUMMARY_BUILD_TAG,
        }))
        .catch((error) => ({
          ok: false,
          room_id: roomId,
          error: error instanceof Error ? error.message : String(error),
          retry: "/api/internal/rooms/summarize-ended",
          build_tag: ROOM_SUMMARY_BUILD_TAG,
        }));
    }

    return NextResponse.json(
      {
        ...payload,
        daily_room_name: dailyRoomName,
        daily_delete: dailyDelete,
        post_session_summary: summary,
        build_tag: ROOM_INFRA_BUILD_TAG,
        summary_build_tag: ROOM_SUMMARY_BUILD_TAG,
      },
      { headers: { "Cache-Control": "no-store" } },
    );
  } catch (error) {
    const message =
      error instanceof Error ? error.message : "Unexpected server error";
    if (message === "UNAUTHORIZED") {
      return NextResponse.json(
        { error: "Unauthorized", build_tag: ROOM_INFRA_BUILD_TAG },
        { status: 401 },
      );
    }

    return NextResponse.json(
      { error: message, build_tag: ROOM_INFRA_BUILD_TAG },
      { status: 500 },
    );
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";

export const runtime = "nodejs";

type Body = { roomId?: string };

export async function POST(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const body = (await req.json()) as Body;
    const roomId = (body.roomId ?? "").trim();

    if (!roomId) {
      return NextResponse.json({ error: "Missing roomId" }, { status: 400 });
    }

    const { data: room, error: roomErr } = await supabaseAdmin
      .from("rooms")
      .select("id,created_by")
      .eq("id", roomId)
      .single();

    if (roomErr || !room) {
      return NextResponse.json({ error: roomErr?.message || "Room not found" }, { status: 404 });
    }

    const isOwner = room.created_by === userId;

    const { data: ownMembership, error: ownMembershipErr } = await supabaseAdmin
      .from("room_members")
      .select("room_id,user_id")
      .eq("room_id", roomId)
      .eq("user_id", userId)
      .maybeSingle();

    if (ownMembershipErr) {
      return NextResponse.json({ error: ownMembershipErr.message }, { status: 500 });
    }

    if (!isOwner && !ownMembership) {
      return NextResponse.json({ error: "Not allowed to view room roster" }, { status: 403 });
    }

    const { data: members, error: membersErr } = await supabaseAdmin
      .from("room_members")
      .select("room_id,user_id")
      .eq("room_id", roomId);

    if (membersErr) {
      return NextResponse.json({ error: membersErr.message }, { status: 500 });
    }

    const memberRows = (members ?? []) as Array<{ room_id: string; user_id: string }>;
    const memberIds = Array.from(new Set([...memberRows.map((item) => item.user_id), room.created_by, userId]));

    let profiles: any[] = [];
    if (memberIds.length > 0) {
      const { data: profileRows, error: profilesErr } = await supabaseAdmin
        .from("profiles")
        .select("*")
        .in("user_id", memberIds);

      if (profilesErr) {
        return NextResponse.json({ error: profilesErr.message }, { status: 500 });
      }

      profiles = profileRows ?? [];
    }

    const otherIds = memberIds.filter((id) => id !== userId);

    const [incomingReqResult, outgoingReqResult, friendshipsResult] = await Promise.all([
      otherIds.length > 0
        ? supabaseAdmin
            .from("friend_requests")
            .select("*")
            .eq("addressee_user_id", userId)
            .eq("status", "pending")
            .in("requester_user_id", otherIds)
        : Promise.resolve({ data: [], error: null } as any),
      otherIds.length > 0
        ? supabaseAdmin
            .from("friend_requests")
            .select("*")
            .eq("requester_user_id", userId)
            .eq("status", "pending")
            .in("addressee_user_id", otherIds)
        : Promise.resolve({ data: [], error: null } as any),
      supabaseAdmin
        .from("friendships")
        .select("*")
        .or(`user_low.eq.${userId},user_high.eq.${userId}`),
    ]);

    if (incomingReqResult.error) {
      return NextResponse.json({ error: incomingReqResult.error.message }, { status: 500 });
    }
    if (outgoingReqResult.error) {
      return NextResponse.json({ error: outgoingReqResult.error.message }, { status: 500 });
    }
    if (friendshipsResult.error) {
      return NextResponse.json({ error: friendshipsResult.error.message }, { status: 500 });
    }

    const friendships = ((friendshipsResult.data ?? []) as Array<{ user_low: string; user_high: string; created_at: string }>).filter((item) => {
      const otherId = item.user_low === userId ? item.user_high : item.user_low;
      return memberIds.includes(otherId);
    });

    return NextResponse.json({
      room: {
        id: room.id,
        created_by: room.created_by,
      },
      members: memberRows,
      profiles,
      incoming_requests: incomingReqResult.data ?? [],
      outgoing_requests: outgoingReqResult.data ?? [],
      friendships,
    });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再查看房內名單。" }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "Unexpected server error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { FORMAL_OPS_BUILD_TAG, cleanText } from "@/lib/server/safety";

export const runtime = "nodejs";

type Body = {
  blocked_user_id?: string;
  action?: "block" | "unblock";
  reason?: string | null;
};

function isMissingRelationshipBlockSchema(message?: string | null) {
  const text = String(message || "");
  return (
    /relation .*user_blocks.* does not exist/i.test(text) ||
    /column .*user_blocks\.(id|blocker_user_id|blocked_user_id|reason|created_at).* does not exist/i.test(text) ||
    /Could not find the '(id|blocker_user_id|blocked_user_id|reason|created_at)' column/i.test(text)
  );
}

function normalizeBlockRow(row: any) {
  const blocker = row?.blocker_user_id ?? "";
  const blocked = row?.blocked_user_id ?? "";

  return {
    id: row?.id ?? `${blocker}:${blocked}`,
    blocker_user_id: blocker,
    blocked_user_id: blocked,
    reason: row?.reason ?? null,
    created_at: row?.created_at ?? null,
  };
}

export async function GET(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);

    const { data, error } = await supabaseAdmin
      .from("user_blocks")
      .select("blocker_user_id,blocked_user_id,reason,created_at")
      .eq("blocker_user_id", userId)
      .order("created_at", { ascending: false })
      .limit(200);

    if (error) {
      if (isMissingRelationshipBlockSchema(error.message)) {
        return NextResponse.json({
          blocks: [],
          soft_error: error.message,
          build_tag: FORMAL_OPS_BUILD_TAG,
        });
      }

      return NextResponse.json({ error: error.message, build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ blocks: (data ?? []).map(normalizeBlockRow), build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再查看封鎖名單。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 401 });
    }

    return NextResponse.json({ error: error?.message || "讀取封鎖名單失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const body = (await req.json().catch(() => ({}))) as Body;
    const targetUserId = cleanText(body.blocked_user_id, 80);
    const action = body.action || "block";
    const reason = cleanText(body.reason, 1000) || null;

    if (!targetUserId) {
      return NextResponse.json({ error: "缺少 blocked_user_id。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    if (targetUserId === userId) {
      return NextResponse.json({ error: "不能封鎖自己。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    if (action === "unblock") {
      const result = await supabaseAdmin
        .from("user_blocks")
        .delete()
        .eq("blocker_user_id", userId)
        .eq("blocked_user_id", targetUserId);

      if (result.error) {
        return NextResponse.json({ error: result.error.message, build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
      }

      return NextResponse.json({ ok: true, action: "unblock", build_tag: FORMAL_OPS_BUILD_TAG });
    }

    const existing = await supabaseAdmin
      .from("user_blocks")
      .select("blocker_user_id,blocked_user_id,reason,created_at")
      .eq("blocker_user_id", userId)
      .eq("blocked_user_id", targetUserId)
      .maybeSingle();

    if (existing.error && isMissingRelationshipBlockSchema(existing.error.message)) {
      return NextResponse.json(
        {
          error: "封鎖功能的資料庫欄位尚未完整建立，請先套用 user_blocks schema alignment migration。",
          details: existing.error.message,
          build_tag: FORMAL_OPS_BUILD_TAG,
        },
        { status: 500 }
      );
    }

    if (existing.error) {
      return NextResponse.json({ error: existing.error.message, build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    const writeResult = existing.data
      ? await supabaseAdmin
          .from("user_blocks")
          .update({ reason })
          .eq("blocker_user_id", userId)
          .eq("blocked_user_id", targetUserId)
          .select("blocker_user_id,blocked_user_id,reason,created_at")
          .single()
      : await supabaseAdmin
          .from("user_blocks")
          .insert({ blocker_user_id: userId, blocked_user_id: targetUserId, reason })
          .select("blocker_user_id,blocked_user_id,reason,created_at")
          .single();

    if (writeResult.error || !writeResult.data) {
      return NextResponse.json({ error: writeResult.error?.message || "封鎖失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ block: normalizeBlockRow(writeResult.data), build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再封鎖使用者。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 401 });
    }

    return NextResponse.json({ error: error?.message || "封鎖操作失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { FORMAL_OPS_BUILD_TAG, cleanText, insertReliabilityEvent } from "@/lib/server/safety";

export const runtime = "nodejs";

type ReportBody = {
  target_type?: string;
  target_user_id?: string | null;
  target_room_id?: string | null;
  target_buddy_service_id?: string | null;
  target_buddy_booking_id?: string | null;
  category?: string;
  description?: string;
  severity?: string;
  metadata?: Record<string, unknown>;
};

const TARGET_TYPES = new Set(["user", "room", "buddy_service", "buddy_booking", "payment_order", "ai", "other"]);
const CATEGORIES = new Set(["harassment", "sexual", "spam", "scam", "illegal", "self_harm", "privacy", "payment", "impersonation", "other"]);
const SEVERITIES = new Set(["low", "normal", "high", "critical"]);

function normalized(value: unknown, allowed: Set<string>, fallback: string) {
  const text = cleanText(value, 40);
  return allowed.has(text) ? text : fallback;
}

export async function GET(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { data, error } = await supabaseAdmin
      .from("user_reports")
      .select("id,target_type,target_user_id,target_room_id,target_buddy_service_id,target_buddy_booking_id,category,status,severity,created_at,updated_at")
      .eq("reporter_user_id", userId)
      .order("created_at", { ascending: false })
      .limit(100);

    if (error) {
      return NextResponse.json({ error: error.message, build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ reports: data ?? [], build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再查看檢舉紀錄。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "讀取檢舉紀錄失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const body = (await req.json().catch(() => ({}))) as ReportBody;

    const targetType = normalized(body.target_type, TARGET_TYPES, "other");
    const category = normalized(body.category, CATEGORIES, "other");
    const severity = normalized(body.severity, SEVERITIES, category === "sexual" || category === "scam" ? "high" : "normal");
    const description = cleanText(body.description, 6000);

    if (!description) {
      return NextResponse.json({ error: "請填寫檢舉說明。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    const insert = await supabaseAdmin
      .from("user_reports")
      .insert({
        reporter_user_id: userId,
        target_type: targetType,
        target_user_id: body.target_user_id || null,
        target_room_id: body.target_room_id || null,
        target_buddy_service_id: body.target_buddy_service_id || null,
        target_buddy_booking_id: body.target_buddy_booking_id || null,
        category,
        description,
        severity,
        status: "open",
        metadata: body.metadata ?? {},
      })
      .select("*")
      .single();

    if (insert.error || !insert.data) {
      return NextResponse.json({ error: insert.error?.message || "建立檢舉失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    await insertReliabilityEvent({
      userId: body.target_user_id || null,
      roomId: body.target_room_id || null,
      eventType: "report_received",
      severity: severity as any,
      source: "user_report",
      metadata: { report_id: insert.data.id, category, target_type: targetType },
    });

    return NextResponse.json({ report: insert.data, build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再送出檢舉。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "送出檢舉失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { FORMAL_OPS_BUILD_TAG, cleanText } from "@/lib/server/safety";
import { assertSupportTransition } from "@/lib/server/trustOps";

export const runtime = "nodejs";
type RouteContext = { params: Promise<{ ticketId: string }> };
type Body = { body?: string };

export async function POST(req: Request, context: RouteContext) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { ticketId } = await context.params;
    const body = (await req.json().catch(() => ({}))) as Body;
    const message = cleanText(body.body, 8000);
    if (!message) {
      return NextResponse.json(
        { error: "請填寫訊息內容。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 400 },
      );
    }

    const ticket = await supabaseAdmin
      .from("support_tickets")
      .select("id,status")
      .eq("id", ticketId)
      .eq("user_id", userId)
      .maybeSingle();
    if (ticket.error || !ticket.data) {
      return NextResponse.json(
        { error: ticket.error?.message || "找不到客服單。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 404 },
      );
    }
    if (ticket.data.status === "closed") {
      return NextResponse.json(
        { error: "這張客服單已關閉，請重新開啟或建立新的客服單。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 400 },
      );
    }

    const inserted = await supabaseAdmin
      .from("support_ticket_messages")
      .insert({
        ticket_id: ticketId,
        sender_user_id: userId,
        sender_role: "user",
        body: message,
      })
      .select("id,ticket_id,sender_role,body,created_at")
      .single();
    if (inserted.error || !inserted.data) {
      return NextResponse.json(
        { error: inserted.error?.message || "新增訊息失敗。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 400 },
      );
    }

    const nextStatus = ticket.data.status === "resolved" ? "open" : ticket.data.status;
    if (nextStatus !== ticket.data.status) {
      assertSupportTransition(ticket.data.status, nextStatus);
    }
    const nowIso = new Date().toISOString();
    const ticketPatch: Record<string, unknown> = {
      status: nextStatus,
      last_user_message_at: nowIso,
      updated_at: nowIso,
    };
    if (nextStatus === "open" && ticket.data.status === "resolved") {
      ticketPatch.resolved_at = null;
    }
    await supabaseAdmin
      .from("support_tickets")
      .update(ticketPatch)
      .eq("id", ticketId)
      .eq("user_id", userId);

    await supabaseAdmin.from("support_ticket_events").insert({
      ticket_id: ticketId,
      actor_user_id: userId,
      actor_role: "user",
      event_type: "user_message_added",
      from_status: ticket.data.status,
      to_status: nextStatus,
      metadata: { message_id: inserted.data.id, source: "account_support_v129" },
    });

    return NextResponse.json({ message: inserted.data, build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    const status = error?.message === "UNAUTHORIZED" ? 401 : Number(error?.status || 500);
    return NextResponse.json(
      { error: status === 401 ? "請先登入後再回覆客服單。" : error?.message || "新增客服訊息失敗。", code: error?.code, build_tag: FORMAL_OPS_BUILD_TAG },
      { status },
    );
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { FORMAL_OPS_BUILD_TAG, cleanText } from "@/lib/server/safety";
import { assertSupportTransition } from "@/lib/server/trustOps";

export const runtime = "nodejs";
type RouteContext = { params: Promise<{ ticketId: string }> };
type PatchBody = { action?: "close" | "reopen"; message?: string };

const USER_TICKET_FIELDS =
  "id,user_id,category,subject,description,status,priority,related_room_id,related_booking_id,related_payment_order_id,last_user_message_at,last_admin_message_at,resolved_at,closed_at,created_at,updated_at";

async function loadOwnTicket(ticketId: string, userId: string) {
  return supabaseAdmin
    .from("support_tickets")
    .select(USER_TICKET_FIELDS)
    .eq("id", ticketId)
    .eq("user_id", userId)
    .maybeSingle();
}

export async function GET(req: Request, context: RouteContext) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { ticketId } = await context.params;
    const ticket = await loadOwnTicket(ticketId, userId);
    if (ticket.error || !ticket.data) {
      return NextResponse.json(
        { error: ticket.error?.message || "找不到客服單。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 404 },
      );
    }

    const [messages, events] = await Promise.all([
      supabaseAdmin
        .from("support_ticket_messages")
        .select("id,ticket_id,sender_role,body,created_at")
        .eq("ticket_id", ticketId)
        .order("created_at", { ascending: true }),
      supabaseAdmin
        .from("support_ticket_events")
        .select("id,ticket_id,actor_role,event_type,from_status,to_status,created_at")
        .eq("ticket_id", ticketId)
        .order("created_at", { ascending: false })
        .limit(80),
    ]);
    if (messages.error) throw messages.error;
    if (events.error) throw events.error;

    return NextResponse.json({
      ticket: ticket.data,
      messages: messages.data ?? [],
      events: events.data ?? [],
      build_tag: FORMAL_OPS_BUILD_TAG,
    });
  } catch (error: any) {
    const status = error?.message === "UNAUTHORIZED" ? 401 : Number(error?.status || 500);
    return NextResponse.json(
      { error: status === 401 ? "請先登入後再查看客服單。" : error?.message || "讀取客服單失敗。", build_tag: FORMAL_OPS_BUILD_TAG },
      { status },
    );
  }
}

export async function PATCH(req: Request, context: RouteContext) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const { ticketId } = await context.params;
    const body = (await req.json().catch(() => ({}))) as PatchBody;
    if (!body.action || !["close", "reopen"].includes(body.action)) {
      return NextResponse.json(
        { error: "無效的客服單動作。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 400 },
      );
    }

    const current = await loadOwnTicket(ticketId, userId);
    if (current.error || !current.data) {
      return NextResponse.json(
        { error: current.error?.message || "找不到客服單。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 404 },
      );
    }

    const nextStatus = body.action === "close" ? "closed" : "open";
    assertSupportTransition(current.data.status, nextStatus);
    const nowIso = new Date().toISOString();
    const update = await supabaseAdmin
      .from("support_tickets")
      .update({
        status: nextStatus,
        resolved_at: nextStatus === "open" ? null : current.data.resolved_at,
        closed_at: nextStatus === "closed" ? nowIso : null,
        updated_at: nowIso,
      })
      .eq("id", ticketId)
      .eq("user_id", userId)
      .select(USER_TICKET_FIELDS)
      .single();
    if (update.error || !update.data) {
      return NextResponse.json(
        { error: update.error?.message || "更新客服單失敗。", build_tag: FORMAL_OPS_BUILD_TAG },
        { status: 400 },
      );
    }

    const message = cleanText(body.message, 4000);
    if (message) {
      await supabaseAdmin.from("support_ticket_messages").insert({
        ticket_id: ticketId,
        sender_user_id: userId,
        sender_role: "user",
        body: message,
      });
    }
    await supabaseAdmin.from("support_ticket_events").insert({
      ticket_id: ticketId,
      actor_user_id: userId,
      actor_role: "user",
      event_type: body.action === "close" ? "ticket_closed_by_user" : "ticket_reopened_by_user",
      from_status: current.data.status,
      to_status: nextStatus,
      metadata: { has_message: Boolean(message), source: "account_support_v129" },
    });

    return NextResponse.json({ ticket: update.data, build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    const status = error?.message === "UNAUTHORIZED" ? 401 : Number(error?.status || 500);
    return NextResponse.json(
      { error: status === 401 ? "請先登入後再操作客服單。" : error?.message || "操作客服單失敗。", code: error?.code, build_tag: FORMAL_OPS_BUILD_TAG },
      { status },
    );
  }
}

import { NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { getAuthUserFromRequest } from "@/lib/serverRoomUtils";
import { FORMAL_OPS_BUILD_TAG, cleanText } from "@/lib/server/safety";

export const runtime = "nodejs";

type CreateTicketBody = {
  category?: string;
  subject?: string;
  description?: string;
  related_room_id?: string | null;
  related_booking_id?: string | null;
  related_payment_order_id?: string | null;
  metadata?: Record<string, unknown>;
};

const ALLOWED_CATEGORIES = new Set([
  "payment",
  "invoice",
  "room",
  "account",
  "safety",
  "buddies",
  "ai",
  "refund",
  "technical",
  "other",
]);

function normalizeCategory(input?: string) {
  const value = cleanText(input || "other", 40);
  return ALLOWED_CATEGORIES.has(value) ? value : "other";
}

export async function GET(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const url = new URL(req.url);
    const status = cleanText(url.searchParams.get("status") || "", 40);
    const limit = Math.min(Math.max(Number(url.searchParams.get("limit") || 50), 1), 100);

    let query = supabaseAdmin
      .from("support_tickets")
      .select("id,category,subject,status,priority,related_room_id,related_booking_id,related_payment_order_id,last_user_message_at,last_admin_message_at,resolved_at,closed_at,created_at,updated_at")
      .eq("user_id", userId)
      .order("updated_at", { ascending: false })
      .limit(limit);

    if (status) query = query.eq("status", status);

    const { data, error } = await query;
    if (error) {
      return NextResponse.json({ error: error.message, build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    return NextResponse.json({ tickets: data ?? [], build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再查看客服紀錄。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "讀取客服紀錄失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    const { userId } = await getAuthUserFromRequest(req);
    const body = (await req.json().catch(() => ({}))) as CreateTicketBody;

    const category = normalizeCategory(body.category);
    const subject = cleanText(body.subject, 160);
    const description = cleanText(body.description, 6000);

    if (subject.length < 4) {
      return NextResponse.json({ error: "請填寫至少 4 個字的主旨。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }
    if (!description) {
      return NextResponse.json({ error: "請填寫問題內容。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    const insert = await supabaseAdmin
      .from("support_tickets")
      .insert({
        user_id: userId,
        category,
        subject,
        description,
        status: "open",
        priority: category === "safety" || category === "payment" ? "high" : "normal",
        related_room_id: body.related_room_id || null,
        related_booking_id: body.related_booking_id || null,
        related_payment_order_id: body.related_payment_order_id || null,
        metadata: body.metadata ?? {},
        last_user_message_at: new Date().toISOString(),
      })
      .select("*")
      .single();

    if (insert.error || !insert.data) {
      return NextResponse.json({ error: insert.error?.message || "建立客服單失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 400 });
    }

    await supabaseAdmin.from("support_ticket_messages").insert({
      ticket_id: insert.data.id,
      sender_user_id: userId,
      sender_role: "user",
      body: description,
    });

    await supabaseAdmin.from("support_ticket_events").insert({
      ticket_id: insert.data.id,
      actor_user_id: userId,
      actor_role: "user",
      event_type: "ticket_created",
      to_status: "open",
      metadata: { category },
    });

    return NextResponse.json({ ticket: insert.data, build_tag: FORMAL_OPS_BUILD_TAG });
  } catch (error: any) {
    if (error?.message === "UNAUTHORIZED") {
      return NextResponse.json({ error: "請先登入後再建立客服單。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 401 });
    }
    return NextResponse.json({ error: error?.message || "建立客服單失敗。", build_tag: FORMAL_OPS_BUILD_TAG }, { status: 500 });
  }
}

