  return <Image20SidebarShell title="安感夥伴" email={email} lead="Buddies 是有邊界、可預約、可審核的陪伴服務。使用功能前需手機綁定；Buddies 操作需實名審核。"><div className="i20-page" data-image20-dom-page="buddies-v118-service-detail-gated"><section className="i20-panel dark" style={{ backgroundImage: "linear-gradient(90deg,rgba(7,21,29,.95),rgba(7,21,29,.55)),url(/site-assets/image20/hero/brand-hero-evening-shared-presence.png)", backgroundSize: "cover", backgroundPosition: "center", minHeight: 250 }}><span className="i20-kicker">Buddies</span><h2 className="i20-serif" style={{ fontSize: 44 }}>找安感夥伴，或開始提供陪伴服務。</h2><p>Buddies 不是交友牆，而是把陪伴服務整理成可以被理解、預約與審核的入口。</p><div className="i20-actions-row">{(["market", "services", "slots", "bookings", "provider"] as Tab[]).map((item) => <button key={item} className={`i20-btn ${tab === item ? "peach" : "ghost"}`} onClick={() => setTab(item)}>{item === "market" ? "找夥伴" : item === "services" ? "我的服務" : item === "slots" ? "時段" : item === "bookings" ? "預約" : "夥伴申請"}</button>)}</div></section>{msg ? <div className="i20-panel" style={{ marginTop: 18 }}>{msg}</div> : null}{tab !== "market" ? <IdentityRequirementPanel identity={identity} requireRealName /> : null}{tab === "market" ? <section className="i20-grid four" style={{ marginTop: 18 }}>{loading ? <div className="i20-card">讀取中…</div> : services.length ? services.map((service) => <article className="i20-card" key={service.id}><div className="i20-avatar">{service.provider_profile?.display_name?.[0] || "島"}</div><span className="i20-kicker">{service.provider_profile?.is_professional_buddy ? "Verified Buddy" : "Buddy Service"}</span><h3>{service.title}</h3><p>{service.summary}</p><div className="i20-chip-row"><span className="i20-chip">NT${service.price_per_hour_twd}/hr</span><span className="i20-chip">{service.buddy_category}</span><span className="i20-chip">{service.delivery_mode}</span><span className="i20-chip">{service.open_slots_count || 0} 時段</span></div><div className="i20-actions-row"><Link className="i20-btn light"