  { key: "focus", title: "專注任務", body: "讀書、工作、寫作、整理資料，有人一起開始。", image: "/site-assets/image20/rooms/scene-focus-task-evening-desk.png" },
  { key: "life", title: "生活陪伴", body: "家務、晚餐、下班整理，普通日常也能有人在。", image: "/site-assets/image20/rooms/scene-life-companionship-warm-lounge.png" },
