import { getAiConfig } from "@/lib/ai/aiConfig";

export type ModelArkRole = "system" | "user" | "assistant";

export type ModelArkMessage = {
  role: ModelArkRole;
  content: string;
};

export type ModelArkTextResult = {
  text: string;
  providerRequestId: string | null;
  rawId: string | null;
};

export class ModelArkClientError extends Error {
  status: number;
  providerCode: string | null;
  providerRequestId: string | null;
  raw: unknown;

  constructor(params: {
    message: string;
    status: number;
    providerCode?: string | null;
    providerRequestId?: string | null;
    raw?: unknown;
  }) {
    super(params.message);
    this.name = "ModelArkClientError";
    this.status = params.status;
    this.providerCode = params.providerCode ?? null;
    this.providerRequestId = params.providerRequestId ?? null;
    this.raw = params.raw;
  }
}

function normalizeBaseUrl(baseUrl: string): string {
  return baseUrl.replace(/\/+$/g, "");
}

function withTimeout(timeoutMs: number) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  return {
    signal: controller.signal,
    done: () => clearTimeout(timeout),
  };
}

function extractText(json: any): string {
  const chatText = json?.choices?.[0]?.message?.content;
  if (typeof chatText === "string" && chatText.trim()) {
    return chatText.trim();
  }

  const outputText = json?.output_text;
  if (typeof outputText === "string" && outputText.trim()) {
    return outputText.trim();
  }

  const responseOutput = json?.output;
  if (Array.isArray(responseOutput)) {
    const parts: string[] = [];
    for (const item of responseOutput) {
      if (Array.isArray(item?.content)) {
        for (const content of item.content) {
          if (typeof content?.text === "string") {
            parts.push(content.text);
          }
        }
      }
    }

    const joined = parts.join("\n").trim();
    if (joined) {
      return joined;
    }
  }

  return "";
}

export async function callModelArkText(params: {
  messages: ModelArkMessage[];
  temperature?: number;
  topP?: number;
  maxTokens?: number;
}): Promise<ModelArkTextResult> {
  const config = getAiConfig();
  if (!config.modelArk.apiKey) {
    throw new Error("Missing BYTEPLUS_MODELARK_API_KEY");
  }
  if (!config.modelArk.endpointId) {
    throw new Error("Missing BYTEPLUS_MODELARK_ENDPOINT_ID");
  }

  const timer = withTimeout(config.requestTimeoutMs);
  const url = `${normalizeBaseUrl(config.modelArk.baseUrl)}/chat/completions`;

  try {
    const response = await fetch(url, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${config.modelArk.apiKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: config.modelArk.endpointId,
        messages: params.messages,
        stream: false,
        temperature: params.temperature ?? 0.65,
        top_p: params.topP ?? 0.8,
        max_tokens: params.maxTokens ?? 512,
      }),
      signal: timer.signal,
    });

    const providerRequestId =
      response.headers.get("x-request-id") ||
      response.headers.get("x-tt-logid") ||
      response.headers.get("x-volc-request-id") ||
      null;

    const json = await response.json().catch(async () => ({ raw: await response.text().catch(() => "") }));

    if (!response.ok) {
      throw new ModelArkClientError({
        message: json?.error?.message || json?.message || "ModelArk request failed",
        status: response.status,
        providerCode: json?.error?.code || json?.code || null,
        providerRequestId,
        raw: json,
      });
    }

    const text = extractText(json);
    if (!text) {
      throw new ModelArkClientError({
        message: "ModelArk response text missing",
        status: response.status,
        providerRequestId,
        raw: json,
      });
    }

    return {
      text,
      providerRequestId,
      rawId: typeof json?.id === "string" ? json.id : null,
    };
  } catch (error: any) {
    if (error?.name === "AbortError") {
      throw new ModelArkClientError({
        message: "ModelArk request timeout",
        status: 408,
        providerCode: "TIMEOUT",
      });
    }

    throw error;
  } finally {
    timer.done();
  }
}

import { getAiConfig } from "@/lib/ai/aiConfig";

export type SeedTtsResult =
  | {
      kind: "audio";
      contentType: string;
      audio: ArrayBuffer;
      providerRequestId: string | null;
    }
  | {
      kind: "json";
      json: unknown;
      providerRequestId: string | null;
    };

export class SeedTtsClientError extends Error {
  status: number;
  providerCode: string | null;
  providerRequestId: string | null;
  raw: unknown;

  constructor(params: {
    message: string;
    status: number;
    providerCode?: string | null;
    providerRequestId?: string | null;
    raw?: unknown;
  }) {
    super(params.message);
    this.name = "SeedTtsClientError";
    this.status = params.status;
    this.providerCode = params.providerCode ?? null;
    this.providerRequestId = params.providerRequestId ?? null;
    this.raw = params.raw;
  }
}

function withTimeout(timeoutMs: number) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  return {
    signal: controller.signal,
    done: () => clearTimeout(timeout),
  };
}

function safeRequestId() {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }

  return `calmco-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

export function resolveTtsVoiceType(input?: string | null): string {
  const config = getAiConfig();
  const normalized = (input || "").trim();
  if (!normalized) {
    return config.seedSpeech.ttsDefaultVoiceType;
  }

  const allowed = Object.values(config.seedSpeech.ttsVoiceTypes);
  if (allowed.length > 0 && !allowed.includes(normalized)) {
    return config.seedSpeech.ttsDefaultVoiceType;
  }

  return normalized;
}

export async function synthesizeSeedTts(params: {
  text: string;
  voiceType?: string | null;
  format?: "mp3" | "wav";
  sampleRate?: number;
}): Promise<SeedTtsResult> {
  const config = getAiConfig();
  if (!config.seedSpeech.apiKey) {
    throw new Error("Missing BYTEPLUS_SEED_SPEECH_API_KEY");
  }
  if (!config.seedSpeech.ttsResourceId) {
    throw new Error("Missing BYTEPLUS_TTS_RESOURCE_ID");
  }

  const voiceType = resolveTtsVoiceType(params.voiceType);
  if (!voiceType) {
    throw new Error("Missing BYTEPLUS_TTS_DEFAULT_VOICE_TYPE");
  }

  const timer = withTimeout(config.requestTimeoutMs);

  try {
    const response = await fetch(config.seedSpeech.ttsEndpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Api-Key": config.seedSpeech.apiKey,
        "X-Api-Resource-Id": config.seedSpeech.ttsResourceId,
        "X-Api-Request-Id": safeRequestId(),
      },
      body: JSON.stringify({
        req_params: {
          text: params.text,
          speaker: voiceType,
          additions: JSON.stringify({
            disable_markdown_filter: true,
            enable_language_detector: true,
            enable_latex_tn: false,
          }),
          audio_params: {
            format: params.format ?? "mp3",
            sample_rate: params.sampleRate ?? 24000,
          },
        },
      }),
      signal: timer.signal,
    });

    const providerRequestId =
      response.headers.get("x-request-id") ||
      response.headers.get("x-tt-logid") ||
      response.headers.get("x-volc-request-id") ||
      null;
    const contentType = response.headers.get("content-type") || "application/octet-stream";

    if (!response.ok) {
      const raw = contentType.includes("application/json")
        ? await response.json().catch(() => null)
        : await response.text().catch(() => "");
      throw new SeedTtsClientError({
        message:
          (raw as any)?.error?.message ||
          (raw as any)?.message ||
          "SeedTTS request failed",
        status: response.status,
        providerCode: (raw as any)?.error?.code || (raw as any)?.code || null,
        providerRequestId,
        raw,
      });
    }

    if (contentType.includes("application/json")) {
      const json = await response.json();
      return { kind: "json", json, providerRequestId };
    }

    return {
      kind: "audio",
      contentType,
      audio: await response.arrayBuffer(),
      providerRequestId,
    };
  } catch (error: any) {
    if (error?.name === "AbortError") {
      throw new SeedTtsClientError({
        message: "SeedTTS request timeout",
        status: 408,
        providerCode: "TIMEOUT",
      });
    }

    throw error;
  } finally {
    timer.done();
  }
}

import {
  PRODUCT_PLANS,
  getProductPlan,
  getPurchasablePlan,
} from "@/lib/productCatalog";

export type BillingPlanCode =
  | "vip_month"
  | "rooms_unlimited_299"
  | "buddies_pro_399"
  | "whole_site_599"
  | "host_999";

export type BillingPlanAvailability = "active" | "coming_soon";
export type BillingMode = "one_time" | "subscription";
export type BillingStage = "pilot" | "formal_launch";

export type BillingPlan = {
  code: BillingPlanCode;
  title: string;
  shortTitle: string;
  priceLabel: string;
  amount: number | null;
  entitlementDays: number | null;
  availability: BillingPlanAvailability;
  purchaseEnabled: boolean;
  billingMode: BillingMode;
  stage: BillingStage;
  autoRenew: boolean;
  checkoutPlanCode: string | null;
  description: string;
  highlights: string[];
  supportSummary: string;
  disabledReason?: string;
  invoiceItemName: string;
  tradeDescription: string;
  valueMetric: string;
};

export const BILLING_SCOPE_LABEL =
  "Pricing v128｜Pricing v2 最終規格與 production 商品隔離";
export const BILLING_SCOPE_DESCRIPTION =
  "目前 production 只開放 VIP 月方案（一次性付款／30 天／不自動續扣）。Rooms 299、Buddies 399、全站 599、主理人 999 是 final next-spec，尚未開放付款。";

function toBillingPlan(code: BillingPlanCode): BillingPlan {
  const plan = getProductPlan(code);
  if (!plan) {
    throw new Error(`Unknown billing plan: ${code}`);
  }

  const purchaseEnabled =
    Boolean(plan.purchaseEnabled) &&
    plan.purchaseStatus === "active" &&
    Boolean(plan.checkoutPlanCode) &&
    plan.amountTwd !== null;

  return {
    code: plan.code as BillingPlanCode,
    title: plan.title,
    shortTitle: plan.shortTitle,
    priceLabel: plan.priceLabel,
    amount: plan.amountTwd,
    entitlementDays: plan.entitlementDays,
    availability: purchaseEnabled ? "active" : "coming_soon",
    purchaseEnabled,
    billingMode:
      plan.billingMode === "one_time" ? "one_time" : "subscription",
    stage: plan.stage === "production_pilot" ? "pilot" : "formal_launch",
    autoRenew: plan.autoRenew,
    checkoutPlanCode: plan.checkoutPlanCode,
    description: plan.positioning || plan.description,
    highlights: plan.highlights?.length ? plan.highlights : plan.benefits,
    supportSummary: plan.supportSummary,
    disabledReason: plan.disabledReason,
    invoiceItemName: plan.invoiceItemName,
    tradeDescription: plan.tradeDescription,
    valueMetric: plan.valueMetric,
  };
}

export const BILLING_PLANS: BillingPlan[] = [
  toBillingPlan("vip_month"),
  toBillingPlan("rooms_unlimited_299"),
  toBillingPlan("buddies_pro_399"),
  toBillingPlan("whole_site_599"),
  toBillingPlan("host_999"),
];

export const ACTIVE_BILLING_PLAN =
  BILLING_PLANS.find((plan) => plan.code === "vip_month") ??
  BILLING_PLANS[0];

export const FUTURE_BILLING_PLANS = BILLING_PLANS.filter(
  (plan) => plan.code !== ACTIVE_BILLING_PLAN.code,
);

export function getBillingPlan(
  code: string | null | undefined,
): BillingPlan | undefined {
  return BILLING_PLANS.find((plan) => plan.code === code);
}

export function resolvePurchasableBillingPlan(
  code: string | null | undefined,
): BillingPlan {
  const productPlan = getPurchasablePlan(code);

  return {
    code: productPlan.code as BillingPlanCode,
    title: productPlan.title,
    shortTitle: productPlan.shortTitle,
    priceLabel: productPlan.priceLabel,
    amount: productPlan.amountTwd,
    entitlementDays: productPlan.entitlementDays,
    availability: "active",
    purchaseEnabled: true,
    billingMode:
      productPlan.billingMode === "one_time" ? "one_time" : "subscription",
    stage:
      productPlan.stage === "production_pilot" ? "pilot" : "formal_launch",
    autoRenew: productPlan.autoRenew,
    checkoutPlanCode: productPlan.checkoutPlanCode,
    description: productPlan.positioning || productPlan.description,
    highlights: productPlan.highlights?.length
      ? productPlan.highlights
      : productPlan.benefits,
    supportSummary: productPlan.supportSummary,
    disabledReason: productPlan.disabledReason,
    invoiceItemName: productPlan.invoiceItemName,
    tradeDescription: productPlan.tradeDescription,
    valueMetric: productPlan.valueMetric,
  };
}

import type { User } from "@supabase/supabase-js";
import { supabase } from "@/lib/supabaseClient";
import {
  type PrivateProfileSettingsRow,
  type PublicProfileRow,
  buildDefaultHandle,
  deriveDisplayName,
} from "@/lib/socialProfile";

export function makeDefaultPublicProfile(user: User) {
  const displayName = deriveDisplayName({
    email: user.email,
    user_metadata: (user as any).user_metadata ?? null,
  });
  const handleSeed =
    ((user as any).user_metadata?.preferred_username as string | undefined) ||
    ((user as any).user_metadata?.user_name as string | undefined) ||
    displayName;

  return {
    user_id: user.id,
    handle: buildDefaultHandle(user.id, handleSeed),
    display_name: displayName,
    avatar_url:
      ((user as any).user_metadata?.avatar_url as string | undefined) ||
      ((user as any).user_metadata?.picture as string | undefined) ||
      null,
    bio: null,
    tags: [] as string[],
    visibility: "public" as const,
    accepting_friend_requests: true,
    accepting_schedule_invites: true,
    show_upcoming_schedule: true,
    is_professional_buddy: false,
  };
}

export async function ensureOwnProfile(user: User) {
  const existing = await supabase
    .from("profiles")
    .select("*")
    .eq("user_id", user.id)
    .maybeSingle();

  if (existing.error) throw existing.error;
  if (existing.data) return existing.data as PublicProfileRow;

  const fallback = makeDefaultPublicProfile(user);
  const inserted = await supabase.from("profiles").insert(fallback).select("*").single();

  if (!inserted.error && inserted.data) {
    return inserted.data as PublicProfileRow;
  }

  const retry = await supabase
    .from("profiles")
    .select("*")
    .eq("user_id", user.id)
    .maybeSingle();

  if (retry.error) throw retry.error;
  if (!retry.data) {
    throw inserted.error ?? new Error("建立個人檔案失敗");
  }
  return retry.data as PublicProfileRow;
}

export async function ensureOwnPrivateSettings(userId: string) {
  const existing = await supabase
    .from("user_private_profile_settings")
    .select("*")
    .eq("user_id", userId)
    .maybeSingle();

  if (existing.error) throw existing.error;
  if (existing.data) return existing.data as PrivateProfileSettingsRow;

  const inserted = await supabase
    .from("user_private_profile_settings")
    .insert({
      user_id: userId,
      notify_friend_requests: true,
      notify_schedule_updates: true,
      notify_room_reminders: true,
    })
    .select("*")
    .single();

  if (!inserted.error && inserted.data) {
    return inserted.data as PrivateProfileSettingsRow;
  }

  const retry = await supabase
    .from("user_private_profile_settings")
    .select("*")
    .eq("user_id", userId)
    .maybeSingle();

  if (retry.error) throw retry.error;
  if (!retry.data) {
    throw inserted.error ?? new Error("建立私人設定失敗");
  }
  return retry.data as PrivateProfileSettingsRow;
}

// lib/runtimeCaps.ts
// Capability-based gating for UI/features.
// MVP policy: mobile/tablet devices disable all blur-related effects.

export type RuntimeCaps = {
  isMobile: boolean;
  isIOS: boolean;
  isAndroid: boolean;
  supportsCanvasCaptureStream: boolean;
  supportsCanvasFilter: boolean;
};

function detectIOS(ua: string): boolean {
  // iPadOS 13+ can pretend to be Mac; add touch heuristic.
  const isIPhoneIPadIPod = /iPhone|iPad|iPod/i.test(ua);
  const isMacLikeIPad = /Macintosh/i.test(ua) && typeof navigator !== "undefined" && (navigator as any).maxTouchPoints > 1;
  return isIPhoneIPadIPod || isMacLikeIPad;
}

export function getRuntimeCaps(): RuntimeCaps {
  if (typeof window === "undefined") {
    return {
      isMobile: false,
      isIOS: false,
      isAndroid: false,
      supportsCanvasCaptureStream: false,
      supportsCanvasFilter: false,
    };
  }

  const ua = navigator.userAgent || "";
  const isIOS = detectIOS(ua);
  const isAndroid = /Android/i.test(ua);

  // Pointer heuristic: coarse pointer + small-ish viewport => mobile/tablet UX
  const coarse = typeof window.matchMedia === "function" && window.matchMedia("(pointer: coarse)").matches;
  const smallViewport = Math.min(window.innerWidth || 0, window.innerHeight || 0) <= 900;

  const isMobile = isIOS || isAndroid || (coarse && smallViewport);

  const supportsCanvasCaptureStream =
    typeof (HTMLCanvasElement.prototype as any).captureStream === "function";

  // Canvas 2D ctx filter support (not perfect, but good enough)
  let supportsCanvasFilter = false;
  try {
    const c = document.createElement("canvas");
    const ctx = c.getContext("2d") as any;
    supportsCanvasFilter = !!ctx && "filter" in ctx;
  } catch {
    supportsCanvasFilter = false;
  }

  return {
    isMobile,
    isIOS,
    isAndroid,
    supportsCanvasCaptureStream,
    supportsCanvasFilter,
  };
}

