  };
}

import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { listManagedDailyRooms, parseDailyRoomNameFromUrl, tryDeleteDailyRoom, ROOM_INFRA_BUILD_TAG } from "@/lib/server/roomInfra";

export const ROOM_RECONCILIATION_BUILD_TAG = "daily-room-reconciliation-v117-2026-06-25";

type Severity = "low" | "normal" | "high" | "urgent" | "critical";
type IssueType = "active_overdue" | "active_without_daily_url" | "active_daily_missing" | "ended_with_daily_room" | "orphan_daily_room" | "active_without_members" | "stale_presence" | "daily_list_failed";

export type RoomReconciliationItemDraft = {
  issue_type: IssueType;
  severity: Severity;
  room_id?: string | null;
  daily_room_name?: string | null;
  daily_room_url?: string | null;
  title: string;
  description?: string | null;
  recommended_action?: string | null;
  metadata?: Record<string, unknown>;
};

type RoomRow = {
  id: string;
  title?: string | null;
  status?: string | null;
  daily_room_url?: string | null;
  created_at?: string | null;
  started_at?: string | null;
  scheduled_end_at?: string | null;
  ended_at?: string | null;
  last_presence_at?: string | null;
  duration_minutes?: number | null;
  created_by?: string | null;
};

function parseMs(value?: string | null) {
  if (!value) return null;
  const t = new Date(value).getTime();
  return Number.isFinite(t) ? t : null;
}

function isBeforeNow(value?: string | null, graceMinutes = 0) {
  const t = parseMs(value);
  if (!t) return false;
  return t + graceMinutes * 60_000 < Date.now();
}

function scheduledEnd(room: RoomRow) {
  if (room.scheduled_end_at) return room.scheduled_end_at;
  const base = parseMs(room.started_at || room.created_at);
  if (!base) return null;
  const duration = Number(room.duration_minutes || 25);
  return new Date(base + (Number.isFinite(duration) ? duration : 25) * 60_000).toISOString();
}

function roomNameFor(room: RoomRow) {
  return parseDailyRoomNameFromUrl(room.daily_room_url);
}

function item(input: RoomReconciliationItemDraft): RoomReconciliationItemDraft {
  return { description: null, recommended_action: null, metadata: {}, ...input };
}

function summarize(items: RoomReconciliationItemDraft[]) {
  return items.reduce((acc: Record<string, number>, row) => {
    acc.total = (acc.total || 0) + 1;
    acc[row.issue_type] = (acc[row.issue_type] || 0) + 1;
    acc[`severity_${row.severity}`] = (acc[`severity_${row.severity}`] || 0) + 1;
    return acc;
  }, {});
}

export async function scanRoomReconciliation() {
  const [roomsResult, membersResult, dailyRoomsResult] = await Promise.all([
    supabaseAdmin.from("rooms").select("id,title,status,daily_room_url,created_at,started_at,scheduled_end_at,ended_at,last_presence_at,duration_minutes,created_by").order("created_at", { ascending: false }).limit(600),
    supabaseAdmin.from("room_members").select("room_id,user_id").limit(2000),
    listManagedDailyRooms(100),
  ]);

  if (roomsResult.error) throw roomsResult.error;
  if (membersResult.error) throw membersResult.error;

  const rooms = (roomsResult.data ?? []) as RoomRow[];
  const membersByRoom = new Map<string, number>();
  for (const row of membersResult.data ?? []) {
    const roomId = String((row as any).room_id || "");
    if (roomId) membersByRoom.set(roomId, (membersByRoom.get(roomId) || 0) + 1);
  }

  const dailyRooms = dailyRoomsResult.ok ? dailyRoomsResult.rooms : [];
  const dailyByName = new Map<string, any>();
  for (const dailyRoom of dailyRooms) if (dailyRoom.name) dailyByName.set(dailyRoom.name, dailyRoom);

  const activeDailyNames = new Set<string>();
  const referencedDailyNames = new Set<string>();
  const issues: RoomReconciliationItemDraft[] = [];

  for (const room of rooms) {
    const roomName = roomNameFor(room);
    if (roomName) referencedDailyNames.add(roomName);
    const status = room.status || "active";
    const isActive = status === "active";
    const isEnded = status === "ended" || status === "expired" || Boolean(room.ended_at);
    const endAt = scheduledEnd(room);
    const memberCount = membersByRoom.get(room.id) || 0;
    if (isActive && roomName) activeDailyNames.add(roomName);

    if (isActive && isBeforeNow(endAt, 5)) {
      issues.push(item({ issue_type: "active_overdue", severity: "high", room_id: room.id, daily_room_name: roomName, daily_room_url: room.daily_room_url, title: `逾期仍 active：${room.title || room.id}`, description: `scheduled_end_at=${endAt || "missing"}，status 仍為 active。`, recommended_action: "run_cleanup_or_end_room", metadata: { scheduled_end_at: endAt, status, created_by: room.created_by } }));
    }
    if (isActive && !room.daily_room_url) {
      issues.push(item({ issue_type: "active_without_daily_url", severity: "urgent", room_id: room.id, title: `active 房間缺少 Daily URL：${room.title || room.id}`, description: "Supabase rooms.status=active，但 daily_room_url 為空，使用者可能看得到房間卻無法進入通話。", recommended_action: "end_room_or_recreate_daily", metadata: { status, created_by: room.created_by } }));
    }
    if (isActive && roomName && dailyRoomsResult.ok && !dailyByName.has(roomName)) {
      issues.push(item({ issue_type: "active_daily_missing", severity: "critical", room_id: room.id, daily_room_name: roomName, daily_room_url: room.daily_room_url, title: `active 房間的 Daily room 不存在：${room.title || room.id}`, description: `Daily room ${roomName} 不在 Daily API list 結果中。`, recommended_action: "end_room_or_recreate_daily", metadata: { status, created_by: room.created_by } }));
    }
    if (isEnded && roomName && dailyRoomsResult.ok && dailyByName.has(roomName)) {
      issues.push(item({ issue_type: "ended_with_daily_room", severity: "normal", room_id: room.id, daily_room_name: roomName, daily_room_url: room.daily_room_url, title: `已結束房間仍有 Daily room：${room.title || room.id}`, description: `Supabase 已 ended / expired，但 Daily room ${roomName} 仍存在。`, recommended_action: "delete_daily_room", metadata: { status, ended_at: room.ended_at } }));
    }
    if (isActive && memberCount <= 0) {
      issues.push(item({ issue_type: "active_without_members", severity: "high", room_id: room.id, daily_room_name: roomName, daily_room_url: room.daily_room_url, title: `active 房間沒有 room_members：${room.title || room.id}`, description: "房間為 active，但沒有任何 room_members。這通常代表建立 / join 流程中斷。", recommended_action: "end_room", metadata: { member_count: memberCount, status } }));
    }
    if (isActive && room.last_presence_at && isBeforeNow(room.last_presence_at, 30) && !isBeforeNow(endAt, 5)) {
      issues.push(item({ issue_type: "stale_presence", severity: "low", room_id: room.id, daily_room_name: roomName, daily_room_url: room.daily_room_url, title: `presence 過久未更新：${room.title || room.id}`, description: `last_presence_at=${room.last_presence_at}`, recommended_action: "observe_or_end_if_empty", metadata: { last_presence_at: room.last_presence_at, scheduled_end_at: endAt } }));
    }
  }

  if (dailyRoomsResult.ok) {
    for (const dailyRoom of dailyRooms) {
      const roomName = dailyRoom.name || "";
      if (!roomName || activeDailyNames.has(roomName)) continue;
      const matchingRoom = rooms.find((room) => roomNameFor(room) === roomName);
      if (matchingRoom && (matchingRoom.status === "ended" || matchingRoom.status === "expired" || matchingRoom.ended_at)) continue;
      issues.push(item({ issue_type: "orphan_daily_room", severity: "high", daily_room_name: roomName, daily_room_url: dailyRoom.url || null, title: `Daily orphan room：${roomName}`, description: "Daily 有 cowork_ / buddy_ 管理房，但沒有對應 active Supabase room。", recommended_action: "delete_daily_room", metadata: { daily_room: dailyRoom, has_supabase_reference: referencedDailyNames.has(roomName) } }));
    }
  } else {
    issues.push(item({ issue_type: "daily_list_failed", severity: "urgent", title: "Daily rooms list 失敗", description: dailyRoomsResult.error || "Daily list failed", recommended_action: "check_daily_api_key", metadata: { error: dailyRoomsResult.error || null } }));
  }

  return { rooms, daily_rooms: dailyRooms, daily_error: dailyRoomsResult.ok ? null : dailyRoomsResult.error || "daily_list_failed", issues, summary: summarize(issues), scanned_supabase_rooms: rooms.length, scanned_daily_rooms: dailyRooms.length, build_tag: ROOM_RECONCILIATION_BUILD_TAG, room_infra_build_tag: ROOM_INFRA_BUILD_TAG };
}

export async function persistRoomReconciliationRun(input: { adminUserId?: string | null; runType?: "manual_scan" | "manual_fix" | "cleanup_cron" | "auto_scan"; scan: Awaited<ReturnType<typeof scanRoomReconciliation>> }) {
  const run = await supabaseAdmin.from("room_reconciliation_runs").insert({ run_type: input.runType || "manual_scan", status: "completed", scanned_supabase_rooms: input.scan.scanned_supabase_rooms, scanned_daily_rooms: input.scan.scanned_daily_rooms, detected_items: input.scan.issues.length, triggered_by_admin_user_id: input.adminUserId ?? null, summary: input.scan.summary, completed_at: new Date().toISOString() }).select("*").single();
  if (run.error || !run.data) throw run.error || new Error("failed_to_create_reconciliation_run");
  if (input.scan.issues.length) {
    const rows = input.scan.issues.map((issue) => ({ ...issue, run_id: run.data.id, status: "open", metadata: issue.metadata ?? {} }));
    const inserted = await supabaseAdmin.from("room_reconciliation_items").insert(rows).select("*");
    if (inserted.error) throw inserted.error;
    return { run: run.data, items: inserted.data ?? [] };
  }
  return { run: run.data, items: [] };
}

export async function endSupabaseRoom(roomId: string, adminUserId: string, reason = "admin_reconciliation") {
  const now = new Date().toISOString();
  const room = await supabaseAdmin.from("rooms").update({ status: "ended", ended_at: now, cleanup_reason: reason }).eq("id", roomId).select("id,title,status,daily_room_url").single();
  if (room.error || !room.data) throw room.error || new Error("failed_to_end_room");
  await supabaseAdmin.from("room_access_sessions").update({ status: "ended", updated_at: now }).eq("room_id", roomId).eq("status", "active");
  await supabaseAdmin.from("reliability_events").insert({ user_id: adminUserId, room_id: roomId, event_type: "admin_reconciliation_room_ended", severity: "high", source: "admin_room_reconciliation_v117", metadata: { reason } }).then(() => null);
  return room.data;
}

export async function deleteDailyRoomByName(roomName: string) {
  if (!roomName) throw new Error("Missing Daily room name.");
  return tryDeleteDailyRoom(roomName);
}

export async function markReconciliationItem(input: { itemId: string; adminUserId: string; status: "fixed" | "ignored" | "failed" | "in_progress"; result?: Record<string, unknown> }) {
  const now = new Date().toISOString();
  const patch: Record<string, unknown> = { status: input.status, updated_at: now };
  if (input.status === "fixed" || input.status === "failed") { patch.fixed_by_admin_user_id = input.adminUserId; patch.fixed_at = now; patch.fix_result = input.result ?? {}; }
  if (input.status === "ignored") { patch.ignored_by_admin_user_id = input.adminUserId; patch.ignored_at = now; patch.fix_result = input.result ?? {}; }
  const updated = await supabaseAdmin.from("room_reconciliation_items").update(patch).eq("id", input.itemId).select("*").single();
  if (updated.error || !updated.data) throw updated.error || new Error("failed_to_update_reconciliation_item");
  return updated.data;
}

import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { insertReliabilityEvent } from "@/lib/server/safety";
import { P0_BUILD_TAGS } from "@/lib/p0Status";

export const ROOM_SUMMARY_BUILD_TAG = P0_BUILD_TAGS.summary;
export const ROOM_SUMMARY_VERSION = "p0-summary-v1";

const DEFAULT_VIDEO_RATE_USD = 0.004;
const DEFAULT_AUDIO_RATE_USD = 0.00099;
const MAX_HEARTBEAT_DELTA_SECONDS = 90;

type PresenceEvent = {
  id?: string;
  user_id?: string | null;
  access_session_id?: string | null;
  presence_mode?: string | null;
  event_type?: string | null;
  media_track_state?: Record<string, unknown> | null;
  daily_participant_state?: string | null;
  billing_media_class?: string | null;
  created_at?: string | null;
};

type ParticipantAccumulator = {
  userId: string;
  accessSessionId: string | null;
  presenceMode: string;
  firstPresenceAt: string | null;
  lastPresenceAt: string | null;
  actualPresenceSeconds: number;
  visualSeconds: number;
  audioOnlySeconds: number;
  screenShareSeconds: number;
  billingMediaClass: "unknown" | "no_media" | "audio_only" | "video";
  joinedConfirmed: boolean;
  leftExplicitly: boolean;
  brbCount: number;
  hiddenCount: number;
  extensionConfirmCount: number;
};

function numericEnv(name: string, fallback: number) {
  const value = Number(process.env[name]);
  return Number.isFinite(value) && value >= 0 ? value : fallback;
}

function timestamp(value: unknown) {
  if (!value) return null;
  const date = new Date(String(value));
  return Number.isNaN(date.getTime()) ? null : date.getTime();
}

function boolTrack(value: unknown) {
  return value === true || value === "on" || value === "playable";
}

function classifyEvent(event: PresenceEvent) {
  const media = event.media_track_state || {};
  if (
    event.billing_media_class === "video" ||
    boolTrack(media.video) ||
    boolTrack(media.screen)
  ) {
    return "video" as const;
  }
  if (event.billing_media_class === "audio_only" || boolTrack(media.audio)) {
    return "audio_only" as const;
  }
  if (event.billing_media_class === "no_media") return "no_media" as const;
  return "unknown" as const;
}

function normalizeBillingMediaClass(
  value: unknown,
): ParticipantAccumulator["billingMediaClass"] {
  if (
    value === "video" ||
    value === "audio_only" ||
    value === "no_media" ||
    value === "unknown"
  ) {
    return value;
  }
  return "unknown";
}

function isCountable(event: PresenceEvent) {
  if (event.event_type === "left" || event.event_type === "brb_start") return false;
  if (event.daily_participant_state === "left" || event.daily_participant_state === "error") {
    return false;
  }
  return true;
}

function upgradeMediaClass(
  current: ParticipantAccumulator["billingMediaClass"],
  next: ParticipantAccumulator["billingMediaClass"],
) {
  const rank = { unknown: 0, no_media: 1, audio_only: 2, video: 3 } as const;
  return rank[next] > rank[current] ? next : current;
}

function participantFromEvents(userId: string, events: PresenceEvent[]) {
  const sorted = [...events].sort(
    (a, b) => (timestamp(a.created_at) ?? 0) - (timestamp(b.created_at) ?? 0),
  );
  const accumulator: ParticipantAccumulator = {
    userId,
    accessSessionId: null,
    presenceMode: "quiet",
    firstPresenceAt: sorted[0]?.created_at ?? null,
    lastPresenceAt: sorted.at(-1)?.created_at ?? null,
    actualPresenceSeconds: 0,
    visualSeconds: 0,
    audioOnlySeconds: 0,
    screenShareSeconds: 0,
    billingMediaClass: "unknown",
    joinedConfirmed: false,
    leftExplicitly: false,
    brbCount: 0,
    hiddenCount: 0,
    extensionConfirmCount: 0,
  };

  for (let index = 0; index < sorted.length; index += 1) {
    const event = sorted[index];
    const next = sorted[index + 1];
    accumulator.accessSessionId =
      event.access_session_id || accumulator.accessSessionId;
    accumulator.presenceMode = event.presence_mode || accumulator.presenceMode;
    accumulator.joinedConfirmed ||=
      event.event_type === "selected" ||
      event.event_type === "heartbeat" ||
      event.daily_participant_state === "joined";
    accumulator.leftExplicitly ||= event.event_type === "left";
    if (event.event_type === "brb_start") accumulator.brbCount += 1;
    if (event.event_type === "hidden") accumulator.hiddenCount += 1;
    if (event.event_type === "extension_confirmed") {
      accumulator.extensionConfirmCount += 1;
    }

    const currentAt = timestamp(event.created_at);
    const nextAt = timestamp(next?.created_at);
    if (!currentAt || !nextAt || !isCountable(event)) continue;

    const deltaSeconds = Math.max(
      0,
      Math.min(
        Math.floor((nextAt - currentAt) / 1000),
        MAX_HEARTBEAT_DELTA_SECONDS,
      ),
    );
    const eventClass = classifyEvent(event);
    accumulator.billingMediaClass = upgradeMediaClass(
      accumulator.billingMediaClass,
      eventClass,
    );
    accumulator.actualPresenceSeconds += deltaSeconds;
    if (eventClass === "video") accumulator.visualSeconds += deltaSeconds;
    if (eventClass === "audio_only" || eventClass === "no_media") {
      accumulator.audioOnlySeconds += deltaSeconds;
    }
    if (boolTrack(event.media_track_state?.screen)) {
      accumulator.screenShareSeconds += deltaSeconds;
    }
  }

  return accumulator;
}

function estimatedCostUsd(input: {
  connectedSeconds: number;
  billingMediaClass: ParticipantAccumulator["billingMediaClass"];
}) {
  const videoRate = numericEnv(
    "DAILY_VIDEO_RATE_USD_PER_PARTICIPANT_MINUTE",
    DEFAULT_VIDEO_RATE_USD,
  );
  const audioRate = numericEnv(
    "DAILY_AUDIO_RATE_USD_PER_PARTICIPANT_MINUTE",
    DEFAULT_AUDIO_RATE_USD,
  );

  // Conservative provider estimate: once a session is classified as video,
  // price the whole connected session at the video rate. Unknown also uses
  // the video rate so operational dashboards do not understate cost.
  const rate =
    input.billingMediaClass === "audio_only" ||
    input.billingMediaClass === "no_media"
      ? audioRate
      : videoRate;
  return (input.connectedSeconds / 60) * rate;
}

export async function summarizeRoom(roomId: string) {
  const roomResult = await supabaseAdmin
    .from("rooms")
    .select("*")
    .eq("id", roomId)
    .maybeSingle();
  if (roomResult.error || !roomResult.data) {
    throw new Error(roomResult.error?.message || "Room not found");
  }
  const room = roomResult.data as any;

  const [
    eventsResult,
    sessionsResult,
    reliabilityResult,
    confirmationsResult,
  ] = await Promise.all([
    supabaseAdmin
      .from("room_presence_events")
      .select("*")
      .eq("room_id", roomId)
      .order("created_at", { ascending: true })
      .limit(5000),
    supabaseAdmin
      .from("room_access_sessions")
      .select("*")
      .eq("room_id", roomId)
      .order("created_at", { ascending: true })
      .limit(500),
    supabaseAdmin
      .from("reliability_events")
      .select("user_id,event_type,created_at")
      .eq("room_id", roomId)
      .limit(1000),
    supabaseAdmin
      .from("room_extension_confirmations")
      .select("user_id,decision,extension_window_key,created_at")
      .eq("room_id", roomId)
      .limit(1000),
  ]);

  if (eventsResult.error) throw new Error(eventsResult.error.message);
  if (sessionsResult.error) throw new Error(sessionsResult.error.message);
  if (reliabilityResult.error) throw new Error(reliabilityResult.error.message);
  if (confirmationsResult.error) {
    throw new Error(confirmationsResult.error.message);
  }

  const events = (eventsResult.data ?? []) as PresenceEvent[];
  const sessions = (sessionsResult.data ?? []) as any[];
  const reliability = (reliabilityResult.data ?? []) as any[];
  const confirmations = (confirmationsResult.data ?? []) as any[];
  const userIds = new Set<string>();
  for (const event of events) if (event.user_id) userIds.add(event.user_id);
  for (const session of sessions) if (session.user_id) userIds.add(session.user_id);

  const participantRows = [...userIds].map((userId) => {
    const userEvents = events.filter((event) => event.user_id === userId);
    const summary = participantFromEvents(userId, userEvents);
    const session = [...sessions]
      .reverse()
      .find((item) => item.user_id === userId);
    const reliabilityCount = reliability.filter(
      (item) => item.user_id === userId,
    ).length;

    const actualPresenceSeconds = Math.max(
      summary.actualPresenceSeconds,
      Number(session?.connected_seconds || 0),
    );
    const visualSeconds = Math.max(
      summary.visualSeconds,
      Number(session?.visual_seconds || 0),
    );
    const audioOnlySeconds = Math.max(
      summary.audioOnlySeconds,
      Number(session?.audio_only_seconds || 0),
    );
    const screenShareSeconds = Math.max(
      summary.screenShareSeconds,
      Number(session?.screen_share_seconds || 0),
    );
    const billingMediaClass = upgradeMediaClass(
      summary.billingMediaClass,
      normalizeBillingMediaClass(session?.billing_media_class),
    );

    return {
      room_id: roomId,
      user_id: userId,
      access_session_id: session?.id || summary.accessSessionId,
      presence_mode: summary.presenceMode,
      first_presence_at: summary.firstPresenceAt || session?.connected_at || session?.created_at,
      last_presence_at:
        summary.lastPresenceAt || session?.disconnected_at || session?.updated_at,
      actual_presence_seconds: actualPresenceSeconds,
      participant_minutes: Number((actualPresenceSeconds / 60).toFixed(4)),
      visual_seconds: visualSeconds,
      audio_only_seconds: audioOnlySeconds,
      screen_share_seconds: screenShareSeconds,
      billing_media_class: billingMediaClass,
      joined_confirmed:
        summary.joinedConfirmed || Boolean(session?.join_confirmed_at),
      left_explicitly: summary.leftExplicitly,
      brb_count: summary.brbCount,
      hidden_count: summary.hiddenCount,
      extension_confirm_count: summary.extensionConfirmCount,
      reliability_event_count: reliabilityCount,
      estimated_provider_cost_usd: Number(
        estimatedCostUsd({
          connectedSeconds: actualPresenceSeconds,
          billingMediaClass,
        }).toFixed(6),
      ),
      summary_version: ROOM_SUMMARY_VERSION,
      generated_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    };
  });

  const scheduledEndMs = timestamp(
    room.scheduled_end_at || room.ended_at,
  );
  if (
    scheduledEndMs &&
    (room.status === "ended" || room.status === "expired" || room.ended_at)
  ) {
    const extensionPromptWindowStart = scheduledEndMs - 8 * 60_000;
    for (const row of participantRows) {
      const lastPresenceMs = timestamp(row.last_presence_at);
      const wasPresentForPrompt =
        row.joined_confirmed &&
        lastPresenceMs !== null &&
        lastPresenceMs >= extensionPromptWindowStart;
      const answered = confirmations.some(
        (confirmation) => confirmation.user_id === row.user_id,
      );
      const alreadyRecorded = reliability.some(
        (item) =>
          item.user_id === row.user_id &&
          item.event_type === "extension_confirmation_missing",
      );

      if (wasPresentForPrompt && !answered && !alreadyRecorded) {
        await insertReliabilityEvent({
          userId: row.user_id,
          roomId,
          eventType: "extension_confirmation_missing",
          severity: "info",
          source: "room_summary_v128",
          metadata: {
            scheduled_end_at: room.scheduled_end_at || room.ended_at,
            grace_minutes: 3,
          },
        });
        row.reliability_event_count += 1;
      }
    }
  }

  if (participantRows.length > 0) {
    const upsertParticipants = await supabaseAdmin
      .from("room_participant_summaries")
      .upsert(participantRows, { onConflict: "room_id,user_id" });
    if (upsertParticipants.error) {
      throw new Error(upsertParticipants.error.message);
    }
  }

  const totals = participantRows.reduce(
    (acc, row) => {
      acc.presenceSeconds += Number(row.actual_presence_seconds || 0);
      acc.visualSeconds += Number(row.visual_seconds || 0);
      acc.audioOnlySeconds += Number(row.audio_only_seconds || 0);
      acc.costUsd += Number(row.estimated_provider_cost_usd || 0);
      if (row.joined_confirmed) acc.connectedCount += 1;
      return acc;
    },
    {
      presenceSeconds: 0,
      visualSeconds: 0,
      audioOnlySeconds: 0,
      costUsd: 0,
      connectedCount: 0,
    },
  );

  const summaryRow = {
    room_id: roomId,
    summary_version: ROOM_SUMMARY_VERSION,
    room_title: room.title || null,
    room_category: room.room_category || null,
    room_mode: room.mode || null,
    visibility: room.visibility || null,
    scheduled_duration_minutes: Number(room.duration_minutes || 0),
    scheduled_start_at: room.started_at || room.created_at || null,
    scheduled_end_at: room.scheduled_end_at || null,
    actual_started_at:
      participantRows
        .map((row) => timestamp(row.first_presence_at))
        .filter((value): value is number => value !== null)
        .sort((a, b) => a - b)[0]
        ? new Date(
            participantRows
              .map((row) => timestamp(row.first_presence_at))
              .filter((value): value is number => value !== null)
              .sort((a, b) => a - b)[0],
          ).toISOString()
        : room.started_at || null,
    actual_ended_at: room.ended_at || room.scheduled_end_at || null,
    end_reason: room.cleanup_reason || (room.ended_at ? "ended" : room.status),
    participant_count: participantRows.length,
    connected_participant_count: totals.connectedCount,
    total_presence_seconds: totals.presenceSeconds,
    total_participant_minutes: Number((totals.presenceSeconds / 60).toFixed(4)),
    total_visual_seconds: totals.visualSeconds,
    total_audio_only_seconds: totals.audioOnlySeconds,
    estimated_provider_cost_usd: Number(totals.costUsd.toFixed(6)),
    source_event_count: events.length,
    source_access_session_count: sessions.length,
    status: "ready",
    last_error: null,
    generated_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  };

  const summaryResult = await supabaseAdmin
    .from("room_session_summaries")
    .upsert(summaryRow, { onConflict: "room_id" })
    .select("*")
    .single();
  if (summaryResult.error) throw new Error(summaryResult.error.message);

  await supabaseAdmin
    .from("room_access_sessions")
    .update({
      usage_status: "reconciled",
      reconciled_at: new Date().toISOString(),
      reconciliation_source: ROOM_SUMMARY_VERSION,
      updated_at: new Date().toISOString(),
    })
    .eq("room_id", roomId);

  return {
    ok: true,
    summary: summaryResult.data,
    participants: participantRows,
    build_tag: ROOM_SUMMARY_BUILD_TAG,
  };
}

export async function summarizeEndedRooms(limit = 25) {
  const roomsResult = await supabaseAdmin
    .from("rooms")
    .select("id,status,ended_at,updated_at")
    .in("status", ["ended", "expired"])
    .order("ended_at", { ascending: false, nullsFirst: false })
    .limit(Math.max(1, Math.min(limit, 100)));

  if (roomsResult.error) throw new Error(roomsResult.error.message);

  const results: Array<Record<string, unknown>> = [];
  for (const room of roomsResult.data ?? []) {
    try {
      const summarized = await summarizeRoom(room.id);
      results.push({ room_id: room.id, ok: true, summary: summarized.summary });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      results.push({ room_id: room.id, ok: false, error: message });
      await supabaseAdmin.from("room_session_summaries").upsert(
        {
          room_id: room.id,
          summary_version: ROOM_SUMMARY_VERSION,
          status: "failed",
          last_error: message,
          generated_at: new Date().toISOString(),
          updated_at: new Date().toISOString(),
        },
        { onConflict: "room_id" },
      );
      await insertReliabilityEvent({
        roomId: room.id,
        eventType: "room_summary_failed",
        severity: "normal",
        source: "room_summary_v128",
        metadata: { error: message },
      });
    }
  }

  return {
    ok: results.every((item) => item.ok === true),
    processed: results.length,
    succeeded: results.filter((item) => item.ok === true).length,
    failed: results.filter((item) => item.ok !== true).length,
    results,
    build_tag: ROOM_SUMMARY_BUILD_TAG,
  };
}

export type ProfileVisibility = "public" | "members" | "friends";
export type RoomCategory = "focus" | "life" | "share" | "hobby";
export type ActiveRoomScene = RoomCategory;
export type InteractionStyle = "silent" | "light-chat" | "guided" | "open-share";
export type ScheduleVisibility = "public" | "members" | "friends" | "invited";
export type RoomSceneTheme = ActiveRoomScene;

export type PublicProfileRow = { user_id: string; handle: string; display_name: string; avatar_url: string | null; bio: string | null; tags: string[] | null; visibility: ProfileVisibility; accepting_friend_requests: boolean; accepting_schedule_invites: boolean; show_upcoming_schedule: boolean; is_professional_buddy: boolean; created_at: string; updated_at: string };
export type PrivateProfileSettingsRow = { user_id: string; notify_friend_requests: boolean; notify_schedule_updates: boolean; notify_room_reminders: boolean; payment_card_brand: string | null; payment_card_last4: string | null; created_at: string; updated_at: string };

export const PROFILE_VISIBILITY_OPTIONS: Array<{ value: ProfileVisibility; label: string }> = [
  { value: "public", label: "公開可見" }, { value: "members", label: "僅 VIP 會員可見" }, { value: "friends", label: "僅自己與好友可見" },
];
export const ROOM_CATEGORY_OPTIONS: Array<{ value: RoomCategory; label: string; desc: string }> = [
  { value: "focus", label: "專注任務", desc: "共工、讀書、寫作、任務陪跑" },
  { value: "life", label: "生活陪伴", desc: "家務、煮菜、收納、帶小孩時的低壓力同行" },
  { value: "share", label: "主題分享", desc: "某個主題的交流、經驗交換、作品分享" },
  { value: "hobby", label: "興趣同好", desc: "手作、運動、畫圖、共同興趣" },
];
export const ACTIVE_ROOM_SCENE_OPTIONS: Array<{ value: ActiveRoomScene; label: string; desc: string }> = ROOM_CATEGORY_OPTIONS;
export const INTERACTION_STYLE_OPTIONS: Array<{ value: InteractionStyle; label: string }> = [
  { value: "silent", label: "安靜同行" }, { value: "light-chat", label: "輕聊天" }, { value: "guided", label: "房主引導" }, { value: "open-share", label: "開放分享" },
];
export const SCHEDULE_VISIBILITY_OPTIONS: Array<{ value: ScheduleVisibility; label: string }> = [
  { value: "public", label: "公開" }, { value: "members", label: "VIP 會員可見" }, { value: "friends", label: "好友可見" }, { value: "invited", label: "邀請制" },
];

export const INSTANT_ROOM_DURATION_OPTIONS = [25, 50, 75] as const;
export const ACTIVITY_ROOM_DURATION_OPTIONS = [90] as const;
export const DEPRECATED_ROOM_DURATION_OPTIONS = [100] as const;
export const SCHEDULE_DURATION_OPTIONS = [25, 50, 75, 90] as const;
export const SCHEDULE_SEAT_LIMIT_OPTIONS = [2, 4, 6] as const;

export function normalizeHandle(input: string) { return input.trim().toLowerCase().replace(/[^a-z0-9._-]+/g, "-").replace(/-{2,}/g, "-").replace(/^[._-]+|[._-]+$/g, "").slice(0, 30); }
export function deriveDisplayName(user: { email?: string | null; user_metadata?: Record<string, any> | null }) { const metadata = user.user_metadata ?? {}; const fromMetadata = metadata.display_name || metadata.full_name || metadata.name || metadata.user_name || metadata.preferred_username; if (typeof fromMetadata === "string" && fromMetadata.trim()) return fromMetadata.trim().slice(0, 40); const emailPrefix = (user.email ?? "").split("@")[0]?.trim(); return emailPrefix ? emailPrefix.slice(0, 40) : "安感島使用者"; }
export function buildDefaultHandle(userId: string, seed?: string | null) { const normalizedSeed = normalizeHandle(seed ?? ""); return normalizedSeed ? `${normalizedSeed.slice(0, 20)}-${userId.slice(0, 6)}` : `islander-${userId.slice(0, 8)}`; }
export function parseTagsInput(input: string) { return Array.from(new Set(input.split(",").map((item) => item.trim()).filter(Boolean).map((item) => item.slice(0, 24)))).slice(0, 8); }
export function tagsToInput(tags?: string[] | null) { return (tags ?? []).join(", "); }
export function formatPhoneForHumans(phone?: string | null) { if (!phone) return "尚未綁定"; if (/^\+8869\d{8}$/.test(phone)) return `0${phone.slice(4)}`; return phone; }
export function formatPaymentSummary(brand?: string | null, last4?: string | null) { if (!brand || !last4) return "尚未綁定付款方式"; return `${brand.toUpperCase()} •••• ${last4}`; }
export function isActiveRoomScene(value?: string | null): value is ActiveRoomScene { return value === "focus" || value === "life" || value === "share" || value === "hobby"; }
export function normalizeRoomCategoryForUi(value?: string | null): ActiveRoomScene { if (isActiveRoomScene(value)) return value; if (value === "support" || value === "life") return "life"; if (value === "pro") return "share"; return "focus"; }
export function roomSceneThemeForCategory(value?: string | null): RoomSceneTheme { return normalizeRoomCategoryForUi(value); }
export function labelForRoomCategory(value?: string | null) { return ROOM_CATEGORY_OPTIONS.find((item) => item.value === value)?.label ?? "未分類"; }
export function labelForRoomScene(value?: string | null) { return ACTIVE_ROOM_SCENE_OPTIONS.find((item) => item.value === normalizeRoomCategoryForUi(value))?.label ?? "專注任務"; }
export function descForRoomScene(value?: string | null) { return ACTIVE_ROOM_SCENE_OPTIONS.find((item) => item.value === normalizeRoomCategoryForUi(value))?.desc ?? "共工、讀書、寫作、任務陪跑"; }
export function labelForInteractionStyle(value?: string | null) { return INTERACTION_STYLE_OPTIONS.find((item) => item.value === value)?.label ?? "未指定"; }
export function labelForVisibility(value?: string | null) { return SCHEDULE_VISIBILITY_OPTIONS.find((item) => item.value === value)?.label ?? "未指定"; }
export function formatDateTimeRange(startAt?: string | null, endAt?: string | null) { if (!startAt || !endAt) return "時間待補"; const start = new Date(startAt); const end = new Date(endAt); return `${start.toLocaleString("zh-TW", { month: "numeric", day: "numeric", hour: "2-digit", minute: "2-digit" })} ～ ${end.toLocaleString("zh-TW", { hour: "2-digit", minute: "2-digit" })}`; }
export function formatDurationLabel(minutes: number) { if (minutes === 90) return "90 分鐘（活動房）"; if (minutes === 100) return "100 分鐘（舊版）"; return `${minutes} 分鐘`; }
export function sortFriendPair(userA: string, userB: string) { return userA < userB ? { user_low: userA, user_high: userB } : { user_low: userB, user_high: userA }; }
export function toDatetimeLocalValue(iso?: string | null) { const target = iso ? new Date(iso) : new Date(Date.now() + 60 * 60 * 1000); const local = new Date(target.getTime() - target.getTimezoneOffset() * 60000); return local.toISOString().slice(0, 16); }

// types/daily-events.d.ts
// 目的：補齊 @daily-co/daily-js 在某些版本 typings 未包含的事件名稱，避免 TS 報錯。
// 不影響 runtime；只影響 TypeScript 編譯/IDE 型別檢查。

declare module "@daily-co/daily-js" {
  // daily-js 的 call object 通常是 DailyCall。若你的版本名稱不同，這個 augmentation 可能不會生效；
  // 仍可改用方案 A（event name cast as any）。
  interface DailyCall {
    on(event: "video-processor-warning", callback: (ev: any) => void): any;
    on(event: "video-processor-error", callback: (ev: any) => void): any;
  }
}
